  function normalizeProjectRequestBody(body) {
    if (!isPlainObject(body)) {
      throwInvalidProjectMetadata();
    }
    return body;
  }

  function normalizeProjectText(body, field, options = {}) {
    const { fallback = "", required = false, minLength = 0, maxLength = 200, error = "Project request requires safe metadata" } = options;
    const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
    if (value === undefined || value === "") {
      if (required) throwInvalidProjectMetadata(error);
      const text = String(fallback || "").trim();
      if (text.length < minLength || text.length > maxLength || /[\x00-\x1f\x7f]/.test(text)) {
        throwInvalidProjectMetadata(error);
      }
      return text;
    }
    if (value === null || typeof value !== "string") {
      throwInvalidProjectMetadata();
    }
    if (/[\x00-\x1f\x7f]/.test(value)) {
      throwInvalidProjectMetadata();
    }
    const text = value.trim();
    if (text.length < minLength || text.length > maxLength) {
      throwInvalidProjectMetadata(error);
    }
    return text;
  }

  function normalizeProjectEnum(body, field, allowed, fallback, error) {
    const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
    if (value === undefined) return fallback;
    if (value === "") {
      if (fallback) return fallback;
      throwInvalidProjectMetadata(error);
    }
    if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
      throwInvalidProjectMetadata(error);
    }
    const status = normalizeChoice(value, allowed, "");
    if (!status) throwInvalidProjectMetadata(error);
    return status;
  }

  function normalizeProjectDate(body, field, fallback) {
    const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
    if (value === undefined || value === "") return fallback;
    if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
      throwInvalidProjectMetadata();
    }
    const date = value.trim();
    if (!isExactIsoDate(date)) {
      throwInvalidProjectMetadata();
    }
    return date;
  }

  function normalizeProjectBoolean(body, field) {
    const value = body[field];
    if (typeof value !== "boolean") {
      throwInvalidProjectMetadata();
    }
    return value;
  }

  function normalizeProjectMinutes(body, field) {
    const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
    if (value === undefined || value === "") return 0;
    if (value === null || Array.isArray(value) || typeof value === "object") {
      throwInvalidProjectMetadata();
    }
    if (typeof value === "string" && /[\x00-\x1f\x7f]/.test(value)) {
      throwInvalidProjectMetadata();
    }
    let minutes;
    if (typeof value === "number") {
      if (!Number.isInteger(value)) {
        throwInvalidProjectMetadata("Minutes must be a positive number");
      }
      minutes = value;
    } else if (typeof value === "string") {
      const text = value.trim();
      if (!/^\d+$/.test(text)) {
        throwInvalidProjectMetadata("Minutes must be a positive number");
      }
      minutes = Number(text);
    } else {
      throwInvalidProjectMetadata();
    }
    if (!Number.isSafeInteger(minutes) || !(minutes > 0) || minutes > 100000) {
      throwInvalidProjectMetadata("Minutes must be a positive number");
    }
    return minutes;
  }

  function normalizeProjectBillTimeBody(body, nowIso) {
    body = normalizeProjectRequestBody(body);
    const issueDate = normalizeProjectDate(body, "issueDate", nowIso.slice(0, 10));
    return {
      hourlyRate: normalizeProjectBillingAmount(body, "hourlyRate", { required: true, error: "A positive hourlyRate is required" }),
      issueDate,
      periodKey: normalizeProjectPeriodKey(body, "periodKey", issueDate.slice(0, 7)),
      dueDays: normalizeProjectBillingDueDays(body, "dueDays", 14)
    };
  }

  function normalizeProjectBillingPreviewQuery(query, nowIso) {
    const input = isPlainObject(query) ? query : {};
    return {
      hourlyRate: normalizeProjectBillingAmount(input, "hourlyRate", { fallback: 0 }),
      asOf: normalizeProjectDate(input, "asOf", nowIso.slice(0, 10))
    };
  }

  function normalizeProjectBillingAmount(body, field, options = {}) {
    const { required = false, fallback = 0, min = 1, max = 1000000000, error = "Project request requires safe metadata" } = options;
    const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
    if (value === undefined || value === "") {
      if (required) throwInvalidProjectMetadata(error);
      return fallback;
    }
    return toValidatedMajorMoneyInput(value, () => throwInvalidProjectMetadata(error), {
      min,
      max,
      positive: min > 0,
      zeroSubunitFraction: "zeroes"
    });
  }

  function normalizeProjectPeriodKey(body, field, fallback) {
    const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
    if (value === undefined || value === "") return fallback;
    if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
      throwInvalidProjectMetadata();
    }
    const periodKey = value.trim();
    const match = /^(\d{4})-(\d{2})$/.exec(periodKey);
    if (!match) throwInvalidProjectMetadata();
    const month = Number(match[2]);
    if (month < 1 || month > 12) throwInvalidProjectMetadata();
    return periodKey;
  }

  function normalizeProjectBillingDueDays(body, field, fallback) {
    const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
    if (value === undefined || value === "") return fallback;
    if (value === null || Array.isArray(value) || typeof value === "object" || typeof value === "boolean") {
      throwInvalidProjectMetadata();
    }
    let days;
    if (typeof value === "number") {
      days = value;
    } else if (typeof value === "string") {
      if (/[\x00-\x1f\x7f]/.test(value)) {
        throwInvalidProjectMetadata();
      }
      const text = value.trim();
      if (!/^\d+$/.test(text)) {
        throwInvalidProjectMetadata();
      }
      days = Number(text);
    } else {
      throwInvalidProjectMetadata();
    }
    if (!Number.isSafeInteger(days) || days < 1 || days > 3650) {
      throwInvalidProjectMetadata();
    }
    return days;
  }

  function throwInvalidProjectMetadata(message = "Project request requires safe metadata") {
    const err = new Error(message);
    err.statusCode = 400;
    throw err;
  }

  function normalizeProjectPathId(value, rawUrl = "") {
    const rawSegment = typeof rawUrl === "string"
      ? rawUrl.match(/^\/api\/projects\/([^/?#]+)(?:\/(?:tasks(?:\/[^/?#]+)?|milestones(?:\/[^/?#]+)?|time-entries|billing-preview|bill-time))?(?:[?#]|$)/)?.[1]
      : "";
    if (rawSegment && (rawSegment.length > 160 || !/^[a-z0-9-]+$/.test(rawSegment))) {
      throwInvalidProjectPathId("Invalid project id");
    }
    return normalizeProjectRouteId(value, "Invalid project id");
  }

  function normalizeProjectTaskPathId(value, rawUrl = "") {
    const rawSegment = typeof rawUrl === "string"
      ? rawUrl.match(/^\/api\/projects\/[^/?#]+\/tasks\/([^/?#]+)(?:[?#]|$)/)?.[1]
      : "";
    if (rawSegment && (rawSegment.length > 160 || !/^[a-z0-9-]+$/.test(rawSegment))) {
      throwInvalidProjectPathId("Invalid project task id");
    }
    return normalizeProjectRouteId(value, "Invalid project task id");
  }

  function normalizeProjectMilestonePathId(value, rawUrl = "") {
    const rawSegment = typeof rawUrl === "string"
      ? rawUrl.match(/^\/api\/projects\/[^/?#]+\/milestones\/([^/?#]+)(?:[?#]|$)/)?.[1]
      : "";
    if (rawSegment && (rawSegment.length > 160 || !/^[a-z0-9-]+$/.test(rawSegment))) {
      throwInvalidProjectPathId("Invalid project milestone id");
    }
    return normalizeProjectRouteId(value, "Invalid project milestone id");
  }

  function normalizeProjectRouteId(value, message) {
    if (typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
      throwInvalidProjectPathId(message);
    }
    const text = value.trim();
    if (!text || text.length > 160 || !/^[a-z0-9-]+$/.test(text)) {
      throwInvalidProjectPathId(message);
    }
    return text;
  }

  function throwInvalidProjectPathId(message) {
    const err = new Error(message);
    err.statusCode = 400;
    throw err;
  }

  // Billing seam: preview the unbilled time on a project (minutes → hours → amount at a rate).
  app.get("/api/projects/:id/billing-preview", async request => {
    const user = await app.auth(request);
    const projectId = normalizeProjectPathId(request.params.id, request.raw?.url);
    const project = getProject(db, user.org_id, projectId);
    if (!project) { const e = new Error("Project not found"); e.statusCode = 404; throw e; }
    const { hourlyRate, asOf } = normalizeProjectBillingPreviewQuery(request.query, new Date().toISOString());
    const agg = db.prepare("SELECT COALESCE(SUM(minutes), 0) AS minutes, COUNT(*) AS entries FROM project_time_entries WHERE org_id = ? AND project_id = ? AND billed_invoice_id IS NULL").get(user.org_id, project.id);
    const unbilledMinutes = agg.minutes;
    const hours = Math.round((unbilledMinutes / 60) * 100) / 100;
    const grossMajor = hourlyRate > 0 ? (unbilledMinutes / 60) * hourlyRate : 0;
    // VAT rate in force on the as-of date (defaults to today); the bill-time route freezes
    // the rate on the chosen issue date, so the preview accepts the same asOf for parity.
    const vatRate = resolveVatRate(db, user.org_id, asOf);
    const { subtotal, vat, total } = splitVatInclusive(grossMajor, vatRate);
    return { preview: { projectId: project.id, customerId: project.customerId, unbilledMinutes, unbilledEntries: agg.entries, hours, hourlyRate, subtotal, vat, total, vatRate, currency: activeCurrencyCode() } };
  });

  // Billing seam: convert a project's UNBILLED logged time into a posted invoice (+ ledger),
  // then mark those entries billed so they can never be billed twice. Reuses postDraftInvoice
  // (Dt 221 / Kt 611 + Kt 524). VAT-inclusive 20%. Finance-gated (Owner/Admin/Accountant).
  app.post("/api/projects/:id/bill-time", async request => {
    const user = await app.auth(request);
    requireFinanceOperator(user);
    const projectId = normalizeProjectPathId(request.params.id, request.raw?.url);
    const project = getProject(db, user.org_id, projectId);
    if (!project) { const e = new Error("Project not found"); e.statusCode = 404; throw e; }
    if (!project.customerId) { const e = new Error("Project has no customer to invoice"); e.statusCode = 400; throw e; }
    assertCustomer(db, user.org_id, project.customerId);
    const now = new Date().toISOString();
    const billingInput = normalizeProjectBillTimeBody(request.body === undefined ? {} : request.body, now);
    const { hourlyRate, issueDate, periodKey, dueDays } = billingInput;
    // Idempotent per (project, period): a prior bill for this period returns the same
    // invoice — checked BEFORE the unbilled-time guard, since after the first bill there is
    // no unbilled time left (re-running must not 400).
    const sourceKey = `project-time:${project.id}:${periodKey}`;
    const existingDraft = db.prepare("SELECT id FROM finance_draft_invoices WHERE org_id = ? AND source_key = ?").get(user.org_id, sourceKey);
    if (existingDraft) {
      const link = getFinanceInvoiceLinkByDraft(db, user.org_id, existingDraft.id);
      return { ok: true, idempotent: true, draftInvoice: getFinanceDraftInvoice(db, user.org_id, existingDraft.id), invoice: link ? getInvoice(db, user.org_id, link.invoiceId) : null };
    }
    const period = getFinancePeriod(db, user.org_id, periodKey);
    if (!period || period.status !== "open") { const e = new Error("PERIOD_LOCKED"); e.statusCode = 409; throw e; }
    const unbilled = db.prepare("SELECT id, minutes FROM project_time_entries WHERE org_id = ? AND project_id = ? AND billed_invoice_id IS NULL").all(user.org_id, project.id);
    const totalMinutes = unbilled.reduce((sum, e) => sum + (Number(e.minutes) || 0), 0);
    if (totalMinutes <= 0) { const e = new Error("No unbilled time to invoice"); e.statusCode = 400; throw e; }
    const grossMajor = (totalMinutes / 60) * hourlyRate;
    // Freeze the VAT split at the rate in force on the invoice's issue date (effective-dated),
    // so recomputing a historical period uses the rate that applied THEN, not today's.
    const vatRate = resolveVatRate(db, user.org_id, issueDate);
    const { subtotal, vat, total } = splitVatInclusive(grossMajor, vatRate);
    if (!(total > 0)) { const e = new Error("Computed invoice total is zero"); e.statusCode = 400; throw e; }
    const draftId = randomId("draft-inv");
    const number = `DRAFT-PRJ-${project.id.replace(/^proj-/, "").toUpperCase().replace(/[^A-Z0-9]+/g, "-").slice(0, 18)}-${periodKey.replace("-", "")}`;
    const dueDate = addDays(issueDate, dueDays);
    let result;
    db.exec("BEGIN");
    try {
      db.prepare(`INSERT INTO finance_draft_invoices (id, org_id, customer_id, deal_id, number, status, subtotal, vat, total, currency, issue_date, due_date, period_key, source_key, created_by_user_id, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, 'draft', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`)
        .run(draftId, user.org_id, project.customerId, project.dealId || null, number, subtotal, vat, total, activeCurrencyCode(), issueDate, dueDate, periodKey, sourceKey, user.id, now, now);
      const draftInvoice = getFinanceDraftInvoice(db, user.org_id, draftId);
      // Reuse the canonical draft→posted+ledger path (Dt 221 / Kt 611 + Kt 524).
      result = postDraftInvoice(db, user, draftInvoice, {});
      const invoiceId = result.invoice.id;
      // Mark every unbilled entry as billed on this invoice — prevents double-billing.
      const mark = db.prepare("UPDATE project_time_entries SET billed_invoice_id = ? WHERE org_id = ? AND id = ? AND billed_invoice_id IS NULL");
      for (const entry of unbilled) mark.run(invoiceId, user.org_id, entry.id);
      db.exec("COMMIT");
    } catch (err) {
      db.exec("ROLLBACK");
      throw err;
    }
    audit(db, user.org_id, user.id, "projects.time.billed", { projectId: project.id, invoiceId: result.invoice.id, minutes: totalMinutes, total });
    return { ok: true, idempotent: false, billedMinutes: totalMinutes, billedEntries: unbilled.length, invoice: result.invoice, draftInvoice: result.draftInvoice };
  });

  // Forms — intake/lead-capture. Definition routes are auth-gated; the SUBMIT route is
