  app.post("/api/service/cases/:id/replies", async request => {
    const user = await app.auth(request);
    const serviceCaseId = normalizeServiceCasePathId(request.params.id);
    const serviceCase = getServiceCase(db, user.org_id, serviceCaseId);
    if (!serviceCase) {
      const err = new Error("Service case not found");
      err.statusCode = 404;
      throw err;
    }
    const input = normalizeServiceReplyInput(request.body === undefined ? {} : request.body);
    const body = input.body;
    if (body.length < 3) {
      const err = new Error("Reply body is required");
      err.statusCode = 400;
      throw err;
    }
    const now = new Date().toISOString();
    db.prepare(`
      INSERT INTO case_messages (id, org_id, case_id, author_type, author_name, channel, body, approval_state, created_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).run(randomId("msg"), user.org_id, serviceCase.id, "operator", user.name, serviceCase.channel, body, "human-approved", now);
    db.prepare("UPDATE service_cases SET status = ?, updated_at = ? WHERE org_id = ? AND id = ?")
      .run("waiting-customer", now, user.org_id, serviceCase.id);
    emitSuiteEvent(db, {
      orgId: user.org_id,
      actorUserId: user.id,
      eventType: "service.reply.recorded",
      subjectType: "service_case",
      subjectId: serviceCase.id,
      customerId: serviceCase.customer_id,
      status: "recorded",
      payload: { approvalState: "human-approved", channel: serviceCase.channel }
    });
    audit(db, user.org_id, user.id, "service.reply.recorded", { caseId: serviceCase.id });
    return { ok: true, case: getServiceCase(db, user.org_id, serviceCase.id), messages: getCaseMessages(db, user.org_id, serviceCase.id) };
  });

  app.patch("/api/service/cases/:id", async request => {
    const user = await app.auth(request);
    const serviceCaseId = normalizeServiceCasePathId(request.params.id);
    const serviceCase = getServiceCase(db, user.org_id, serviceCaseId);
    if (!serviceCase) { const err = new Error("Service case not found"); err.statusCode = 404; throw err; }
    // Escalation is supervisor-governed: every exit from the escalated state
    // (resolve already guards this) must also gate generic field changes, so a
    // non-supervisor can't silently de-escalate via PATCH { status }.
    if (serviceCase.status === "escalated") requireServiceSupervisor(user);
    const body = normalizeServiceCaseUpdateInput(request.body === undefined ? {} : request.body);
    const sets = [];
    const values = [];
    if (Object.prototype.hasOwnProperty.call(body, "status")) {
      sets.push("status = ?"); values.push(body.status);
    }
    if (Object.prototype.hasOwnProperty.call(body, "priority")) {
      sets.push("priority = ?"); values.push(body.priority);
    }
    if (Object.prototype.hasOwnProperty.call(body, "ownerUserId")) {
      const ownerUserId = body.ownerUserId;
      const owner = db.prepare("SELECT id FROM users WHERE org_id = ? AND id = ?").get(user.org_id, ownerUserId);
      if (!owner) { const err = new Error("Owner must be a user in this organization"); err.statusCode = 400; throw err; }
      sets.push("owner_user_id = ?"); values.push(ownerUserId);
    }
    if (sets.length === 0) { const err = new Error("No updatable fields provided"); err.statusCode = 400; throw err; }
    const now = new Date().toISOString();
    sets.push("updated_at = ?"); values.push(now);
    db.prepare(`UPDATE service_cases SET ${sets.join(", ")} WHERE org_id = ? AND id = ?`).run(...values, user.org_id, serviceCase.id);
    audit(db, user.org_id, user.id, "service.case.updated", { caseId: serviceCase.id, status: body.status, priority: body.priority, ownerUserId: body.ownerUserId });
    return { ok: true, case: getServiceCase(db, user.org_id, serviceCase.id) };
  });

