  app.post("/api/workflow/approvals/:id/decision", async request => {
    const user = await app.auth(request);
    requireOwner(user);
    const approvalId = normalizeWorkflowApprovalPathId(request.params.id);
    const body = request.body === undefined ? {} : request.body;
    const { decision, note } = normalizeWorkflowApprovalDecisionBody(body);
    const approval = getWorkflowApproval(db, user.org_id, approvalId);
    if (!approval) {
      const err = new Error("Approval not found");
      err.statusCode = 404;
      throw err;
    }
    if (approval.status !== "pending") {
      const err = new Error("Approval already decided");
      err.statusCode = 409;
      throw err;
    }
    const now = new Date().toISOString();
    db.prepare(`
      UPDATE workflow_approvals
      SET status = ?, decided_by_user_id = ?, decided_at = ?
      WHERE org_id = ? AND id = ?
    `).run(decision, user.id, now, user.org_id, approval.id);
    emitSuiteEvent(db, {
      orgId: user.org_id,
      actorUserId: user.id,
      eventType: `workflow.approval.${decision}`,
      subjectType: "workflow_approval",
      subjectId: approval.id,
      customerId: approval.customerId,
      status: decision,
      payload: { actionKey: approval.actionKey, riskLevel: approval.riskLevel, note }
    });
    audit(db, user.org_id, user.id, `workflow.approval.${decision}`, { approvalId: approval.id, actionKey: approval.actionKey });
    return { ok: true, approval: getWorkflowApproval(db, user.org_id, approval.id), events: getRecentSuiteEvents(db, user.org_id, 5, approval.customerId) };
  });

  app.post("/api/workflow/approvals/:id/execute", async (request, reply) => {
    const user = await app.auth(request);
    requireOwner(user);
    const approvalId = normalizeWorkflowApprovalPathId(request.params.id);
    const approval = getWorkflowApproval(db, user.org_id, approvalId);
    if (!approval) {
      const err = new Error("Approval not found");
      err.statusCode = 404;
      throw err;
    }
    if (approval.status === "pending") {
      const err = new Error("Approval must be approved before execution");
      err.statusCode = 409;
      throw err;
    }
    if (approval.status === "rejected") {
      const err = new Error("Rejected approval cannot be executed");
      err.statusCode = 409;
      throw err;
    }
    const existingRun = getWorkflowRunByApproval(db, user.org_id, approval.id);
    if (existingRun) {
      if (existingRun.status === "failed") {
        return replyWorkflowFailure(reply, db, user, approval, existingRun);
      }
      return {
        ok: true,
        idempotent: true,
        run: existingRun,
        ...getWorkflowRunResult(db, user.org_id, existingRun)
      };
    }

    try {
      const result = executeApprovedAction(db, user, approval);
      return { ok: true, idempotent: false, ...result, events: getRecentSuiteEvents(db, user.org_id, 8, approval.customerId) };
    } catch (error) {
      const failed = recordWorkflowRunFailure(db, user, approval, error);
      return replyWorkflowFailure(reply, db, user, approval, failed.run, error.statusCode || 500);
    }
  });

