function createClinicWellnessOperatorWorkbench(db, user, body) {
  const brief = resolvePilotOwnerBriefForWorkbench(db, user.org_id, body.briefId);
  if (!brief) {
    const err = new Error("Pilot owner brief not found");
    err.statusCode = 404;
    throw err;
  }
  const sourceKey = `operator-workbench:${brief.id}`;
  const existing = db.prepare("SELECT * FROM pilot_operator_workbenches WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) return { ok: true, idempotent: true, workbench: formatPilotOperatorWorkbench(existing, true) };

  const now = new Date().toISOString();
  const lanes = buildClinicWellnessOperatorLanes(brief);
  const payload = {
    kind: "armosphera-one-pilot-operator-workbench",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    briefId: brief.id,
    reportDate: brief.payload.reportDate || brief.reportDate,
    generatedAt: now,
    customer: brief.payload.customer,
    readinessGaps: brief.payload.readinessGaps || [],
    ownerNextActions: brief.payload.nextActions || [],
    lanes,
    summary: summarizePilotOperatorLanes(lanes),
    handoffChecklist: clinicWellnessOperatorHandoffChecklist()
  };
  const checksum = sha256Json(payload);
  const workbenchId = randomId("pilot-operator-workbench");
  const note = String(body.note || "").trim().slice(0, 500);
  db.prepare(`
    INSERT INTO pilot_operator_workbenches (
      id, org_id, template_key, brief_id, customer_id, report_date,
      status, source_key, checksum, payload, note, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    workbenchId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    brief.id,
    brief.customerId,
    payload.reportDate,
    "ready",
    sourceKey,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.operator_workbench.created",
    subjectType: "pilot_operator_workbench",
    subjectId: workbenchId,
    customerId: brief.customerId,
    status: "ready",
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      briefId: brief.id,
      totalActions: payload.summary.totalActions,
      reviewRequiredActions: payload.summary.reviewRequiredActions
    }
  });
  audit(db, user.org_id, user.id, "pilot.operator_workbench.created", {
    workbenchId,
    briefId: brief.id,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    reportDate: payload.reportDate,
    totalActions: payload.summary.totalActions,
    reviewRequiredActions: payload.summary.reviewRequiredActions,
    checksum
  });
  return { ok: true, idempotent: false, workbench: getPilotOperatorWorkbench(db, user.org_id, workbenchId, true) };
}

function resolvePilotOwnerBriefForWorkbench(db, orgId, briefId) {
  if (briefId) return getPilotOwnerBrief(db, orgId, String(briefId).trim(), true);
  const row = db.prepare(`
    SELECT id
    FROM pilot_owner_briefs
    WHERE org_id = ? AND template_key = ?
    ORDER BY report_date DESC, created_at DESC
    LIMIT 1
  `).get(orgId, CLINIC_WELLNESS_TEMPLATE_KEY);
  return row ? getPilotOwnerBrief(db, orgId, row.id, true) : null;
}

function buildClinicWellnessOperatorLanes(brief) {
  const answers = brief.payload.answers || [];
  const recordsFor = question => answers.find(answer => answer.question === question)?.records || [];
  return [
    {
      key: "receivables",
      title: "Receivables follow-up",
      ownerRole: "Operator",
      actions: recordsFor("Who owes money?").map(record => ({
        key: `collect-${record.invoiceId}`,
        title: `Collect or promise ${record.invoiceNumber}`,
        priority: record.status === "overdue" ? "high" : "medium",
        ownerRole: "Operator",
        reviewRequired: true,
        reviewReason: "Accountant-reviewed collection wording required before external reminder.",
        suggestedChannel: "WhatsApp",
        due: record.dueDate,
        nextStep: "Confirm payment status, record a promise, and attach HayHashvapah evidence before any customer reminder.",
        source: {
          type: "invoice",
          id: record.invoiceId,
          invoiceNumber: record.invoiceNumber,
          status: record.status,
          customerId: record.customerId,
          customerName: record.customerName
        },
        hayhashvapahContext: {
          invoiceNumber: record.invoiceNumber,
          amount: record.amount,
          vat: record.vat,
          currency: record.currency,
          dueDate: record.dueDate
        }
      }))
    },
    {
      key: "stuck-leads",
      title: "Stuck lead conversion",
      ownerRole: "Salesperson",
      actions: recordsFor("Which leads are stuck?").map(record => ({
        key: `convert-${record.leadId}`,
        title: `Convert ${record.companyName}`,
        priority: record.rating === "hot" ? "high" : "medium",
        ownerRole: "Salesperson",
        reviewRequired: false,
        suggestedChannel: record.channel || "Phone",
        due: brief.reportDate,
        nextStep: record.nextAction || "Create quote-ready CRM deal with Armenian package pricing.",
        source: {
          type: "lead",
          id: record.leadId,
          rating: record.rating,
          status: record.status,
          companyName: record.companyName
        },
        estimatedValue: record.estimatedValue,
        currency: record.currency,
        score: record.score
      }))
    },
    {
      key: "late-tickets",
      title: "SLA rescue",
      ownerRole: "Operator",
      actions: recordsFor("Which tickets are late?").map(record => ({
        key: `rescue-${record.caseId}`,
        title: `Recover ${record.caseNumber}`,
        priority: record.slaStatus === "at-risk" ? "high" : record.priority,
        ownerRole: "Operator",
        reviewRequired: false,
        suggestedChannel: "Service Hub",
        due: record.slaDueAt,
        nextStep: "Send a human-approved update and escalate if the SLA remains at risk.",
        source: {
          type: "service_case",
          id: record.caseId,
          caseNumber: record.caseNumber,
          customerId: record.customerId,
          customerName: record.customerName,
          subject: record.subject
        },
        slaStatus: record.slaStatus,
        caseStatus: record.status
      }))
    },
    {
      key: "campaign-revenue",
      title: "Campaign revenue loop",
      ownerRole: "Owner",
      actions: recordsFor("Which campaigns produced paying clients?")
        .filter(record => record.paidRevenue > 0)
        .map(record => ({
          key: `retain-${record.campaignId}`,
          title: `Repeat ${record.name}`,
          priority: record.roi > 0 ? "medium" : "low",
          ownerRole: "Owner",
          reviewRequired: false,
          suggestedChannel: record.channel,
          due: brief.reportDate,
          nextStep: "Use paid-revenue attribution to decide whether the clinic pilot should repeat this channel.",
          source: {
            type: "campaign",
            id: record.campaignId,
            name: record.name
          },
          budget: record.budget,
          paidRevenue: record.paidRevenue,
          roi: record.roi,
          currency: record.currency,
          attributionCount: record.attributionCount
        }))
    },
    {
      key: "compliance-review",
      title: "Tax and accounting review",
      ownerRole: "Accountant",
      actions: recordsFor("What tax/accounting actions need review?").map(record => ({
        key: `review-${record.key}`,
        title: record.label,
        priority: record.status === "clear" ? "low" : "high",
        ownerRole: "Accountant",
        reviewRequired: record.status !== "clear",
        suggestedChannel: "HayHashvapah",
        due: record.due,
        nextStep: "Resolve VAT/SRC, period-lock, or receivable evidence before live external wording.",
        source: {
          type: "compliance_record",
          id: record.key,
          status: record.status
        },
        evidence: record.evidence
      }))
    }
  ];
}

function summarizePilotOperatorLanes(lanes) {
  const actions = lanes.flatMap(lane => lane.actions || []);
  return {
    totalActions: actions.length,
    highPriorityActions: actions.filter(action => action.priority === "high").length,
    reviewRequiredActions: actions.filter(action => action.reviewRequired).length,
    laneCount: lanes.length,
    currency: activeCurrencyCode()
  };
}

