function createClinicWellnessAccountantReview(db, user, body) {
  const workbench = resolvePilotOperatorWorkbenchForReview(db, user.org_id, body.workbenchId);
  if (!workbench) {
    const err = new Error("Pilot operator workbench not found");
    err.statusCode = 404;
    throw err;
  }
  const sourceKey = `accountant-review:${workbench.id}`;
  const existing = db.prepare("SELECT * FROM pilot_accountant_reviews WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) return { ok: true, idempotent: true, review: formatPilotAccountantReview(existing, true) };

  const now = new Date().toISOString();
  const items = buildClinicWellnessAccountantReviewItems(db, user.org_id, workbench);
  const payload = {
    kind: "armosphera-one-pilot-accountant-review",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    workbenchId: workbench.id,
    reportDate: workbench.payload.reportDate || workbench.reportDate,
    generatedAt: now,
    customer: workbench.payload.customer,
    items,
    summary: summarizePilotAccountantReviewItems(items),
    checklist: clinicWellnessAccountantReviewChecklist()
  };
  const checksum = sha256Json(payload);
  const reviewId = randomId("pilot-accountant-review");
  const note = String(body.note || "").trim().slice(0, 500);
  db.prepare(`
    INSERT INTO pilot_accountant_reviews (
      id, org_id, template_key, workbench_id, customer_id, report_date,
      status, source_key, checksum, payload, note, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    reviewId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    workbench.id,
    workbench.customerId,
    payload.reportDate,
    "ready",
    sourceKey,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.accountant_review.created",
    subjectType: "pilot_accountant_review",
    subjectId: reviewId,
    customerId: workbench.customerId,
    status: "ready",
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      workbenchId: workbench.id,
      itemCount: payload.summary.itemCount,
      openReviewCount: payload.summary.openReviewCount,
      moneyAtRisk: payload.summary.moneyAtRisk
    }
  });
  audit(db, user.org_id, user.id, "pilot.accountant_review.created", {
    reviewId,
    workbenchId: workbench.id,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    reportDate: payload.reportDate,
    itemCount: payload.summary.itemCount,
    openReviewCount: payload.summary.openReviewCount,
    moneyAtRisk: payload.summary.moneyAtRisk,
    checksum
  });
  return { ok: true, idempotent: false, review: getPilotAccountantReview(db, user.org_id, reviewId, true) };
}

function resolvePilotOperatorWorkbenchForReview(db, orgId, workbenchId) {
  if (workbenchId) return getPilotOperatorWorkbench(db, orgId, String(workbenchId).trim(), true);
  const row = db.prepare(`
    SELECT id
    FROM pilot_operator_workbenches
    WHERE org_id = ? AND template_key = ?
    ORDER BY report_date DESC, created_at DESC
    LIMIT 1
  `).get(orgId, CLINIC_WELLNESS_TEMPLATE_KEY);
  return row ? getPilotOperatorWorkbench(db, orgId, row.id, true) : null;
}

function buildClinicWellnessAccountantReviewItems(db, orgId, workbench) {
  const lanes = workbench.payload.lanes || [];
  const receivables = lanes.find(lane => lane.key === "receivables")?.actions || [];
  const compliance = lanes.find(lane => lane.key === "compliance-review")?.actions || [];
  const items = [];
  for (const action of receivables) {
    items.push({
      key: `receivable-vat-check-${action.source.id}`,
      category: "receivable-vat",
      title: `VAT and collection wording for ${action.source.invoiceNumber}`,
      status: action.source.status === "overdue" ? "needs-accountant-review" : "review-optional",
      ownerRole: "Accountant",
      reviewRequired: true,
      due: action.due,
      invoiceId: action.source.id,
      invoiceNumber: action.source.invoiceNumber,
      customerId: action.source.customerId,
      customerName: action.source.customerName,
      amount: action.hayhashvapahContext.amount,
      vat: action.hayhashvapahContext.vat,
      currency: action.hayhashvapahContext.currency,
      sourceStatus: action.source.status,
      evidence: `HayHashvapah invoice ${action.source.invoiceNumber} ${action.source.status}`
    });
  }
  for (const action of compliance) {
    items.push(buildClinicWellnessComplianceReviewItem(db, orgId, action));
  }
  return items;
}

function buildClinicWellnessComplianceReviewItem(db, orgId, action) {
  const sourceId = action.source?.id || action.key;
  if (sourceId === "vat-src-review") {
    const legalSource = getLegalSource(db, orgId, "law-tax-code");
    return {
      key: "vat-src-review",
      category: "vat-src",
      title: action.title,
      status: legalSource?.status || action.source?.status || "needs-accountant-review",
      ownerRole: "Accountant",
      reviewRequired: true,
      due: action.due,
      legalSource: legalSource ? {
        id: legalSource.id,
        title: legalSource.title,
        status: legalSource.status,
        effectiveDate: legalSource.effectiveDate,
        sourceUrl: legalSource.sourceUrl
      } : null,
      evidence: action.evidence
    };
  }
  if (sourceId === "period-lock") {
    const period = db.prepare(`
      SELECT *
      FROM finance_periods
      WHERE org_id = ? AND status = 'open'
      ORDER BY period_key DESC
      LIMIT 1
    `).get(orgId);
    return {
      key: "period-lock",
      category: "period-lock",
      title: action.title,
      status: period?.status || action.source?.status || "missing-open-period",
      ownerRole: "Accountant",
      reviewRequired: true,
      due: period?.ends_on || action.due,
      periodKey: period?.period_key || null,
      evidence: period ? `${period.period_key} ${period.status}` : action.evidence
    };
  }
  return {
    key: sourceId,
    category: "accounting-action",
    title: action.title,
    status: action.source?.status || "needs-action",
    ownerRole: "Accountant",
    reviewRequired: action.source?.status !== "clear",
    due: action.due,
    evidence: action.evidence
  };
}

function summarizePilotAccountantReviewItems(items) {
  return {
    itemCount: items.length,
    openReviewCount: items.filter(item => item.reviewRequired && item.status !== "clear").length,
    moneyAtRisk: items
      .filter(item => item.category === "receivable-vat" && item.sourceStatus === "overdue")
      .reduce((sum, item) => sum + Number(item.amount || 0), 0),
    vatItemCount: items.filter(item => ["vat-src", "receivable-vat"].includes(item.category)).length,
    periodItemCount: items.filter(item => item.category === "period-lock").length,
    currency: activeCurrencyCode()
  };
}

function clinicWellnessAccountantReviewChecklist() {
  return [
    "Confirm VAT legal source status before customer-facing invoice wording.",
    "Verify the HayHashvapah period remains open before posting or export packet preparation.",
    "Review overdue receivable wording before WhatsApp, Telegram, email, or phone follow-up.",
    "Keep SRC/File Online export packets offline until accountant review is complete."
  ];
}

