function createClinicWellnessLaunchReadinessPacket(db, user, body) {
  const review = resolvePilotAccountantReviewForLaunch(db, user.org_id, body.accountantReviewId);
  if (!review) {
    const err = new Error("Pilot accountant review not found");
    err.statusCode = 404;
    throw err;
  }
  const targetLaunchDate = normalizeIsoDate(body.targetLaunchDate || armeniaDateString(), "targetLaunchDate");
  const sourceKey = `launch-readiness:${review.id}:${targetLaunchDate}`;
  const existing = db.prepare("SELECT * FROM pilot_launch_readiness_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) return { ok: true, idempotent: true, packet: formatPilotLaunchReadinessPacket(existing, true) };

  const chain = resolvePilotLaunchReadinessChain(db, user.org_id, review);
  const now = new Date().toISOString();
  const commercial = buildPilotLaunchCommercialSummary(chain.install);
  const gates = buildClinicWellnessLaunchGates(chain, review, commercial);
  const summary = summarizePilotLaunchGates(gates, review);
  const payload = {
    kind: "armosphera-one-pilot-launch-readiness",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    targetLaunchDate,
    generatedAt: now,
    customer: review.payload.customer,
    accountantReviewId: review.id,
    workbenchId: review.workbenchId,
    ownerBriefId: chain.brief?.id || chain.workbench?.briefId || null,
    installId: chain.install?.id || chain.brief?.installId || null,
    commercial,
    gates,
    summary,
    goLiveDecision: summary.blockerCount > 0 ? "blocked" : "ready",
    goLiveAllowed: summary.blockerCount === 0,
    nextActions: buildPilotLaunchReadinessNextActions(gates, review)
  };
  const status = payload.goLiveDecision;
  const checksum = sha256Json(payload);
  const packetId = randomId("pilot-launch-readiness");
  const note = String(body.note || "").trim().slice(0, 500);
  db.prepare(`
    INSERT INTO pilot_launch_readiness_packets (
      id, org_id, template_key, accountant_review_id, customer_id, target_launch_date,
      status, source_key, checksum, payload, note, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    packetId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    review.id,
    review.customerId,
    targetLaunchDate,
    status,
    sourceKey,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.launch_readiness.created",
    subjectType: "pilot_launch_readiness_packet",
    subjectId: packetId,
    customerId: review.customerId,
    status,
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      accountantReviewId: review.id,
      targetLaunchDate,
      blockerCount: summary.blockerCount,
      moneyAtRisk: summary.moneyAtRisk
    }
  });
  audit(db, user.org_id, user.id, "pilot.launch_readiness.created", {
    packetId,
    accountantReviewId: review.id,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    targetLaunchDate,
    status,
    blockerCount: summary.blockerCount,
    moneyAtRisk: summary.moneyAtRisk,
    checksum
  });
  return { ok: true, idempotent: false, packet: getPilotLaunchReadinessPacket(db, user.org_id, packetId, true) };
}

function resolvePilotAccountantReviewForLaunch(db, orgId, reviewId) {
  if (reviewId) return getPilotAccountantReview(db, orgId, String(reviewId).trim(), true);
  const row = db.prepare(`
    SELECT id
    FROM pilot_accountant_reviews
    WHERE org_id = ? AND template_key = ?
    ORDER BY report_date DESC, created_at DESC
    LIMIT 1
  `).get(orgId, CLINIC_WELLNESS_TEMPLATE_KEY);
  return row ? getPilotAccountantReview(db, orgId, row.id, true) : null;
}

function resolvePilotLaunchReadinessChain(db, orgId, review) {
  const workbench = getPilotOperatorWorkbench(db, orgId, review.workbenchId, true);
  const briefId = workbench?.briefId || workbench?.payload?.briefId;
  const brief = briefId ? getPilotOwnerBrief(db, orgId, briefId, true) : null;
  const installId = brief?.installId || brief?.payload?.installId;
  const install = installId ? getPilotTemplateInstall(db, orgId, installId, true) : null;
  return { install, brief, workbench };
}

function buildPilotLaunchCommercialSummary(install) {
  const pricing = install?.payload?.pricing || install?.pricing || {};
  return {
    currency: currencyOrActive(pricing.currency),
    setupFee: pricing.setupFee || 0,
    monthlyOpsFee: pricing.monthlyOpsFee || 0,
    optionalPerformanceFee: Boolean(pricing.optionalPerformanceFee),
    rolloutShape: install?.payload?.rolloutShape || null
  };
}

function buildClinicWellnessLaunchGates(chain, review, commercial) {
  const readinessGaps = chain.install?.payload?.readiness?.gaps || chain.workbench?.payload?.readinessGaps || [];
  const workbenchSummary = chain.workbench?.payload?.summary || {};
  const reviewSummary = review.payload.summary || {};
  const evidenceMissing = [
    !chain.install && "pilot install",
    !chain.brief && "owner brief",
    !chain.workbench && "operator workbench",
    !review && "accountant review"
  ].filter(Boolean);
  return [
    {
      key: "evidence-chain",
      label: "Pilot evidence chain",
      status: evidenceMissing.length ? "blocked" : "ready",
      blockers: evidenceMissing,
      evidence: {
        installId: chain.install?.id || null,
        ownerBriefId: chain.brief?.id || null,
        workbenchId: chain.workbench?.id || null,
        accountantReviewId: review.id
      }
    },
    {
      key: "commercial-package",
      label: "Commercial package",
      status: commercial.setupFee > 0 && commercial.monthlyOpsFee > 0 ? "ready" : "blocked",
      blockers: commercial.setupFee > 0 && commercial.monthlyOpsFee > 0 ? [] : ["package pricing missing"],
      setupFee: commercial.setupFee,
      monthlyOpsFee: commercial.monthlyOpsFee,
      currency: commercial.currency
    },
    {
      key: "operator-workbench",
      label: "Operator workbench",
      status: workbenchSummary.totalActions > 0 ? "ready" : "blocked",
      blockers: workbenchSummary.totalActions > 0 ? [] : ["operator actions missing"],
      totalActions: workbenchSummary.totalActions || 0,
      highPriorityActions: workbenchSummary.highPriorityActions || 0,
      reviewRequiredActions: workbenchSummary.reviewRequiredActions || 0
    },
    {
      key: "accountant-review",
      label: "Accountant review",
      status: (reviewSummary.openReviewCount || 0) > 0 ? "blocked" : "ready",
      blockers: (reviewSummary.openReviewCount || 0) > 0 ? ["open accountant review items"] : [],
      itemCount: reviewSummary.itemCount || 0,
      openReviewCount: reviewSummary.openReviewCount || 0
    },
    {
      key: "connector-readiness",
      label: "Integration readiness",
      status: readinessGaps.length ? "blocked" : "ready",
      blockers: readinessGaps,
      requiredConnectors: chain.install?.payload?.requiredConnectors || []
    },
    {
      key: "money-at-risk",
      label: "Overdue money at risk",
      status: (reviewSummary.moneyAtRisk || 0) > 0 ? "blocked" : "ready",
      blockers: (reviewSummary.moneyAtRisk || 0) > 0 ? ["overdue receivable unresolved"] : [],
      moneyAtRisk: reviewSummary.moneyAtRisk || 0,
      currency: activeCurrencyCode()
    }
  ];
}

function summarizePilotLaunchGates(gates, review) {
  return {
    gateCount: gates.length,
    readyCount: gates.filter(gate => gate.status === "ready").length,
    blockerCount: gates.reduce((sum, gate) => sum + (gate.blockers || []).length, 0),
    blockedGateCount: gates.filter(gate => gate.status === "blocked").length,
    moneyAtRisk: review.payload.summary?.moneyAtRisk || 0,
    currency: activeCurrencyCode()
  };
}

function buildPilotLaunchReadinessNextActions(gates, review) {
  const actions = [];
  const accountantGate = gates.find(gate => gate.key === "accountant-review");
  const connectorGate = gates.find(gate => gate.key === "connector-readiness");
  const moneyGate = gates.find(gate => gate.key === "money-at-risk");
  if ((accountantGate?.openReviewCount || 0) > 0) {
    actions.push("Resolve accountant VAT/SRC and period-lock review items before launch.");
  }
  if ((connectorGate?.blockers || []).length) {
    actions.push("Configure WhatsApp Business and HayHashvapah finance connectors before live customer operations.");
  }
  if ((moneyGate?.moneyAtRisk || 0) > 0) {
    actions.push("Close or document overdue receivable risk before offering the paid pilot.");
  }
  if (!actions.length) actions.push("Approve go-live and prepare the paid pilot onboarding sequence.");
  if ((review.payload.checklist || []).length) actions.push("Archive accountant review checklist with the launch readiness packet.");
  return actions;
}

