function createClinicWellnessLaunchRemediationPlan(db, user, body) {
  const readiness = resolvePilotLaunchReadinessForRemediation(db, user.org_id, body.launchReadinessId);
  if (!readiness) {
    const err = new Error("Pilot launch readiness packet not found");
    err.statusCode = 404;
    throw err;
  }
  const sourceKey = `launch-remediation:${readiness.id}`;
  const existing = db.prepare("SELECT * FROM pilot_launch_remediation_plans WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) return { ok: true, idempotent: true, plan: formatPilotLaunchRemediationPlan(existing, true) };

  const now = new Date().toISOString();
  const actions = buildPilotLaunchRemediationActions(readiness);
  const payload = {
    kind: "armosphera-one-pilot-launch-remediation-plan",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    launchReadinessId: readiness.id,
    targetLaunchDate: readiness.payload.targetLaunchDate || readiness.targetLaunchDate,
    generatedAt: now,
    customer: readiness.payload.customer,
    goLiveDecision: readiness.payload.goLiveDecision,
    completionPolicy: "all-actions-closed-before-go-live",
    actions,
    summary: summarizePilotLaunchRemediationActions(actions, readiness),
    checklist: clinicWellnessLaunchRemediationChecklist()
  };
  const checksum = sha256Json(payload);
  const planId = randomId("pilot-launch-remediation");
  const note = String(body.note || "").trim().slice(0, 500);
  db.prepare(`
    INSERT INTO pilot_launch_remediation_plans (
      id, org_id, template_key, launch_readiness_id, customer_id, target_launch_date,
      status, source_key, checksum, payload, note, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    planId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    readiness.id,
    readiness.customerId,
    payload.targetLaunchDate,
    "open",
    sourceKey,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.launch_remediation.created",
    subjectType: "pilot_launch_remediation_plan",
    subjectId: planId,
    customerId: readiness.customerId,
    status: "open",
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      launchReadinessId: readiness.id,
      actionCount: payload.summary.actionCount,
      moneyAtRisk: payload.summary.moneyAtRisk
    }
  });
  audit(db, user.org_id, user.id, "pilot.launch_remediation.created", {
    planId,
    launchReadinessId: readiness.id,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    targetLaunchDate: payload.targetLaunchDate,
    actionCount: payload.summary.actionCount,
    blockerCount: payload.summary.blockerCount,
    moneyAtRisk: payload.summary.moneyAtRisk,
    checksum
  });
  return { ok: true, idempotent: false, plan: getPilotLaunchRemediationPlan(db, user.org_id, planId, true) };
}

function resolvePilotLaunchReadinessForRemediation(db, orgId, launchReadinessId) {
  if (launchReadinessId) return getPilotLaunchReadinessPacket(db, orgId, String(launchReadinessId).trim(), true);
  const row = db.prepare(`
    SELECT id
    FROM pilot_launch_readiness_packets
    WHERE org_id = ? AND template_key = ?
    ORDER BY target_launch_date DESC, created_at DESC
    LIMIT 1
  `).get(orgId, CLINIC_WELLNESS_TEMPLATE_KEY);
  return row ? getPilotLaunchReadinessPacket(db, orgId, row.id, true) : null;
}

function buildPilotLaunchRemediationActions(readiness) {
  const gates = readiness.payload.gates || [];
  const targetLaunchDate = readiness.payload.targetLaunchDate || readiness.targetLaunchDate;
  const actions = [];
  const accountantGate = gates.find(gate => gate.key === "accountant-review");
  if ((accountantGate?.openReviewCount || 0) > 0) {
    actions.push({
      key: "resolve-accountant-review",
      title: "Resolve accountant VAT/SRC and period-lock review",
      category: "accountant-review",
      ownerRole: "Accountant",
      status: "open",
      priority: "high",
      sourceGate: "accountant-review",
      dueDate: targetLaunchDate,
      openReviewCount: accountantGate.openReviewCount,
      nextStep: "Review VAT legal source, period lock, and public invoice wording before launch."
    });
  }

  const connectorGate = gates.find(gate => gate.key === "connector-readiness");
  for (const blocker of connectorGate?.blockers || []) {
    actions.push({
      key: blocker,
      title: launchConnectorRemediationTitle(blocker),
      category: "connector-readiness",
      ownerRole: "Admin",
      status: "open",
      priority: blocker.includes("whatsapp") || blocker.includes("hayhashvapah") ? "high" : "medium",
      sourceGate: "connector-readiness",
      dueDate: targetLaunchDate,
      connectorKey: blocker.replace(/^configure-/, ""),
      nextStep: "Configure connector contract and run Integration Hub health check."
    });
  }

  const moneyGate = gates.find(gate => gate.key === "money-at-risk");
  if ((moneyGate?.moneyAtRisk || 0) > 0) {
    actions.push({
      key: "close-overdue-receivable-risk",
      title: "Close or document overdue receivable risk",
      category: "money-at-risk",
      ownerRole: "Operator",
      status: "open",
      priority: "high",
      sourceGate: "money-at-risk",
      dueDate: targetLaunchDate,
      moneyAtRisk: moneyGate.moneyAtRisk,
      currency: currencyOrActive(moneyGate.currency),
      nextStep: "Record payment promise, reminder evidence, or owner-approved exception before paid pilot offer."
    });
  }

  const commercialGate = gates.find(gate => gate.key === "commercial-package");
  if (commercialGate?.status === "blocked") {
    actions.push({
      key: "complete-commercial-package",
      title: "Complete commercial package pricing",
      category: "commercial-package",
      ownerRole: "Owner",
      status: "open",
      priority: "high",
      sourceGate: "commercial-package",
      dueDate: targetLaunchDate,
      nextStep: "Confirm setup fee, monthly ops fee, and paid pilot terms."
    });
  }
  return actions;
}

function launchConnectorRemediationTitle(blocker) {
  const label = blocker.replace(/^configure-/, "").replace(/-/g, " ");
  return `Configure ${label}`;
}

function summarizePilotLaunchRemediationActions(actions, readiness) {
  return {
    actionCount: actions.length,
    highPriorityCount: actions.filter(action => action.priority === "high").length,
    blockerCount: readiness.payload.summary?.blockerCount || 0,
    moneyAtRisk: readiness.payload.summary?.moneyAtRisk || 0,
    ownerRoles: Array.from(new Set(actions.map(action => action.ownerRole))).sort(),
    currency: activeCurrencyCode()
  };
}

function clinicWellnessLaunchRemediationChecklist() {
  return [
    "Re-run launch readiness after every remediation action is resolved.",
    "Keep connector secrets outside backup packets and re-enter them through Integration Hub.",
    "Do not offer the paid pilot until accountant review and overdue receivable risk are cleared.",
    "Record every remediation outcome into Customer 360 or the relevant evidence packet."
  ];
}

function getPilotLaunchRemediationPlans(db, orgId, templateKey) {
  return db.prepare(`
    SELECT pilot_launch_remediation_plans.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_launch_remediation_plans
    JOIN customers ON customers.id = pilot_launch_remediation_plans.customer_id
    LEFT JOIN users ON users.id = pilot_launch_remediation_plans.created_by_user_id
    WHERE pilot_launch_remediation_plans.org_id = ? AND pilot_launch_remediation_plans.template_key = ?
    ORDER BY pilot_launch_remediation_plans.target_launch_date DESC, pilot_launch_remediation_plans.created_at DESC
  `).all(orgId, templateKey).map(row => formatPilotLaunchRemediationPlan(row, false));
}

function getPilotLaunchRemediationPlan(db, orgId, planId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_launch_remediation_plans.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_launch_remediation_plans
    JOIN customers ON customers.id = pilot_launch_remediation_plans.customer_id
    LEFT JOIN users ON users.id = pilot_launch_remediation_plans.created_by_user_id
    WHERE pilot_launch_remediation_plans.org_id = ? AND pilot_launch_remediation_plans.id = ?
  `).get(orgId, planId);
  return row ? formatPilotLaunchRemediationPlan(row, includePayload) : null;
}

function formatPilotLaunchRemediationPlan(row, includePayload = false) {
  const payload = safeJson(row.payload);
  const summary = payload.summary || {};
  const plan = {
    id: row.id,
    templateKey: row.template_key,
    launchReadinessId: row.launch_readiness_id,
    customerId: row.customer_id,
    customerName: row.customer_name || payload.customer?.name,
    targetLaunchDate: row.target_launch_date,
    status: row.status,
    checksum: row.checksum,
    actionCount: summary.actionCount || (payload.actions || []).length,
    actionSummaries: (payload.actions || []).map(action => ({
      key: action.key,
      title: action.title,
      ownerRole: action.ownerRole,
      sourceGate: action.sourceGate,
      status: action.status,
      priority: action.priority,
      dueDate: action.dueDate,
      moneyAtRisk: action.moneyAtRisk || 0
    })),
    highPriorityCount: summary.highPriorityCount || 0,
    blockerCount: summary.blockerCount || 0,
    moneyAtRisk: summary.moneyAtRisk || 0,
    note: row.note,
    createdByUserId: row.created_by_user_id,
    createdByName: row.created_by_name,
    createdAt: row.created_at,
    updatedAt: row.updated_at
  };
  if (includePayload) plan.payload = payload;
  return plan;
}

function resolveClinicWellnessRemediationAction(db, user, actionKeyParam, body) {
  const planId = String(body.planId || "").trim();
  if (!planId) {
    const err = new Error("Pilot remediation plan required");
    err.statusCode = 400;
    throw err;
  }
  const plan = getPilotLaunchRemediationPlan(db, user.org_id, planId, true);
  if (!plan) {
    const err = new Error("Pilot remediation plan not found");
    err.statusCode = 404;
    throw err;
  }
  const actionKey = String(actionKeyParam || "").trim();
  const action = (plan.payload.actions || []).find(item => item.key === actionKey);
  if (!action) {
    const err = new Error("Pilot remediation action not found");
    err.statusCode = 404;
    throw err;
  }
  requirePilotRemediationResolutionWriterForAction(user, action);

  const existing = getPilotRemediationActionResolutionByAction(db, user.org_id, plan.id, action.key, true);
  if (existing) return { ok: true, idempotent: true, resolution: existing };

  const evidenceType = String(body.evidenceType || "").trim().slice(0, 80);
  const evidence = String(body.evidence || "").trim().slice(0, 1200);
  if (!evidenceType || !evidence) {
    const err = new Error("Pilot remediation evidence required");
    err.statusCode = 400;
    throw err;
  }

  const now = new Date().toISOString();
  const progress = buildPilotRemediationResolutionProgress(db, user.org_id, plan, action.key);
  const note = String(body.note || "").trim().slice(0, 500);
  const payload = {
    kind: "armosphera-one-pilot-remediation-resolution",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    remediationPlanId: plan.id,
    launchReadinessId: plan.launchReadinessId,
    targetLaunchDate: plan.targetLaunchDate,
    resolvedAt: now,
    customer: {
      id: plan.customerId,
      name: plan.customerName
    },
    action: {
      ...action,
      status: "resolved"
    },
    evidence: {
      type: evidenceType,
      text: evidence
    },
    progress,
    resolvedBy: {
      id: user.id,
      name: user.name,
      role: user.role
    },
    note
  };
  const checksum = sha256Json(payload);
  const resolutionId = randomId("pilot-remediation-resolution");
  db.prepare(`
    INSERT INTO pilot_remediation_action_resolutions (
      id, org_id, template_key, remediation_plan_id, launch_readiness_id, customer_id,
      target_launch_date, action_key, action_title, owner_role, source_gate, status,
      evidence_type, evidence, money_at_risk, checksum, payload, note,
      resolved_by_user_id, resolved_at, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    resolutionId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    plan.id,
    plan.launchReadinessId,
    plan.customerId,
    plan.targetLaunchDate,
    action.key,
    action.title,
    action.ownerRole,
    action.sourceGate,
    "resolved",
    evidenceType,
    evidence,
    Math.round(Number(action.moneyAtRisk || 0)),
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now,
    now
  );
  if (progress.allResolved) {
    db.prepare("UPDATE pilot_launch_remediation_plans SET status = ?, updated_at = ? WHERE org_id = ? AND id = ?")
      .run("resolved", now, user.org_id, plan.id);
  }
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.remediation_action.resolved",
    subjectType: "pilot_remediation_action_resolution",
    subjectId: resolutionId,
    customerId: plan.customerId,
    status: "resolved",
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      planId: plan.id,
      actionKey: action.key,
      ownerRole: action.ownerRole,
      sourceGate: action.sourceGate,
      evidenceType,
      progress
    }
  });
  audit(db, user.org_id, user.id, "pilot.remediation_action.resolved", {
    resolutionId,
    planId: plan.id,
    actionKey: action.key,
    ownerRole: action.ownerRole,
    sourceGate: action.sourceGate,
    evidenceType,
    progress,
    checksum
  });
  return {
    ok: true,
    idempotent: false,
    resolution: getPilotRemediationActionResolution(db, user.org_id, resolutionId, true)
  };
}

function buildPilotRemediationResolutionProgress(db, orgId, plan, nextActionKey = "") {
  const totalActionCount = (plan.payload.actions || []).length;
  const resolvedKeys = new Set(db.prepare(`
    SELECT action_key
    FROM pilot_remediation_action_resolutions
    WHERE org_id = ? AND remediation_plan_id = ?
  `).all(orgId, plan.id).map(row => row.action_key));
  if (nextActionKey) resolvedKeys.add(nextActionKey);
  const resolvedActionCount = Math.min(resolvedKeys.size, totalActionCount);
  const remainingActionCount = Math.max(totalActionCount - resolvedActionCount, 0);
  return {
    resolvedActionCount,
    totalActionCount,
    remainingActionCount,
    completionPercent: totalActionCount ? Math.round((resolvedActionCount / totalActionCount) * 100) : 100,
    allResolved: remainingActionCount === 0
  };
}

function getPilotRemediationActionResolutions(db, orgId, templateKey, planId = "") {
  const filters = ["pilot_remediation_action_resolutions.org_id = ?", "pilot_remediation_action_resolutions.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedPlanId = String(planId || "").trim();
  if (requestedPlanId) {
    filters.push("pilot_remediation_action_resolutions.remediation_plan_id = ?");
    params.push(requestedPlanId);
  }
  return db.prepare(`
    SELECT pilot_remediation_action_resolutions.*, customers.name AS customer_name, users.name AS resolved_by_name
    FROM pilot_remediation_action_resolutions
    JOIN customers ON customers.id = pilot_remediation_action_resolutions.customer_id
    LEFT JOIN users ON users.id = pilot_remediation_action_resolutions.resolved_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_remediation_action_resolutions.resolved_at DESC, pilot_remediation_action_resolutions.created_at DESC
  `).all(...params).map(row => formatPilotRemediationActionResolution(row, false));
}

function getPilotRemediationActionResolution(db, orgId, resolutionId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_remediation_action_resolutions.*, customers.name AS customer_name, users.name AS resolved_by_name
    FROM pilot_remediation_action_resolutions
    JOIN customers ON customers.id = pilot_remediation_action_resolutions.customer_id
    LEFT JOIN users ON users.id = pilot_remediation_action_resolutions.resolved_by_user_id
    WHERE pilot_remediation_action_resolutions.org_id = ? AND pilot_remediation_action_resolutions.id = ?
  `).get(orgId, resolutionId);
  return row ? formatPilotRemediationActionResolution(row, includePayload) : null;
}

function getPilotRemediationActionResolutionByAction(db, orgId, planId, actionKey, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_remediation_action_resolutions.*, customers.name AS customer_name, users.name AS resolved_by_name
    FROM pilot_remediation_action_resolutions
    JOIN customers ON customers.id = pilot_remediation_action_resolutions.customer_id
    LEFT JOIN users ON users.id = pilot_remediation_action_resolutions.resolved_by_user_id
    WHERE pilot_remediation_action_resolutions.org_id = ?
      AND pilot_remediation_action_resolutions.remediation_plan_id = ?
      AND pilot_remediation_action_resolutions.action_key = ?
  `).get(orgId, planId, actionKey);
  return row ? formatPilotRemediationActionResolution(row, includePayload) : null;
}

function formatPilotRemediationActionResolution(row, includePayload = false) {
  const payload = safeJson(row.payload);
  const resolution = {
    id: row.id,
    templateKey: row.template_key,
    remediationPlanId: row.remediation_plan_id,
    launchReadinessId: row.launch_readiness_id,
    customerId: row.customer_id,
    customerName: row.customer_name || payload.customer?.name,
    targetLaunchDate: row.target_launch_date,
    actionKey: row.action_key,
    actionTitle: row.action_title,
    ownerRole: row.owner_role,
    sourceGate: row.source_gate,
    status: row.status,
    evidenceType: row.evidence_type,
    moneyAtRisk: Number(row.money_at_risk || 0),
    checksum: row.checksum,
    note: row.note,
    resolvedByUserId: row.resolved_by_user_id,
    resolvedByName: row.resolved_by_name,
    resolvedAt: row.resolved_at,
    createdAt: row.created_at,
    updatedAt: row.updated_at
  };
  if (includePayload) resolution.payload = payload;
  return resolution;
}

function createClinicWellnessLaunchClearancePacket(db, user, body) {
  const plan = resolvePilotLaunchRemediationForClearance(db, user.org_id, body.remediationPlanId);
  if (!plan) {
    const err = new Error("Pilot launch remediation plan not found");
    err.statusCode = 404;
    throw err;
  }
  const actions = plan.payload.actions || [];
  const resolutions = getPilotRemediationActionResolutions(db, user.org_id, CLINIC_WELLNESS_TEMPLATE_KEY, plan.id);
  const resolutionByAction = new Map(resolutions.map(resolution => [resolution.actionKey, resolution]));
  const resolvedActions = actions.filter(action => resolutionByAction.has(action.key))
    .map(action => formatLaunchClearanceResolvedAction(action, resolutionByAction.get(action.key)));
  const unresolvedActions = actions.filter(action => !resolutionByAction.has(action.key))
    .map(formatLaunchClearanceUnresolvedAction);
  const status = unresolvedActions.length === 0 ? "cleared" : "blocked";
  const sourceKey = buildPilotLaunchClearanceSourceKey(plan.id, status, resolvedActions);
  const existing = db.prepare("SELECT * FROM pilot_launch_clearance_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) return { ok: true, idempotent: true, packet: formatPilotLaunchClearancePacket(existing, true) };

  const now = new Date().toISOString();
  const totalActionCount = actions.length;
  const completionPercent = totalActionCount ? Math.round((resolvedActions.length / totalActionCount) * 100) : 100;
  const note = String(body.note || "").trim().slice(0, 500);
  const payload = {
    kind: "armosphera-one-pilot-launch-clearance",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    remediationPlanId: plan.id,
    launchReadinessId: plan.launchReadinessId,
    targetLaunchDate: plan.targetLaunchDate,
    generatedAt: now,
    customer: {
      id: plan.customerId,
      name: plan.customerName
    },
    goLiveAllowed: status === "cleared",
    clearanceDecision: status === "cleared" ? "ready-for-paid-pilot" : "blocked-remediation-open",
    summary: {
      totalActionCount,
      resolvedActionCount: resolvedActions.length,
      unresolvedActionCount: unresolvedActions.length,
      completionPercent,
      highPriorityOpenCount: unresolvedActions.filter(action => action.priority === "high").length,
      moneyAtRisk: plan.moneyAtRisk || plan.payload.summary?.moneyAtRisk || 0,
      currency: activeCurrencyCode()
    },
    resolvedActions,
    unresolvedActions,
    controls: [
      "all-remediation-actions-resolved-with-checksums",
      "owner-admin-clearance-only",
      "auditor-metadata-visibility",
      "tenant-backup-restore-scoped"
    ],
    checklist: clinicWellnessLaunchClearanceChecklist(status),
    note
  };
  const checksum = sha256Json(payload);
  const packetId = randomId("pilot-launch-clearance");
  db.prepare(`
    INSERT INTO pilot_launch_clearance_packets (
      id, org_id, template_key, remediation_plan_id, launch_readiness_id, customer_id,
      target_launch_date, status, source_key, resolved_action_count, unresolved_action_count,
      checksum, payload, note, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    packetId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    plan.id,
    plan.launchReadinessId,
    plan.customerId,
    plan.targetLaunchDate,
    status,
    sourceKey,
    resolvedActions.length,
    unresolvedActions.length,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.launch_clearance.created",
    subjectType: "pilot_launch_clearance_packet",
    subjectId: packetId,
    customerId: plan.customerId,
    status,
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      remediationPlanId: plan.id,
      launchReadinessId: plan.launchReadinessId,
      resolvedActionCount: resolvedActions.length,
      unresolvedActionCount: unresolvedActions.length,
      goLiveAllowed: payload.goLiveAllowed
    }
  });
  audit(db, user.org_id, user.id, "pilot.launch_clearance.created", {
    packetId,
    remediationPlanId: plan.id,
    launchReadinessId: plan.launchReadinessId,
    status,
    goLiveAllowed: payload.goLiveAllowed,
    resolvedActionCount: resolvedActions.length,
    unresolvedActionCount: unresolvedActions.length,
    checksum
  });
  return { ok: true, idempotent: false, packet: getPilotLaunchClearancePacket(db, user.org_id, packetId, true) };
}

function resolvePilotLaunchRemediationForClearance(db, orgId, remediationPlanId) {
  if (remediationPlanId) return getPilotLaunchRemediationPlan(db, orgId, String(remediationPlanId).trim(), true);
  const row = db.prepare(`
    SELECT id
    FROM pilot_launch_remediation_plans
    WHERE org_id = ? AND template_key = ?
    ORDER BY target_launch_date DESC, created_at DESC
    LIMIT 1
  `).get(orgId, CLINIC_WELLNESS_TEMPLATE_KEY);
  return row ? getPilotLaunchRemediationPlan(db, orgId, row.id, true) : null;
}

function buildPilotLaunchClearanceSourceKey(planId, status, resolvedActions) {
  const resolutionChain = resolvedActions
    .map(action => `${action.key}:${action.resolutionChecksum}`)
    .sort();
  return `launch-clearance:${planId}:${status}:${sha256Json(resolutionChain)}`;
}

function formatLaunchClearanceResolvedAction(action, resolution) {
  return {
    key: action.key,
    title: action.title,
    ownerRole: action.ownerRole,
    sourceGate: action.sourceGate,
    priority: action.priority,
    status: "resolved",
    evidenceType: resolution.evidenceType,
    resolutionId: resolution.id,
    resolutionChecksum: resolution.checksum,
    resolvedAt: resolution.resolvedAt,
    resolvedByName: resolution.resolvedByName,
    moneyAtRisk: action.moneyAtRisk || 0
  };
}

function formatLaunchClearanceUnresolvedAction(action) {
  return {
    key: action.key,
    title: action.title,
    ownerRole: action.ownerRole,
    sourceGate: action.sourceGate,
    priority: action.priority,
    status: action.status || "open",
    dueDate: action.dueDate,
    nextStep: action.nextStep,
    moneyAtRisk: action.moneyAtRisk || 0
  };
}

function clinicWellnessLaunchClearanceChecklist(status) {
  const base = [
    "Keep every remediation resolution attached to the pilot record.",
    "Archive the clearance packet before offering the paid pilot.",
    "Re-run clearance if any action is reopened or a new blocker appears."
  ];
  if (status === "cleared") return ["Proceed to owner-approved paid pilot offer.", ...base];
  return ["Resolve every open remediation action before go-live.", ...base];
}

function getPilotLaunchClearancePackets(db, orgId, templateKey, remediationPlanId = "") {
  const filters = ["pilot_launch_clearance_packets.org_id = ?", "pilot_launch_clearance_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedPlanId = String(remediationPlanId || "").trim();
  if (requestedPlanId) {
    filters.push("pilot_launch_clearance_packets.remediation_plan_id = ?");
    params.push(requestedPlanId);
  }
  return db.prepare(`
    SELECT pilot_launch_clearance_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_launch_clearance_packets
    JOIN customers ON customers.id = pilot_launch_clearance_packets.customer_id
    LEFT JOIN users ON users.id = pilot_launch_clearance_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_launch_clearance_packets.target_launch_date DESC, pilot_launch_clearance_packets.created_at DESC
  `).all(...params).map(row => formatPilotLaunchClearancePacket(row, false));
}

