function createClinicWellnessOfferQuoteHandoff(db, user, offerIdParam, body) {
  const offerId = String(offerIdParam || "").trim();
  const offer = offerId ? getPilotPaidOfferPacket(db, user.org_id, offerId, true) : null;
  if (!offer) {
    const err = new Error("Pilot paid offer not found");
    err.statusCode = 404;
    throw err;
  }
  if (offer.status !== "ready-for-customer") {
    const err = new Error("Pilot paid offer must be ready before quote handoff");
    err.statusCode = 409;
    throw err;
  }
  const sourceKey = `offer-quote-handoff:${offer.id}`;
  const existing = db.prepare("SELECT * FROM pilot_offer_quote_handoff_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) {
    return {
      ok: true,
      idempotent: true,
      handoff: formatPilotOfferQuoteHandoffPacket(existing, true),
      quote: getQuote(db, user.org_id, existing.quote_id),
      approval: getWorkflowApproval(db, user.org_id, existing.approval_id)
    };
  }

  const deal = resolvePilotOfferQuoteDeal(db, user.org_id, offer.customerId, body.dealId);
  if (!deal) {
    const err = new Error("Deal is required for paid offer quote handoff");
    err.statusCode = 422;
    throw err;
  }
  const approvalNote = normalizeCrmQuoteReleaseApprovalNoteForHandoff(body, "Release the paid pilot quote after owner review.");
  const validUntil = normalizeIsoDate(body.validUntil || offer.validUntil, "validUntil");
  const quote = createCrmQuote(db, user, {
    customerId: offer.customerId,
    dealId: deal.id,
    title: "Armosphera One clinic/wellness paid pilot",
    validUntil,
    lines: buildPilotOfferQuoteLines(offer)
  });
  const approvalResult = requestQuoteReleaseApproval(db, user, quote.id, { note: approvalNote });
  const approval = approvalResult.approval;
  const now = new Date().toISOString();
  const note = String(body.note || "").trim().slice(0, 500);
  const payload = {
    kind: "armosphera-one-pilot-offer-quote-handoff",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    generatedAt: now,
    offer: {
      id: offer.id,
      checksum: offer.checksum,
      validUntil: offer.validUntil,
      status: offer.status
    },
    customer: {
      id: offer.customerId,
      name: offer.customerName
    },
    deal: {
      id: deal.id,
      title: deal.title,
      stage: deal.stage
    },
    quote: {
      id: quote.id,
      number: quote.number,
      status: quote.status,
      total: quote.total,
      subtotal: quote.subtotal,
      vat: quote.vat,
      validUntil: quote.validUntil,
      lineCount: quote.lines.length
    },
    approval: {
      id: approval.id,
      actionKey: approval.actionKey,
      status: approval.status
    },
    commercial: offer.payload.commercial || {
      firstMonthTotal: offer.firstMonthTotal,
      setupFee: offer.setupFee,
      monthlyOpsFee: offer.monthlyOpsFee,
      currency: offer.currency
    },
    controls: [
      "crm-quote-release-approval-required",
      "public-quote-hidden-until-approved",
      "accepted-quote-hayhashvapah-invoice-handoff",
      "pilot-paid-offer-checksum-linked"
    ],
    note
  };
  const checksum = sha256Json(payload);
  const handoffId = randomId("pilot-offer-quote-handoff");
  db.prepare(`
    INSERT INTO pilot_offer_quote_handoff_packets (
      id, org_id, template_key, offer_id, clearance_packet_id, customer_id,
      deal_id, quote_id, approval_id, status, source_key, first_month_total,
      checksum, payload, note, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    handoffId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    offer.id,
    offer.clearancePacketId,
    offer.customerId,
    deal.id,
    quote.id,
    approval.id,
    "quote-release-pending",
    sourceKey,
    quote.total,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.offer_quote_handoff.created",
    subjectType: "pilot_offer_quote_handoff_packet",
    subjectId: handoffId,
    customerId: offer.customerId,
    status: "quote-release-pending",
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      offerId: offer.id,
      quoteId: quote.id,
      approvalId: approval.id,
      total: quote.total
    }
  });
  audit(db, user.org_id, user.id, "pilot.offer_quote_handoff.created", {
    handoffId,
    offerId: offer.id,
    quoteId: quote.id,
    approvalId: approval.id,
    firstMonthTotal: quote.total,
    checksum
  });
  return {
    ok: true,
    idempotent: false,
    handoff: getPilotOfferQuoteHandoffPacket(db, user.org_id, handoffId, true),
    quote,
    approval
  };
}

function resolvePilotOfferQuoteDeal(db, orgId, customerId, requestedDealId = "") {
  const dealId = String(requestedDealId || "").trim();
  if (dealId) {
    const deal = getDeal(db, orgId, dealId);
    return deal?.customerId === customerId ? deal : null;
  }
  const row = db.prepare(`
    SELECT id
    FROM deals
    WHERE org_id = ? AND customer_id = ?
    ORDER BY CASE stage WHEN 'Proposal' THEN 1 WHEN 'Negotiation' THEN 2 WHEN 'Discovery' THEN 3 ELSE 4 END, id
    LIMIT 1
  `).get(orgId, customerId);
  return row ? getDeal(db, orgId, row.id) : null;
}

function buildPilotOfferQuoteLines(offer) {
  const commercial = offer.payload.commercial || {};
  const vatMultiplier = 1 + Number(commercial.vatRate || 0.2);
  const setupFee = Math.round(Number(commercial.setupFee || offer.setupFee || 0));
  const monthlyOpsFee = Math.round(Number(commercial.monthlyOpsFee || offer.monthlyOpsFee || 0));
  return [
    {
      description: "Armosphera One clinic/wellness paid pilot setup",
      quantity: 1,
      unitPrice: Math.round(setupFee * vatMultiplier)
    },
    {
      description: "Armosphera One monthly operations and HayHashvapah handoff",
      quantity: 1,
      unitPrice: Math.round(monthlyOpsFee * vatMultiplier)
    }
  ];
}

