function createClinicWellnessQuoteAcceptanceHandoff(db, user, releaseIdParam, body) {
  const releaseId = String(releaseIdParam || "").trim();
  const release = releaseId ? getPilotQuoteReleasePacket(db, user.org_id, releaseId, true) : null;
  if (!release) {
    const err = new Error("Pilot quote release packet not found");
    err.statusCode = 404;
    throw err;
  }
  const quote = getQuote(db, user.org_id, release.quoteId);
  const acceptance = quote ? getQuoteAcceptanceByQuote(db, user.org_id, quote.id) : null;
  if (!quote || quote.status !== "accepted" || !acceptance) {
    const err = new Error("Pilot quote must be accepted before HayHashvapah handoff");
    err.statusCode = 409;
    throw err;
  }
  const financeApproval = getQuoteFinanceApproval(db, user.org_id, quote.id);
  if (!financeApproval) {
    const err = new Error("HayHashvapah invoice approval not found for accepted quote");
    err.statusCode = 409;
    throw err;
  }

  const sourceKey = `quote-acceptance-handoff:${release.id}:${acceptance.id}:${financeApproval.id}`;
  const existing = db.prepare("SELECT * FROM pilot_quote_acceptance_handoff_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) {
    return {
      ok: true,
      idempotent: true,
      packet: formatPilotQuoteAcceptanceHandoffPacket(existing, true)
    };
  }

  const deal = getDeal(db, user.org_id, release.dealId);
  const now = new Date().toISOString();
  const note = String(body.note || "").trim().slice(0, 500);
  const status = financeApproval.status === "executed" ? "draft-invoice-created" : "invoice-approval-pending";
  const periodKey = financeApproval.payload?.periodKey || "";
  const vatMode = financeApproval.payload?.vatMode || "amd-inclusive-20";
  const dueDays = financeApproval.payload?.dueDays || 14;
  const payload = {
    kind: "armosphera-one-pilot-quote-acceptance-hayhashvapah-handoff",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    generatedAt: now,
    release: {
      id: release.id,
      checksum: release.checksum,
      status: release.status
    },
    handoff: {
      id: release.quoteHandoffId,
      offerId: release.offerId
    },
    customer: {
      id: release.customerId,
      name: release.customerName || acceptance.customerName || ""
    },
    deal: {
      id: release.dealId,
      title: deal?.title || "",
      stage: deal?.stage || ""
    },
    quote: {
      id: quote.id,
      number: quote.number,
      status: quote.status,
      total: quote.total,
      subtotal: quote.subtotal,
      vat: quote.vat,
      currency: quote.currency,
      acceptedAt: quote.acceptedAt
    },
    acceptance: {
      id: acceptance.id,
      signerName: acceptance.signerName,
      signerEmail: acceptance.signerEmail,
      acceptedAt: acceptance.acceptedAt
    },
    financeApproval: {
      id: financeApproval.id,
      actionKey: financeApproval.actionKey,
      status: financeApproval.status,
      periodKey,
      dueDays,
      vatMode
    },
    hayhashvapah: {
      ledger: "HayHashvapah Finance",
      handoff: "accepted quote to draft invoice approval",
      periodKey,
      vatMode,
      dueDays,
      ownerApprovalRequired: financeApproval.status !== "executed"
    },
    controls: [
      "public-quote-accepted-before-invoice-handoff",
      "owner-approval-required-before-hayhashvapah-draft",
      "armenian-vat-mode-amd-inclusive-20",
      "quote-release-checksum-linked",
      "accepted-quote-deal-won"
    ],
    note
  };
  const checksum = sha256Json(payload);
  const packetId = randomId("pilot-quote-acceptance-handoff");
  db.prepare(`
    INSERT INTO pilot_quote_acceptance_handoff_packets (
      id, org_id, template_key, quote_release_packet_id, quote_handoff_id, offer_id,
      customer_id, deal_id, quote_id, acceptance_id, finance_approval_id, status,
      source_key, signer_name, signer_email, accepted_at, period_key, vat_mode,
      total, checksum, payload, note, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    packetId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    release.id,
    release.quoteHandoffId,
    release.offerId,
    release.customerId,
    release.dealId,
    quote.id,
    acceptance.id,
    financeApproval.id,
    status,
    sourceKey,
    acceptance.signerName,
    acceptance.signerEmail,
    acceptance.acceptedAt,
    periodKey,
    vatMode,
    quote.total,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.quote_acceptance_handoff.created",
    subjectType: "pilot_quote_acceptance_handoff_packet",
    subjectId: packetId,
    customerId: release.customerId,
    status,
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      releasePacketId: release.id,
      quoteId: quote.id,
      acceptanceId: acceptance.id,
      financeApprovalId: financeApproval.id,
      total: quote.total
    }
  });
  audit(db, user.org_id, user.id, "pilot.quote_acceptance_handoff.created", {
    packetId,
    releasePacketId: release.id,
    handoffId: release.quoteHandoffId,
    quoteId: quote.id,
    acceptanceId: acceptance.id,
    financeApprovalId: financeApproval.id,
    total: quote.total,
    checksum
  });
  return {
    ok: true,
    idempotent: false,
    packet: getPilotQuoteAcceptanceHandoffPacket(db, user.org_id, packetId, true)
  };
}

