function createClinicWellnessHayhashvapahPaymentCollectionPacket(db, user, postingPacketIdParam, body) {
  const postingPacketId = String(postingPacketIdParam || "").trim();
  const postingPacket = postingPacketId ? getPilotHayhashvapahInvoicePostingPacket(db, user.org_id, postingPacketId, true) : null;
  if (!postingPacket) {
    const err = new Error("Pilot official HayHashvapah invoice posting packet not found");
    err.statusCode = 404;
    throw err;
  }
  const invoice = getInvoice(db, user.org_id, postingPacket.invoiceId);
  const payment = getLatestFinancePaymentForInvoice(db, user.org_id, postingPacket.invoiceId);
  const paidTotal = getInvoicePaymentTotal(db, user.org_id, postingPacket.invoiceId);
  if (!invoice || !payment || invoice.status !== "paid" || paidTotal < invoice.total) {
    const err = new Error("HayHashvapah payment receipt must fully pay the official invoice before packet creation");
    err.statusCode = 409;
    throw err;
  }

  const sourceKey = `hayhashvapah-payment:${postingPacket.id}:${payment.id}:${invoice.id}`;
  const existing = db.prepare("SELECT * FROM pilot_hayhashvapah_payment_collection_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) {
    return {
      ok: true,
      idempotent: true,
      packet: formatPilotHayhashvapahPaymentCollectionPacket(existing, true)
    };
  }

  const note = String(body.note || "").trim().slice(0, 500);
  const now = new Date().toISOString();
  const vatMode = postingPacket.vatMode || postingPacket.payload?.hayhashvapah?.vatMode || "amd-inclusive-20";
  const payload = {
    kind: "armosphera-one-pilot-hayhashvapah-payment-collection",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    generatedAt: now,
    postingPacket: {
      id: postingPacket.id,
      checksum: postingPacket.checksum,
      status: postingPacket.status
    },
    draftPacket: {
      id: postingPacket.draftPacketId
    },
    customer: {
      id: postingPacket.customerId,
      name: postingPacket.customerName || invoice.customerName || ""
    },
    quote: {
      id: postingPacket.quoteId
    },
    acceptance: {
      id: postingPacket.acceptanceId
    },
    invoice: {
      id: invoice.id,
      number: invoice.number,
      status: invoice.status,
      total: invoice.total,
      vat: invoice.vat,
      dueDate: invoice.dueDate
    },
    payment: {
      id: payment.id,
      reference: payment.reference,
      amount: payment.amount,
      paidAt: payment.paidAt,
      method: payment.method,
      periodKey: payment.periodKey
    },
    hayhashvapah: {
      ledger: "HayHashvapah Finance",
      status: "payment-collected",
      periodKey: payment.periodKey,
      vatMode,
      receivableState: invoice.status,
      paidTotal
    },
    controls: [
      "hayhashvapah-payment-receipt-linked",
      "official-invoice-fully-paid",
      "crm-receivables-cleared",
      "customer-360-payment-timeline-linked",
      "ready-for-pilot-closeout"
    ],
    note
  };
  const checksum = sha256Json(payload);
  const packetId = randomId("pilot-hayhashvapah-payment");
  db.prepare(`
    INSERT INTO pilot_hayhashvapah_payment_collection_packets (
      id, org_id, template_key, posting_packet_id, draft_packet_id,
      acceptance_handoff_id, quote_release_packet_id, quote_handoff_id, offer_id,
      customer_id, deal_id, quote_id, acceptance_id, draft_invoice_id,
      invoice_id, invoice_link_id, payment_id, status, source_key,
      invoice_number, payment_reference, paid_at, period_key, vat_mode,
      subtotal, vat, amount, checksum, payload, note, created_by_user_id,
      created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    packetId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    postingPacket.id,
    postingPacket.draftPacketId,
    postingPacket.acceptanceHandoffId,
    postingPacket.quoteReleasePacketId,
    postingPacket.quoteHandoffId,
    postingPacket.offerId,
    postingPacket.customerId,
    postingPacket.dealId,
    postingPacket.quoteId,
    postingPacket.acceptanceId,
    postingPacket.draftInvoiceId,
    invoice.id,
    postingPacket.invoiceLinkId,
    payment.id,
    "payment-collected",
    sourceKey,
    invoice.number,
    payment.reference,
    payment.paidAt,
    payment.periodKey,
    vatMode,
    postingPacket.subtotal,
    invoice.vat,
    payment.amount,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.hayhashvapah_payment_collection.created",
    subjectType: "pilot_hayhashvapah_payment_collection_packet",
    subjectId: packetId,
    customerId: postingPacket.customerId,
    status: "payment-collected",
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      postingPacketId: postingPacket.id,
      invoiceId: invoice.id,
      paymentId: payment.id,
      amount: payment.amount,
      periodKey: payment.periodKey
    }
  });
  audit(db, user.org_id, user.id, "pilot.hayhashvapah_payment_collection.created", {
    packetId,
    postingPacketId: postingPacket.id,
    invoiceId: invoice.id,
    paymentId: payment.id,
    amount: payment.amount,
    checksum
  });
  return {
    ok: true,
    idempotent: false,
    packet: getPilotHayhashvapahPaymentCollectionPacket(db, user.org_id, packetId, true)
  };
}

