function createClinicWellnessPilotCloseoutPacket(db, user, paymentCollectionPacketIdParam, body) {
  const paymentCollectionPacketId = String(paymentCollectionPacketIdParam || "").trim();
  const paymentCollection = paymentCollectionPacketId
    ? getPilotHayhashvapahPaymentCollectionPacket(db, user.org_id, paymentCollectionPacketId, true)
    : null;
  if (!paymentCollection) {
    const err = new Error("Pilot HayHashvapah payment collection packet not found");
    err.statusCode = 404;
    throw err;
  }

  const sourceKey = `pilot-closeout:${paymentCollection.id}`;
  const existing = db.prepare("SELECT * FROM pilot_closeout_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) {
    return {
      ok: true,
      idempotent: true,
      packet: formatPilotCloseoutPacket(existing, true),
      renewalTask: getCrmTask(db, user.org_id, existing.renewal_task_id)
    };
  }

  const invoice = getInvoice(db, user.org_id, paymentCollection.invoiceId);
  const payment = getFinancePayment(db, user.org_id, paymentCollection.paymentId);
  if (!invoice || invoice.status !== "paid" || !payment) {
    const err = new Error("Paid invoice and HayHashvapah receipt are required before pilot closeout");
    err.statusCode = 409;
    throw err;
  }

  const note = String(body.note || "").trim().slice(0, 500);
  const closeoutDate = normalizeIsoDate(body.closeoutDate || payment.paidAt || armeniaDateString(), "closeoutDate");
  const renewalDueDate = normalizeIsoDate(body.renewalDueDate || addDays(closeoutDate, 14), "renewalDueDate");
  const now = new Date().toISOString();
  const customer = getCustomerSummary(db, user.org_id, paymentCollection.customerId);
  const salesOwner = db.prepare(`
    SELECT id FROM users
    WHERE org_id = ? AND role = 'Salesperson'
    ORDER BY created_at ASC
    LIMIT 1
  `).get(user.org_id);
  const renewalSourceKey = `pilot-closeout-renewal:${paymentCollection.id}`;
  let renewalTask = getCrmTaskBySource(db, user.org_id, renewalSourceKey);
  if (!renewalTask) {
    const renewalTaskId = randomId("task");
    db.prepare(`
      INSERT INTO crm_tasks (
        id, org_id, customer_id, deal_id, invoice_id, title, description,
        status, priority, source_key, owner_user_id, due_date, created_at, updated_at
      )
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).run(
      renewalTaskId,
      user.org_id,
      paymentCollection.customerId,
      paymentCollection.dealId,
      null,
      `Renew paid pilot for ${customer?.name || "clinic customer"}`,
      `First paid pilot is closed after ${payment.reference}. Prepare renewal or monthly operations proposal before ${renewalDueDate}.`,
      "open",
      "medium",
      renewalSourceKey,
      salesOwner?.id || user.id,
      renewalDueDate,
      now,
      now
    );
    renewalTask = getCrmTask(db, user.org_id, renewalTaskId);
  }

  const payload = {
    kind: "armosphera-one-pilot-closeout-renewal-handoff",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    generatedAt: now,
    closeout: {
      status: "closed-won-pilot",
      closeoutDate,
      nextStage: "renewal-handoff"
    },
    paymentCollection: {
      id: paymentCollection.id,
      checksum: paymentCollection.checksum,
      status: paymentCollection.status
    },
    customer: {
      id: paymentCollection.customerId,
      name: paymentCollection.customerName || customer?.name || ""
    },
    quote: {
      id: paymentCollection.quoteId
    },
    acceptance: {
      id: paymentCollection.acceptanceId
    },
    invoice: {
      id: invoice.id,
      number: invoice.number,
      status: invoice.status,
      total: invoice.total,
      vat: invoice.vat
    },
    payment: {
      id: payment.id,
      reference: payment.reference,
      amount: payment.amount,
      paidAt: payment.paidAt,
      method: payment.method,
      periodKey: payment.periodKey
    },
    renewalTask: {
      id: renewalTask.id,
      title: renewalTask.title,
      dueDate: renewalTask.dueDate,
      ownerName: renewalTask.ownerName,
      sourceKey: renewalTask.sourceKey
    },
    controls: [
      "paid-pilot-closeout-after-collection",
      "crm-renewal-task-created",
      "customer-360-success-timeline-ready",
      "hayhashvapah-payment-evidence-linked",
      "owner-renewal-review-ready"
    ],
    note
  };
  const checksum = sha256Json(payload);
  const packetId = randomId("pilot-closeout");
  db.prepare(`
    INSERT INTO pilot_closeout_packets (
      id, org_id, template_key, payment_collection_packet_id, posting_packet_id,
      draft_packet_id, acceptance_handoff_id, quote_release_packet_id,
      quote_handoff_id, offer_id, customer_id, deal_id, quote_id, acceptance_id,
      draft_invoice_id, invoice_id, invoice_link_id, payment_id, renewal_task_id,
      status, source_key, invoice_number, payment_reference, closeout_date,
      renewal_due_date, period_key, amount, checksum, payload, note, created_by_user_id,
      created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    packetId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    paymentCollection.id,
    paymentCollection.postingPacketId,
    paymentCollection.draftPacketId,
    paymentCollection.acceptanceHandoffId,
    paymentCollection.quoteReleasePacketId,
    paymentCollection.quoteHandoffId,
    paymentCollection.offerId,
    paymentCollection.customerId,
    paymentCollection.dealId,
    paymentCollection.quoteId,
    paymentCollection.acceptanceId,
    paymentCollection.draftInvoiceId,
    invoice.id,
    paymentCollection.invoiceLinkId,
    payment.id,
    renewalTask.id,
    "closed-won-pilot",
    sourceKey,
    invoice.number,
    payment.reference,
    closeoutDate,
    renewalDueDate,
    payment.periodKey,
    payment.amount,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.closeout.created",
    subjectType: "pilot_closeout_packet",
    subjectId: packetId,
    customerId: paymentCollection.customerId,
    status: "closed-won-pilot",
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      paymentCollectionPacketId: paymentCollection.id,
      invoiceId: invoice.id,
      paymentId: payment.id,
      renewalTaskId: renewalTask.id,
      amount: payment.amount
    }
  });
  audit(db, user.org_id, user.id, "pilot.closeout.created", {
    packetId,
    paymentCollectionPacketId: paymentCollection.id,
    invoiceId: invoice.id,
    paymentId: payment.id,
    renewalTaskId: renewalTask.id,
    checksum
  });
  return {
    ok: true,
    idempotent: false,
    packet: getPilotCloseoutPacket(db, user.org_id, packetId, true),
    renewalTask
  };
}

