function createClinicWellnessRenewalQuoteHandoff(db, user, closeoutPacketIdParam, body) {
  const closeoutPacketId = String(closeoutPacketIdParam || "").trim();
  const closeout = closeoutPacketId ? getPilotCloseoutPacket(db, user.org_id, closeoutPacketId, true) : null;
  if (!closeout) {
    const err = new Error("Pilot closeout packet not found");
    err.statusCode = 404;
    throw err;
  }
  if (closeout.status !== "closed-won-pilot") {
    const err = new Error("Pilot closeout must be closed-won before renewal quote handoff");
    err.statusCode = 409;
    throw err;
  }

  const sourceKey = `pilot-renewal-quote:${closeout.id}`;
  const existing = db.prepare("SELECT id FROM pilot_renewal_quote_handoff_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) {
    const handoff = getPilotRenewalQuoteHandoffPacket(db, user.org_id, existing.id, true);
    return {
      ok: true,
      idempotent: true,
      handoff,
      quote: getQuote(db, user.org_id, handoff.quoteId),
      approval: getWorkflowApproval(db, user.org_id, handoff.approvalId)
    };
  }

  const renewalTask = getCrmTask(db, user.org_id, closeout.renewalTaskId);
  if (!renewalTask) {
    const err = new Error("CRM renewal task is required before renewal quote handoff");
    err.statusCode = 409;
    throw err;
  }
  const deal = getDeal(db, user.org_id, closeout.dealId);
  if (!deal || deal.customerId !== closeout.customerId) {
    const err = new Error("Deal is required for renewal quote handoff");
    err.statusCode = 422;
    throw err;
  }

  const approvalNote = normalizeCrmQuoteReleaseApprovalNoteForHandoff(body, "Release the monthly renewal quote after owner review.");
  const validUntil = normalizeIsoDate(
    body.validUntil || closeout.renewalDueDate || addDays(closeout.closeoutDate || armeniaDateString(), 14),
    "validUntil"
  );
  const quote = createCrmQuote(db, user, {
    customerId: closeout.customerId,
    dealId: deal.id,
    title: "Armosphera One clinic/wellness monthly renewal",
    validUntil,
    lines: buildPilotRenewalQuoteLines(db, user.org_id, closeout)
  });
  const approvalResult = requestQuoteReleaseApproval(db, user, quote.id, { note: approvalNote });
  const approval = approvalResult.approval;
  const now = new Date().toISOString();
  const note = String(body.note || "").trim().slice(0, 500);
  const payload = {
    kind: "armosphera-one-pilot-renewal-quote-handoff",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    generatedAt: now,
    closeout: {
      id: closeout.id,
      checksum: closeout.checksum,
      status: closeout.status,
      closeoutDate: closeout.closeoutDate,
      renewalDueDate: closeout.renewalDueDate
    },
    paymentCollection: {
      id: closeout.paymentCollectionPacketId,
      status: closeout.payload?.paymentCollection?.status || "collected"
    },
    customer: {
      id: closeout.customerId,
      name: closeout.customerName
    },
    deal: {
      id: deal.id,
      title: deal.title,
      stage: deal.stage
    },
    renewalTask: {
      id: renewalTask.id,
      title: renewalTask.title,
      dueDate: renewalTask.dueDate,
      ownerName: renewalTask.ownerName,
      sourceKey: renewalTask.sourceKey
    },
    quote: {
      id: quote.id,
      number: quote.number,
      status: quote.status,
      total: quote.total,
      subtotal: quote.subtotal,
      vat: quote.vat,
      validUntil: quote.validUntil,
      lineCount: quote.lines.length
    },
    approval: {
      id: approval.id,
      actionKey: approval.actionKey,
      status: approval.status
    },
    commercial: {
      monthlyTotal: quote.total,
      subtotal: quote.subtotal,
      vat: quote.vat,
      currency: quote.currency,
      vatRate: 0.2
    },
    controls: [
      "renewal-quote-release-approval-required",
      "public-renewal-quote-hidden-until-approved",
      "paid-pilot-closeout-checksum-linked",
      "crm-renewal-task-linked",
      "monthly-operations-renewal-priced"
    ],
    note
  };
  const checksum = sha256Json(payload);
  const handoffId = randomId("pilot-renewal-quote-handoff");
  db.prepare(`
    INSERT INTO pilot_renewal_quote_handoff_packets (
      id, org_id, template_key, closeout_packet_id, payment_collection_packet_id,
      posting_packet_id, renewal_task_id, customer_id, deal_id, quote_id,
      approval_id, status, source_key, monthly_total, subtotal, vat, valid_until,
      checksum, payload, note, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    handoffId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    closeout.id,
    closeout.paymentCollectionPacketId,
    closeout.postingPacketId,
    renewalTask.id,
    closeout.customerId,
    deal.id,
    quote.id,
    approval.id,
    "renewal-quote-release-pending",
    sourceKey,
    quote.total,
    quote.subtotal,
    quote.vat,
    validUntil,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.renewal_quote_handoff.created",
    subjectType: "pilot_renewal_quote_handoff_packet",
    subjectId: handoffId,
    customerId: closeout.customerId,
    status: "renewal-quote-release-pending",
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      closeoutPacketId: closeout.id,
      renewalTaskId: renewalTask.id,
      quoteId: quote.id,
      approvalId: approval.id,
      monthlyTotal: quote.total
    }
  });
  audit(db, user.org_id, user.id, "pilot.renewal_quote_handoff.created", {
    handoffId,
    closeoutPacketId: closeout.id,
    renewalTaskId: renewalTask.id,
    quoteId: quote.id,
    approvalId: approval.id,
    monthlyTotal: quote.total,
    checksum
  });
  return {
    ok: true,
    idempotent: false,
    handoff: getPilotRenewalQuoteHandoffPacket(db, user.org_id, handoffId, true),
    quote,
    approval
  };
}

function buildPilotRenewalQuoteLines(db, orgId, closeout) {
  const offer = closeout.offerId ? getPilotPaidOfferPacket(db, orgId, closeout.offerId, true) : null;
  const commercial = offer?.payload?.commercial || {};
  const monthlyOpsFee = Math.max(800000, Math.round(Number(commercial.monthlyOpsFee || offer?.monthlyOpsFee || 0)));
  const vatMultiplier = 1 + Number(commercial.vatRate || 0.2);
  return [{
    description: "Armosphera One monthly renewal operations and HayHashvapah accounting handoff",
    quantity: 1,
    unitPrice: Math.round(monthlyOpsFee * vatMultiplier)
  }];
}

