function createClinicWellnessRenewalQuoteReleasePacket(db, user, handoffIdParam, body) {
  const handoffId = String(handoffIdParam || "").trim();
  const handoff = handoffId ? getPilotRenewalQuoteHandoffPacket(db, user.org_id, handoffId, true) : null;
  if (!handoff) {
    const err = new Error("Pilot renewal quote handoff not found");
    err.statusCode = 404;
    throw err;
  }
  const quote = getQuote(db, user.org_id, handoff.quoteId);
  const approval = getWorkflowApproval(db, user.org_id, handoff.approvalId);
  const publicQuote = quote?.publicToken ? getPublicQuote(db, quote.publicToken) : null;
  if (!quote || !approval || approval.status !== "executed" || !["sent", "viewed", "accepted"].includes(quote.status) || !publicQuote) {
    const err = new Error("Pilot renewal quote release must be owner-approved and publicly available");
    err.statusCode = 409;
    throw err;
  }

  const sourceKey = `renewal-quote-release:${handoff.id}:${quote.id}:${quote.sentAt || quote.updatedAt}`;
  const existing = db.prepare("SELECT id FROM pilot_renewal_quote_release_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) {
    return {
      ok: true,
      idempotent: true,
      packet: getPilotRenewalQuoteReleasePacket(db, user.org_id, existing.id, true)
    };
  }

  const closeout = getPilotCloseoutPacket(db, user.org_id, handoff.closeoutPacketId, true);
  const renewalTask = getCrmTask(db, user.org_id, handoff.renewalTaskId);
  const deal = getDeal(db, user.org_id, handoff.dealId);
  const now = new Date().toISOString();
  const note = String(body.note || "").trim().slice(0, 500);
  const publicUrl = quote.acceptanceUrl || `/api/public/quotes/${quote.publicToken}`;
  const payload = {
    kind: "armosphera-one-pilot-renewal-quote-release",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    generatedAt: now,
    handoff: {
      id: handoff.id,
      checksum: handoff.checksum,
      status: handoff.status
    },
    closeout: {
      id: handoff.closeoutPacketId,
      checksum: closeout?.checksum || handoff.payload?.closeout?.checksum || "",
      status: closeout?.status || handoff.payload?.closeout?.status || ""
    },
    paymentCollection: {
      id: handoff.paymentCollectionPacketId
    },
    renewalTask: {
      id: renewalTask?.id || handoff.renewalTaskId,
      title: renewalTask?.title || handoff.payload?.renewalTask?.title || "",
      dueDate: renewalTask?.dueDate || handoff.payload?.renewalTask?.dueDate || "",
      ownerName: renewalTask?.ownerName || handoff.payload?.renewalTask?.ownerName || ""
    },
    customer: {
      id: handoff.customerId,
      name: handoff.customerName || publicQuote.customer?.name || ""
    },
    deal: {
      id: handoff.dealId,
      title: deal?.title || publicQuote.deal?.title || "",
      stage: deal?.stage || publicQuote.deal?.stage || ""
    },
    quote: {
      id: quote.id,
      number: quote.number,
      status: quote.status,
      total: quote.total,
      subtotal: quote.subtotal,
      vat: quote.vat,
      currency: quote.currency,
      publicToken: quote.publicToken,
      acceptanceUrl: publicUrl,
      sentAt: quote.sentAt,
      lineCount: quote.lines.length
    },
    approval: {
      id: approval.id,
      actionKey: approval.actionKey,
      status: approval.status
    },
    publicAvailability: true,
    controls: [
      "owner-approved-renewal-quote-release",
      "public-renewal-quote-visible-after-workflow-execution",
      "accepted-renewal-quote-drives-hayhashvapah-invoice-handoff",
      "renewal-quote-handoff-checksum-linked",
      "paid-pilot-closeout-checksum-linked"
    ],
    note
  };
  const checksum = sha256Json(payload);
  const packetId = randomId("pilot-renewal-quote-release");
  db.prepare(`
    INSERT INTO pilot_renewal_quote_release_packets (
      id, org_id, template_key, renewal_quote_handoff_id, closeout_packet_id,
      payment_collection_packet_id, posting_packet_id, renewal_task_id, customer_id,
      deal_id, quote_id, approval_id, status, source_key, public_token, public_url,
      total, subtotal, vat, checksum, payload, note, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    packetId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    handoff.id,
    handoff.closeoutPacketId,
    handoff.paymentCollectionPacketId,
    handoff.postingPacketId,
    handoff.renewalTaskId,
    handoff.customerId,
    handoff.dealId,
    quote.id,
    approval.id,
    "released",
    sourceKey,
    quote.publicToken,
    publicUrl,
    quote.total,
    quote.subtotal,
    quote.vat,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.renewal_quote_release.created",
    subjectType: "pilot_renewal_quote_release_packet",
    subjectId: packetId,
    customerId: handoff.customerId,
    status: "released",
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      handoffId: handoff.id,
      closeoutPacketId: handoff.closeoutPacketId,
      quoteId: quote.id,
      approvalId: approval.id,
      total: quote.total
    }
  });
  audit(db, user.org_id, user.id, "pilot.renewal_quote_release.created", {
    packetId,
    handoffId: handoff.id,
    closeoutPacketId: handoff.closeoutPacketId,
    quoteId: quote.id,
    approvalId: approval.id,
    total: quote.total,
    checksum
  });
  return {
    ok: true,
    idempotent: false,
    packet: getPilotRenewalQuoteReleasePacket(db, user.org_id, packetId, true)
  };
}

