  const sourceKey = `renewal-hayhashvapah-posting:${draftPacket.id}:${link.id}:${invoice.id}`;
  const existing = db.prepare("SELECT id FROM pilot_renewal_hayhashvapah_invoice_posting_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
