function createClinicWellnessNextRenewalQuoteAcceptanceHandoff(db, user, releaseIdParam, body) {
  const releaseId = String(releaseIdParam || "").trim();
  const release = releaseId ? getPilotNextRenewalQuoteReleasePacket(db, user.org_id, releaseId, true) : null;
  if (!release) {
    const err = new Error("Pilot next renewal quote release packet not found");
    err.statusCode = 404;
    throw err;
  }
  const quote = getQuote(db, user.org_id, release.quoteId);
  const acceptance = quote ? getQuoteAcceptanceByQuote(db, user.org_id, quote.id) : null;
  if (!quote || quote.status !== "accepted" || !acceptance) {
    const err = new Error("Pilot next renewal quote must be accepted before HayHashvapah handoff");
    err.statusCode = 409;
    throw err;
  }
  const financeApproval = getQuoteFinanceApproval(db, user.org_id, quote.id);
  if (!financeApproval) {
    const err = new Error("HayHashvapah invoice approval not found for accepted next renewal quote");
    err.statusCode = 409;
    throw err;
  }

  const sourceKey = `next-renewal-quote-acceptance-handoff:${release.id}:${acceptance.id}:${financeApproval.id}`;
  const existing = db.prepare("SELECT id FROM pilot_next_renewal_quote_acceptance_handoff_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) {
    return {
      ok: true,
      idempotent: true,
      packet: getPilotNextRenewalQuoteAcceptanceHandoffPacket(db, user.org_id, existing.id, true)
    };
  }

  const handoff = getPilotNextRenewalQuoteHandoffPacket(db, user.org_id, release.nextRenewalQuoteHandoffId, true);
  const renewalCloseout = getPilotRenewalCloseoutPacket(db, user.org_id, release.renewalCloseoutPacketId, true);
  const renewalTask = getCrmTask(db, user.org_id, release.renewalTaskId);
  const nextRenewalTask = getCrmTask(db, user.org_id, release.nextRenewalTaskId);
  const deal = getDeal(db, user.org_id, release.dealId);
  const now = new Date().toISOString();
  const note = String(body.note || "").trim().slice(0, 500);
  const status = financeApproval.status === "executed" ? "next-renewal-draft-invoice-created" : "next-renewal-invoice-approval-pending";
  const periodKey = financeApproval.payload?.periodKey || "";
  const vatMode = financeApproval.payload?.vatMode || "amd-inclusive-20";
  const dueDays = financeApproval.payload?.dueDays || 14;
  const payload = {
    kind: "armosphera-one-pilot-next-renewal-quote-acceptance-hayhashvapah-handoff",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    generatedAt: now,
    release: {
      id: release.id,
      checksum: release.checksum,
      status: release.status
    },
    handoff: {
      id: release.nextRenewalQuoteHandoffId,
      checksum: handoff?.checksum || release.payload?.handoff?.checksum || "",
      status: handoff?.status || release.payload?.handoff?.status || ""
    },
    renewalCloseout: {
      id: release.renewalCloseoutPacketId,
      checksum: renewalCloseout?.checksum || release.payload?.renewalCloseout?.checksum || "",
      status: renewalCloseout?.status || release.payload?.renewalCloseout?.status || ""
    },
    previousRenewalRelease: {
      id: release.renewalQuoteReleasePacketId
    },
    renewalPaymentCollection: {
      id: release.renewalPaymentCollectionPacketId
    },
    priorCloseout: {
      id: release.closeoutPacketId
    },
    renewalTask: {
      id: renewalTask?.id || release.renewalTaskId,
      title: renewalTask?.title || "",
      dueDate: renewalTask?.dueDate || ""
    },
    nextRenewalTask: {
      id: nextRenewalTask?.id || release.nextRenewalTaskId,
      title: nextRenewalTask?.title || release.payload?.nextRenewalTask?.title || "",
      dueDate: nextRenewalTask?.dueDate || release.payload?.nextRenewalTask?.dueDate || "",
      ownerName: nextRenewalTask?.ownerName || release.payload?.nextRenewalTask?.ownerName || "",
      sourceKey: nextRenewalTask?.sourceKey || release.payload?.nextRenewalTask?.sourceKey || ""
    },
    customer: {
      id: release.customerId,
      name: release.customerName || acceptance.customerName || ""
    },
    deal: {
      id: release.dealId,
      title: deal?.title || release.payload?.deal?.title || "",
      stage: deal?.stage || release.payload?.deal?.stage || ""
    },
    quote: {
      id: quote.id,
      number: quote.number,
      status: quote.status,
      total: quote.total,
      subtotal: quote.subtotal,
      vat: quote.vat,
      currency: quote.currency,
      acceptedAt: quote.acceptedAt
    },
    acceptance: {
      id: acceptance.id,
      signerName: acceptance.signerName,
      signerEmail: acceptance.signerEmail,
      acceptedAt: acceptance.acceptedAt
    },
    financeApproval: {
      id: financeApproval.id,
      actionKey: financeApproval.actionKey,
      status: financeApproval.status,
      periodKey,
      dueDays,
      vatMode
    },
    hayhashvapah: {
      ledger: "HayHashvapah Finance",
      handoff: "next monthly renewal accepted quote to draft invoice approval",
      periodKey,
      vatMode,
      dueDays,
      ownerApprovalRequired: financeApproval.status !== "executed",
      billingMode: "next-monthly-renewal"
    },
    controls: [
      "public-next-renewal-quote-accepted-before-invoice-handoff",
      "owner-approval-required-before-next-renewal-hayhashvapah-draft",
      "armenian-vat-mode-amd-inclusive-20",
      "next-renewal-quote-release-checksum-linked",
      "next-renewal-quote-handoff-checksum-linked",
      "renewal-closeout-checksum-linked",
      "next-renewal-task-linked"
    ],
    note
  };
  const checksum = sha256Json(payload);
  const packetId = randomId("pilot-next-renewal-acceptance-handoff");
  db.prepare(`
    INSERT INTO pilot_next_renewal_quote_acceptance_handoff_packets (
      id, org_id, template_key, next_renewal_quote_release_packet_id,
      next_renewal_quote_handoff_id, renewal_closeout_packet_id,
      renewal_payment_collection_packet_id, renewal_posting_packet_id,
      renewal_draft_packet_id, renewal_acceptance_handoff_id,
      renewal_quote_release_packet_id, renewal_quote_handoff_id,
      closeout_packet_id, prior_payment_collection_packet_id,
      prior_posting_packet_id, renewal_task_id, next_renewal_task_id,
      customer_id, deal_id, quote_id, acceptance_id, finance_approval_id,
      status, source_key, signer_name, signer_email, accepted_at, period_key,
      vat_mode, total, subtotal, vat, checksum, payload, note,
      created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    packetId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    release.id,
    release.nextRenewalQuoteHandoffId,
    release.renewalCloseoutPacketId,
    release.renewalPaymentCollectionPacketId,
    release.renewalPostingPacketId,
    release.renewalDraftPacketId,
    release.renewalAcceptanceHandoffId,
    release.renewalQuoteReleasePacketId,
    release.renewalQuoteHandoffId,
    release.closeoutPacketId,
    release.priorPaymentCollectionPacketId,
    release.priorPostingPacketId,
    release.renewalTaskId,
    release.nextRenewalTaskId,
    release.customerId,
    release.dealId,
    quote.id,
    acceptance.id,
    financeApproval.id,
    status,
    sourceKey,
    acceptance.signerName,
    acceptance.signerEmail,
    acceptance.acceptedAt,
    periodKey,
    vatMode,
    quote.total,
    quote.subtotal,
    quote.vat,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.next_renewal_quote_acceptance_handoff.created",
    subjectType: "pilot_next_renewal_quote_acceptance_handoff_packet",
    subjectId: packetId,
    customerId: release.customerId,
    status,
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      releasePacketId: release.id,
      handoffId: release.nextRenewalQuoteHandoffId,
      renewalCloseoutPacketId: release.renewalCloseoutPacketId,
      nextRenewalTaskId: release.nextRenewalTaskId,
      quoteId: quote.id,
      acceptanceId: acceptance.id,
      financeApprovalId: financeApproval.id,
      total: quote.total
    }
  });
  audit(db, user.org_id, user.id, "pilot.next_renewal_quote_acceptance_handoff.created", {
    packetId,
    releasePacketId: release.id,
    handoffId: release.nextRenewalQuoteHandoffId,
    renewalCloseoutPacketId: release.renewalCloseoutPacketId,
    nextRenewalTaskId: release.nextRenewalTaskId,
    quoteId: quote.id,
    acceptanceId: acceptance.id,
    financeApprovalId: financeApproval.id,
    total: quote.total,
    checksum
  });
  return {
    ok: true,
    idempotent: false,
    packet: getPilotNextRenewalQuoteAcceptanceHandoffPacket(db, user.org_id, packetId, true)
  };
}

