function createClinicWellnessFollowingRenewalQuoteHandoff(db, user, nextRenewalCloseoutPacketIdParam, body) {
  const nextRenewalCloseoutPacketId = String(nextRenewalCloseoutPacketIdParam || "").trim();
  const closeout = nextRenewalCloseoutPacketId
    ? getPilotNextRenewalCloseoutPacket(db, user.org_id, nextRenewalCloseoutPacketId, true)
    : null;
  if (!closeout) {
    const err = new Error("Pilot next renewal closeout packet not found");
    err.statusCode = 404;
    throw err;
  }
  if (closeout.status !== "next-renewal-cycle-closed") {
    const err = new Error("Pilot next renewal cycle must be closed before following renewal quote handoff");
    err.statusCode = 409;
    throw err;
  }

  const sourceKey = `pilot-following-renewal-quote:${closeout.id}`;
  const existing = db.prepare("SELECT id FROM pilot_following_renewal_quote_handoff_packets WHERE org_id = ? AND source_key = ?")
    .get(user.org_id, sourceKey);
  if (existing) {
    const handoff = getPilotFollowingRenewalQuoteHandoffPacket(db, user.org_id, existing.id, true);
    return {
      ok: true,
      idempotent: true,
      handoff,
      quote: getQuote(db, user.org_id, handoff.quoteId),
      approval: getWorkflowApproval(db, user.org_id, handoff.approvalId)
    };
  }

  const followingRenewalTask = getCrmTask(db, user.org_id, closeout.followingRenewalTaskId);
  if (!followingRenewalTask) {
    const err = new Error("CRM following renewal task is required before following renewal quote handoff");
    err.statusCode = 409;
    throw err;
  }
  const deal = getDeal(db, user.org_id, closeout.dealId);
  if (!deal || deal.customerId !== closeout.customerId) {
    const err = new Error("Deal is required for following renewal quote handoff");
    err.statusCode = 422;
    throw err;
  }

  const approvalNote = normalizeCrmQuoteReleaseApprovalNoteForHandoff(body, "Release the following monthly renewal quote after owner review.");
  const validUntil = normalizeIsoDate(
    body.validUntil || addDays(closeout.followingRenewalDueDate || closeout.closeoutDate || armeniaDateString(), 14),
    "validUntil"
  );
  const quote = createCrmQuote(db, user, {
    customerId: closeout.customerId,
    dealId: deal.id,
    title: "Armosphera One clinic/wellness following monthly renewal",
    validUntil,
    lines: buildPilotFollowingRenewalQuoteLines(closeout)
  });
  const approvalResult = requestQuoteReleaseApproval(db, user, quote.id, { note: approvalNote });
  const approval = approvalResult.approval;
  const now = new Date().toISOString();
  const note = String(body.note || "").trim().slice(0, 500);
  const payload = {
    kind: "armosphera-one-pilot-following-renewal-quote-handoff",
    product: "Armosphera One",
    schemaVersion: 1,
    templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
    generatedAt: now,
    nextRenewalCloseout: {
      id: closeout.id,
      checksum: closeout.checksum,
      status: closeout.status,
      closeoutDate: closeout.closeoutDate,
      followingRenewalDueDate: closeout.followingRenewalDueDate
    },
    nextRenewalPaymentCollection: {
      id: closeout.nextRenewalPaymentCollectionPacketId,
      status: closeout.payload?.nextRenewalPaymentCollection?.status || "next-renewal-payment-collected"
    },
    nextRenewalPostingPacket: {
      id: closeout.nextRenewalPostingPacketId
    },
    nextRenewalDraftPacket: {
      id: closeout.nextRenewalDraftPacketId
    },
    nextRenewalAcceptanceHandoff: {
      id: closeout.nextRenewalAcceptanceHandoffId
    },
    release: {
      id: closeout.nextRenewalQuoteReleasePacketId
    },
    handoff: {
      id: closeout.nextRenewalQuoteHandoffId
    },
    renewalCloseout: {
      id: closeout.renewalCloseoutPacketId
    },
    renewalPaymentCollection: {
      id: closeout.renewalPaymentCollectionPacketId
    },
    previousRenewalPosting: {
      id: closeout.renewalPostingPacketId
    },
    previousRenewalDraft: {
      id: closeout.renewalDraftPacketId
    },
    previousRenewalRelease: {
      id: closeout.renewalQuoteReleasePacketId
    },
    previousRenewalHandoff: {
      id: closeout.renewalQuoteHandoffId
    },
    priorCloseout: {
      id: closeout.closeoutPacketId
    },
    priorPaymentCollection: {
      id: closeout.priorPaymentCollectionPacketId
    },
    priorPosting: {
      id: closeout.priorPostingPacketId
    },
    customer: {
      id: closeout.customerId,
      name: closeout.customerName
    },
    deal: {
      id: deal.id,
      title: deal.title,
      stage: deal.stage
    },
    renewalTask: {
      id: closeout.renewalTaskId
    },
    nextRenewalTask: {
      id: closeout.nextRenewalTaskId
    },
    followingRenewalTask: {
      id: followingRenewalTask.id,
      title: followingRenewalTask.title,
      dueDate: followingRenewalTask.dueDate,
      ownerName: followingRenewalTask.ownerName,
      sourceKey: followingRenewalTask.sourceKey
    },
    quote: {
      id: quote.id,
      number: quote.number,
      status: quote.status,
      total: quote.total,
      subtotal: quote.subtotal,
      vat: quote.vat,
      validUntil: quote.validUntil,
      lineCount: quote.lines.length
    },
    approval: {
      id: approval.id,
      actionKey: approval.actionKey,
      status: approval.status
    },
    commercial: {
      monthlyTotal: quote.total,
      subtotal: quote.subtotal,
      vat: quote.vat,
      currency: quote.currency,
      vatRate: 0.2
    },
    controls: [
      "following-renewal-quote-approval-created",
      "public-following-renewal-quote-hidden-until-approved",
      "next-renewal-closeout-checksum-linked",
      "following-renewal-task-linked",
      "armenian-vat-following-renewal-pricing-confirmed"
    ],
    note
  };
  const checksum = sha256Json(payload);
  const handoffId = randomId("pilot-following-renewal-quote-handoff");
  db.prepare(`
    INSERT INTO pilot_following_renewal_quote_handoff_packets (
      id, org_id, template_key, next_renewal_closeout_packet_id,
      next_renewal_payment_collection_packet_id, next_renewal_posting_packet_id,
      next_renewal_draft_packet_id, next_renewal_acceptance_handoff_id,
      next_renewal_quote_release_packet_id, next_renewal_quote_handoff_id,
      renewal_closeout_packet_id, renewal_payment_collection_packet_id,
      renewal_posting_packet_id, renewal_draft_packet_id,
      renewal_acceptance_handoff_id, renewal_quote_release_packet_id,
      renewal_quote_handoff_id, closeout_packet_id, prior_payment_collection_packet_id,
      prior_posting_packet_id, renewal_task_id, next_renewal_task_id,
      following_renewal_task_id, customer_id, deal_id, quote_id, approval_id,
      status, source_key, monthly_total, subtotal, vat, valid_until, checksum,
      payload, note, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    handoffId,
    user.org_id,
    CLINIC_WELLNESS_TEMPLATE_KEY,
    closeout.id,
    closeout.nextRenewalPaymentCollectionPacketId,
    closeout.nextRenewalPostingPacketId,
    closeout.nextRenewalDraftPacketId,
    closeout.nextRenewalAcceptanceHandoffId,
    closeout.nextRenewalQuoteReleasePacketId,
    closeout.nextRenewalQuoteHandoffId,
    closeout.renewalCloseoutPacketId,
    closeout.renewalPaymentCollectionPacketId,
    closeout.renewalPostingPacketId,
    closeout.renewalDraftPacketId,
    closeout.renewalAcceptanceHandoffId,
    closeout.renewalQuoteReleasePacketId,
    closeout.renewalQuoteHandoffId,
    closeout.closeoutPacketId,
    closeout.priorPaymentCollectionPacketId,
    closeout.priorPostingPacketId,
    closeout.renewalTaskId,
    closeout.nextRenewalTaskId,
    followingRenewalTask.id,
    closeout.customerId,
    deal.id,
    quote.id,
    approval.id,
    "following-renewal-quote-release-pending",
    sourceKey,
    quote.total,
    quote.subtotal,
    quote.vat,
    validUntil,
    checksum,
    JSON.stringify(payload),
    note,
    user.id,
    now,
    now
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "pilot.following_renewal_quote_handoff.created",
    subjectType: "pilot_following_renewal_quote_handoff_packet",
    subjectId: handoffId,
    customerId: closeout.customerId,
    status: "following-renewal-quote-release-pending",
    payload: {
      templateKey: CLINIC_WELLNESS_TEMPLATE_KEY,
      nextRenewalCloseoutPacketId: closeout.id,
      followingRenewalTaskId: followingRenewalTask.id,
      quoteId: quote.id,
      approvalId: approval.id,
      monthlyTotal: quote.total
    }
  });
  audit(db, user.org_id, user.id, "pilot.following_renewal_quote_handoff.created", {
    handoffId,
    nextRenewalCloseoutPacketId: closeout.id,
    followingRenewalTaskId: followingRenewalTask.id,
    quoteId: quote.id,
    approvalId: approval.id,
    monthlyTotal: quote.total,
    checksum
  });
  return {
    ok: true,
    idempotent: false,
    handoff: getPilotFollowingRenewalQuoteHandoffPacket(db, user.org_id, handoffId, true),
    quote,
    approval
  };
}

function buildPilotFollowingRenewalQuoteLines(closeout) {
  const monthlyTotal = Math.max(960000, Math.round(Number(closeout.amount || 0)));
  return [{
    description: "Armosphera One following monthly renewal operations and HayHashvapah accounting handoff",
    quantity: 1,
    unitPrice: monthlyTotal
  }];
}

function getPilotFollowingRenewalQuoteHandoffPackets(db, orgId, templateKey, nextRenewalCloseoutPacketId = "") {
  const filters = ["pilot_following_renewal_quote_handoff_packets.org_id = ?", "pilot_following_renewal_quote_handoff_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedCloseoutPacketId = String(nextRenewalCloseoutPacketId || "").trim();
  if (requestedCloseoutPacketId) {
    filters.push("pilot_following_renewal_quote_handoff_packets.next_renewal_closeout_packet_id = ?");
    params.push(requestedCloseoutPacketId);
  }
  return db.prepare(`
    SELECT pilot_following_renewal_quote_handoff_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_following_renewal_quote_handoff_packets
    JOIN customers ON customers.id = pilot_following_renewal_quote_handoff_packets.customer_id
    LEFT JOIN users ON users.id = pilot_following_renewal_quote_handoff_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_following_renewal_quote_handoff_packets.created_at DESC
  `).all(...params).map(row => formatPilotFollowingRenewalQuoteHandoffPacket(row, false));
}

function getPilotFollowingRenewalQuoteHandoffPacket(db, orgId, handoffId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_following_renewal_quote_handoff_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_following_renewal_quote_handoff_packets
    JOIN customers ON customers.id = pilot_following_renewal_quote_handoff_packets.customer_id
    LEFT JOIN users ON users.id = pilot_following_renewal_quote_handoff_packets.created_by_user_id
    WHERE pilot_following_renewal_quote_handoff_packets.org_id = ? AND pilot_following_renewal_quote_handoff_packets.id = ?
  `).get(orgId, handoffId);
  return row ? formatPilotFollowingRenewalQuoteHandoffPacket(row, includePayload) : null;
}

