    renewalDraftPacketId: row.renewal_draft_packet_id,
    renewalAcceptanceHandoffId: row.renewal_acceptance_handoff_id,
    renewalQuoteReleasePacketId: row.renewal_quote_release_packet_id,
    renewalQuoteHandoffId: row.renewal_quote_handoff_id,
    closeoutPacketId: row.closeout_packet_id,
