    dealId: row.deal_id,
    quoteId: row.quote_id,
    approvalId: row.approval_id,
    status: row.status,
    publicToken: row.public_token,
    publicUrl: row.public_url,
    total: row.total || payload.quote?.total || 0,
    subtotal: row.subtotal || payload.quote?.subtotal || 0,
