function getPilotSubsequentRenewalHayhashvapahDraftInvoicePackets(db, orgId, templateKey, subsequentRenewalAcceptanceHandoffId = "") {
  const filters = ["pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.org_id = ?", "pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedHandoffId = String(subsequentRenewalAcceptanceHandoffId || "").trim();
  if (requestedHandoffId) {
    filters.push("pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.subsequent_renewal_acceptance_handoff_id = ?");
    params.push(requestedHandoffId);
  }
  return db.prepare(`
    SELECT pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets
    JOIN customers ON customers.id = pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.customer_id
    LEFT JOIN users ON users.id = pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.created_at DESC
  `).all(...params).map(row => formatPilotSubsequentRenewalHayhashvapahDraftInvoicePacket(row, false));
}

function getPilotSubsequentRenewalHayhashvapahDraftInvoicePacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets
    JOIN customers ON customers.id = pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.customer_id
    LEFT JOIN users ON users.id = pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.created_by_user_id
    WHERE pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.org_id = ? AND pilot_subsequent_renewal_hayhashvapah_draft_invoice_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotSubsequentRenewalHayhashvapahDraftInvoicePacket(row, includePayload) : null;
}

