function buildPilotContinuationRenewalQuoteLines(closeout) {
  const monthlyTotal = Math.max(960000, Math.round(Number(closeout.amount || 0)));
  return [{
    description: "Armosphera One continuation monthly renewal operations and HayHashvapah accounting handoff",
    quantity: 1,
    unitPrice: monthlyTotal
  }];
}

function getPilotContinuationRenewalQuoteHandoffPackets(db, orgId, templateKey, subsequentRenewalCloseoutPacketId = "") {
  const filters = ["pilot_continuation_renewal_quote_handoff_packets.org_id = ?", "pilot_continuation_renewal_quote_handoff_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedCloseoutPacketId = String(subsequentRenewalCloseoutPacketId || "").trim();
  if (requestedCloseoutPacketId) {
    filters.push("pilot_continuation_renewal_quote_handoff_packets.subsequent_renewal_closeout_packet_id = ?");
    params.push(requestedCloseoutPacketId);
  }
  return db.prepare(`
    SELECT pilot_continuation_renewal_quote_handoff_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_continuation_renewal_quote_handoff_packets
    JOIN customers ON customers.id = pilot_continuation_renewal_quote_handoff_packets.customer_id
    LEFT JOIN users ON users.id = pilot_continuation_renewal_quote_handoff_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_continuation_renewal_quote_handoff_packets.created_at DESC
  `).all(...params).map(row => formatPilotContinuationRenewalQuoteHandoffPacket(row, false));
}

function getPilotContinuationRenewalQuoteHandoffPacket(db, orgId, handoffId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_continuation_renewal_quote_handoff_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_continuation_renewal_quote_handoff_packets
    JOIN customers ON customers.id = pilot_continuation_renewal_quote_handoff_packets.customer_id
    LEFT JOIN users ON users.id = pilot_continuation_renewal_quote_handoff_packets.created_by_user_id
    WHERE pilot_continuation_renewal_quote_handoff_packets.org_id = ? AND pilot_continuation_renewal_quote_handoff_packets.id = ?
  `).get(orgId, handoffId);
  return row ? formatPilotContinuationRenewalQuoteHandoffPacket(row, includePayload) : null;
}

