    nextRenewalPaymentCollectionPacketId: row.next_renewal_payment_collection_packet_id,
    nextRenewalPostingPacketId: row.next_renewal_posting_packet_id,
    nextRenewalDraftPacketId: row.next_renewal_draft_packet_id,
    nextRenewalAcceptanceHandoffId: row.next_renewal_acceptance_handoff_id,
    nextRenewalQuoteReleasePacketId: row.next_renewal_quote_release_packet_id,
    nextRenewalQuoteHandoffId: row.next_renewal_quote_handoff_id,
    renewalCloseoutPacketId: row.renewal_closeout_packet_id,
    renewalPaymentCollectionPacketId: row.renewal_payment_collection_packet_id,
