function getPilotContinuationRenewalQuoteReleasePackets(db, orgId, templateKey, continuationRenewalHandoffId = "") {
  const filters = ["pilot_continuation_renewal_quote_release_packets.org_id = ?", "pilot_continuation_renewal_quote_release_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedHandoffId = String(continuationRenewalHandoffId || "").trim();
  if (requestedHandoffId) {
    filters.push("pilot_continuation_renewal_quote_release_packets.continuation_renewal_quote_handoff_id = ?");
    params.push(requestedHandoffId);
  }
  return db.prepare(`
    SELECT pilot_continuation_renewal_quote_release_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_continuation_renewal_quote_release_packets
    JOIN customers ON customers.id = pilot_continuation_renewal_quote_release_packets.customer_id
    LEFT JOIN users ON users.id = pilot_continuation_renewal_quote_release_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_continuation_renewal_quote_release_packets.created_at DESC
  `).all(...params).map(row => formatPilotContinuationRenewalQuoteReleasePacket(row, false));
}

function getPilotContinuationRenewalQuoteReleasePacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_continuation_renewal_quote_release_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_continuation_renewal_quote_release_packets
    JOIN customers ON customers.id = pilot_continuation_renewal_quote_release_packets.customer_id
    LEFT JOIN users ON users.id = pilot_continuation_renewal_quote_release_packets.created_by_user_id
    WHERE pilot_continuation_renewal_quote_release_packets.org_id = ? AND pilot_continuation_renewal_quote_release_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotContinuationRenewalQuoteReleasePacket(row, includePayload) : null;
}

