function getPilotContinuationRenewalCloseoutPackets(db, orgId, templateKey, paymentCollectionPacketId = "") {
  const filters = ["pilot_continuation_renewal_closeout_packets.org_id = ?", "pilot_continuation_renewal_closeout_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedPaymentCollectionPacketId = String(paymentCollectionPacketId || "").trim();
  if (requestedPaymentCollectionPacketId) {
    filters.push("pilot_continuation_renewal_closeout_packets.continuation_renewal_payment_collection_packet_id = ?");
    params.push(requestedPaymentCollectionPacketId);
  }
  return db.prepare(`
    SELECT pilot_continuation_renewal_closeout_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_continuation_renewal_closeout_packets
    JOIN customers ON customers.id = pilot_continuation_renewal_closeout_packets.customer_id
    LEFT JOIN users ON users.id = pilot_continuation_renewal_closeout_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_continuation_renewal_closeout_packets.created_at DESC
  `).all(...params).map(row => formatPilotContinuationRenewalCloseoutPacket(row, false));
}

function getPilotContinuationRenewalCloseoutPacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_continuation_renewal_closeout_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_continuation_renewal_closeout_packets
    JOIN customers ON customers.id = pilot_continuation_renewal_closeout_packets.customer_id
    LEFT JOIN users ON users.id = pilot_continuation_renewal_closeout_packets.created_by_user_id
    WHERE pilot_continuation_renewal_closeout_packets.org_id = ? AND pilot_continuation_renewal_closeout_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotContinuationRenewalCloseoutPacket(row, includePayload) : null;
}

