    subsequentRenewalQuoteReleasePacketId: row.subsequent_renewal_quote_release_packet_id,
    subsequentRenewalQuoteHandoffId: row.subsequent_renewal_quote_handoff_id,
    followingRenewalCloseoutPacketId: row.following_renewal_closeout_packet_id,
    followingRenewalPaymentCollectionPacketId: row.following_renewal_payment_collection_packet_id,
    followingRenewalPostingPacketId: row.following_renewal_posting_packet_id,
    nextRenewalCloseoutPacketId: row.next_renewal_closeout_packet_id,
    nextRenewalPaymentCollectionPacketId: row.next_renewal_payment_collection_packet_id,
    nextRenewalPostingPacketId: row.next_renewal_posting_packet_id,
    renewalCloseoutPacketId: row.renewal_closeout_packet_id,
    renewalPaymentCollectionPacketId: row.renewal_payment_collection_packet_id,
    renewalPostingPacketId: row.renewal_posting_packet_id,
    closeoutPacketId: row.closeout_packet_id,
    priorPaymentCollectionPacketId: row.prior_payment_collection_packet_id,
    priorPostingPacketId: row.prior_posting_packet_id,
    renewalTaskId: row.renewal_task_id,
    nextRenewalTaskId: row.next_renewal_task_id,
    followingRenewalTaskId: row.following_renewal_task_id,
    subsequentRenewalTaskId: row.subsequent_renewal_task_id,
    continuationRenewalTaskId: row.continuation_renewal_task_id,
    ongoingRenewalTaskId: row.ongoing_renewal_task_id,
    customerId: row.customer_id,
    customerName: row.customer_name || payload.customer?.name,
    dealId: row.deal_id,
    quoteId: row.quote_id,
    approvalId: row.approval_id,
    status: row.status,
    monthlyTotal: row.monthly_total || payload.quote?.total || 0,
    subtotal: row.subtotal || payload.quote?.subtotal || 0,
    vat: row.vat || payload.quote?.vat || 0,
    validUntil: row.valid_until || payload.quote?.validUntil,
