    priorPaymentCollectionPacketId: row.prior_payment_collection_packet_id,
    priorPostingPacketId: row.prior_posting_packet_id,
    renewalTaskId: row.renewal_task_id,
    nextRenewalTaskId: row.next_renewal_task_id,
    followingRenewalTaskId: row.following_renewal_task_id,
    subsequentRenewalTaskId: row.subsequent_renewal_task_id,
    continuationRenewalTaskId: row.continuation_renewal_task_id,
    ongoingRenewalTaskId: row.ongoing_renewal_task_id,
    customerId: row.customer_id,
    customerName: row.customer_name || payload.customer?.name,
    dealId: row.deal_id,
