    financeApprovalId: row.finance_approval_id,
    status: row.status,
    signerName: row.signer_name,
    signerEmail: row.signer_email,
    acceptedAt: row.accepted_at,
    periodKey: row.period_key || payload.hayhashvapah?.periodKey || payload.financeApproval?.periodKey || "",
    vatMode: row.vat_mode || payload.hayhashvapah?.vatMode || payload.financeApproval?.vatMode || "",
    total: row.total || payload.quote?.total || 0,
    subtotal: row.subtotal || payload.quote?.subtotal || 0,
    vat: row.vat || payload.quote?.vat || 0,
    checksum: row.checksum,
