function buildPilotNextOngoingRenewalQuoteLines(closeout) {
  const monthlyTotal = Math.max(960000, Math.round(Number(closeout.amount || 0)));
  return [{
    description: "Armosphera One next ongoing monthly renewal operations and HayHashvapah accounting handoff",
    quantity: 1,
    unitPrice: monthlyTotal
  }];
}

function getPilotNextOngoingRenewalQuoteHandoffPackets(db, orgId, templateKey, ongoingRenewalCloseoutPacketId = "") {
  const filters = ["pilot_next_ongoing_renewal_quote_handoff_packets.org_id = ?", "pilot_next_ongoing_renewal_quote_handoff_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedCloseoutPacketId = String(ongoingRenewalCloseoutPacketId || "").trim();
  if (requestedCloseoutPacketId) {
    filters.push("pilot_next_ongoing_renewal_quote_handoff_packets.ongoing_renewal_closeout_packet_id = ?");
    params.push(requestedCloseoutPacketId);
  }
  return db.prepare(`
    SELECT pilot_next_ongoing_renewal_quote_handoff_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_ongoing_renewal_quote_handoff_packets
    JOIN customers ON customers.id = pilot_next_ongoing_renewal_quote_handoff_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_ongoing_renewal_quote_handoff_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_next_ongoing_renewal_quote_handoff_packets.created_at DESC
  `).all(...params).map(row => formatPilotNextOngoingRenewalQuoteHandoffPacket(row, false));
}

function getPilotNextOngoingRenewalQuoteHandoffPacket(db, orgId, handoffId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_next_ongoing_renewal_quote_handoff_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_ongoing_renewal_quote_handoff_packets
    JOIN customers ON customers.id = pilot_next_ongoing_renewal_quote_handoff_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_ongoing_renewal_quote_handoff_packets.created_by_user_id
    WHERE pilot_next_ongoing_renewal_quote_handoff_packets.org_id = ? AND pilot_next_ongoing_renewal_quote_handoff_packets.id = ?
  `).get(orgId, handoffId);
  return row ? formatPilotNextOngoingRenewalQuoteHandoffPacket(row, includePayload) : null;
}

