function getPilotNextOngoingRenewalHayhashvapahInvoicePostingPackets(db, orgId, templateKey, draftPacketId = "") {
  const filters = ["pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.org_id = ?", "pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedDraftPacketId = String(draftPacketId || "").trim();
  if (requestedDraftPacketId) {
    filters.push("pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.next_ongoing_renewal_draft_packet_id = ?");
    params.push(requestedDraftPacketId);
  }
  return db.prepare(`
    SELECT pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets
    JOIN customers ON customers.id = pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.created_at DESC
  `).all(...params).map(row => formatPilotNextOngoingRenewalHayhashvapahInvoicePostingPacket(row, false));
}

function getPilotNextOngoingRenewalHayhashvapahInvoicePostingPacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets
    JOIN customers ON customers.id = pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.created_by_user_id
    WHERE pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.org_id = ? AND pilot_next_ongoing_renewal_hayhashvapah_invoice_posting_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotNextOngoingRenewalHayhashvapahInvoicePostingPacket(row, includePayload) : null;
}

