    status: row.status,
    periodKey: row.period_key || payload.hayhashvapah?.periodKey || payload.draftInvoice?.periodKey || "",
    vatMode: row.vat_mode || payload.hayhashvapah?.vatMode || "",
    subtotal: row.subtotal || payload.draftInvoice?.subtotal || 0,
    vat: row.vat || payload.invoice?.vat || 0,
    total: row.total || payload.invoice?.total || 0,
    checksum: row.checksum,
    note: row.note,
    createdByUserId: row.created_by_user_id,
