function getPilotNextOngoingRenewalHayhashvapahPaymentCollectionPackets(db, orgId, templateKey, postingPacketId = "") {
  const filters = ["pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.org_id = ?", "pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedPostingPacketId = String(postingPacketId || "").trim();
  if (requestedPostingPacketId) {
    filters.push("pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.next_ongoing_renewal_posting_packet_id = ?");
    params.push(requestedPostingPacketId);
  }
  return db.prepare(`
    SELECT pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets
    JOIN customers ON customers.id = pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.created_at DESC
  `).all(...params).map(row => formatPilotNextOngoingRenewalHayhashvapahPaymentCollectionPacket(row, false));
}

function getPilotNextOngoingRenewalHayhashvapahPaymentCollectionPacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets
    JOIN customers ON customers.id = pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.created_by_user_id
    WHERE pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.org_id = ? AND pilot_next_ongoing_renewal_hayhashvapah_payment_collection_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotNextOngoingRenewalHayhashvapahPaymentCollectionPacket(row, includePayload) : null;
}

