    continuationRenewalTaskId: row.continuation_renewal_task_id,
    ongoingRenewalTaskId: row.ongoing_renewal_task_id,
    nextOngoingRenewalTaskId: row.next_ongoing_renewal_task_id,
    customerId: row.customer_id,
    customerName: row.customer_name || payload.customer?.name,
    dealId: row.deal_id,
    quoteId: row.quote_id,
    acceptanceId: row.acceptance_id,
    draftInvoiceId: row.draft_invoice_id,
    invoiceId: row.invoice_id,
    invoiceLinkId: row.invoice_link_id,
    paymentId: row.payment_id,
