    continuationRenewalCloseoutPacketId: row.continuation_renewal_closeout_packet_id,
    continuationRenewalPaymentCollectionPacketId: row.continuation_renewal_payment_collection_packet_id,
    continuationRenewalPostingPacketId: row.continuation_renewal_posting_packet_id,
    subsequentRenewalCloseoutPacketId: row.subsequent_renewal_closeout_packet_id,
    subsequentRenewalPaymentCollectionPacketId: row.subsequent_renewal_payment_collection_packet_id,
    subsequentRenewalPostingPacketId: row.subsequent_renewal_posting_packet_id,
    followingRenewalCloseoutPacketId: row.following_renewal_closeout_packet_id,
    followingRenewalPaymentCollectionPacketId: row.following_renewal_payment_collection_packet_id,
    followingRenewalPostingPacketId: row.following_renewal_posting_packet_id,
    nextRenewalCloseoutPacketId: row.next_renewal_closeout_packet_id,
    nextRenewalPaymentCollectionPacketId: row.next_renewal_payment_collection_packet_id,
    nextRenewalPostingPacketId: row.next_renewal_posting_packet_id,
