function getPilotFollowingOngoingRenewalHayhashvapahPaymentCollectionPackets(db, orgId, templateKey, postingPacketId = "") {
  const filters = ["pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.org_id = ?", "pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedPostingPacketId = String(postingPacketId || "").trim();
  if (requestedPostingPacketId) {
    filters.push("pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.following_ongoing_renewal_posting_packet_id = ?");
    params.push(requestedPostingPacketId);
  }
  return db.prepare(`
    SELECT pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets
    JOIN customers ON customers.id = pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.customer_id
    LEFT JOIN users ON users.id = pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.created_at DESC
  `).all(...params).map(row => formatPilotFollowingOngoingRenewalHayhashvapahPaymentCollectionPacket(row, false));
}

function getPilotFollowingOngoingRenewalHayhashvapahPaymentCollectionPacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets
    JOIN customers ON customers.id = pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.customer_id
    LEFT JOIN users ON users.id = pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.created_by_user_id
    WHERE pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.org_id = ? AND pilot_following_ongoing_renewal_hayhashvapah_payment_collection_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotFollowingOngoingRenewalHayhashvapahPaymentCollectionPacket(row, includePayload) : null;
}

