    deal_id: paymentCollection.dealId,
    quote_id: paymentCollection.quoteId,
    acceptance_id: paymentCollection.acceptanceId,
    draft_invoice_id: paymentCollection.draftInvoiceId,
    invoice_id: invoice.id,
    invoice_link_id: paymentCollection.invoiceLinkId,
