    nextOngoingRenewalCloseoutPacketId: row.next_ongoing_renewal_closeout_packet_id,
    nextOngoingRenewalPaymentCollectionPacketId: row.next_ongoing_renewal_payment_collection_packet_id,
    nextOngoingRenewalPostingPacketId: row.next_ongoing_renewal_posting_packet_id,
    nextOngoingRenewalDraftPacketId: row.next_ongoing_renewal_draft_packet_id,
    nextOngoingRenewalAcceptanceHandoffId: row.next_ongoing_renewal_acceptance_handoff_id,
    nextOngoingRenewalQuoteReleasePacketId: row.next_ongoing_renewal_quote_release_packet_id,
    nextOngoingRenewalQuoteHandoffId: row.next_ongoing_renewal_quote_handoff_id,
    ongoingRenewalCloseoutPacketId: row.ongoing_renewal_closeout_packet_id,
    ongoingRenewalPaymentCollectionPacketId: row.ongoing_renewal_payment_collection_packet_id,
    ongoingRenewalPostingPacketId: row.ongoing_renewal_posting_packet_id,
    continuationRenewalCloseoutPacketId: row.continuation_renewal_closeout_packet_id,
    subsequentRenewalCloseoutPacketId: row.subsequent_renewal_closeout_packet_id,
    followingRenewalCloseoutPacketId: row.following_renewal_closeout_packet_id,
    nextRenewalCloseoutPacketId: row.next_renewal_closeout_packet_id,
    renewalCloseoutPacketId: row.renewal_closeout_packet_id,
    closeoutPacketId: row.closeout_packet_id,
    priorPaymentCollectionPacketId: row.prior_payment_collection_packet_id,
    priorPostingPacketId: row.prior_posting_packet_id,
    renewalTaskId: row.renewal_task_id,
    nextRenewalTaskId: row.next_renewal_task_id,
    followingRenewalTaskId: row.following_renewal_task_id,
    subsequentRenewalTaskId: row.subsequent_renewal_task_id,
    continuationRenewalTaskId: row.continuation_renewal_task_id,
    ongoingRenewalTaskId: row.ongoing_renewal_task_id,
    nextOngoingRenewalTaskId: row.next_ongoing_renewal_task_id,
    followingOngoingRenewalTaskId: row.following_ongoing_renewal_task_id,
    subsequentOngoingRenewalTaskId: row.subsequent_ongoing_renewal_task_id,
    customerId: row.customer_id,
    customerName: row.customer_name || payload.customer?.name,
    dealId: row.deal_id,
    quoteId: row.quote_id,
    approvalId: row.approval_id,
    status: row.status,
    monthlyTotal: row.monthly_total || payload.commercial?.monthlyTotal || 0,
    subtotal: row.subtotal || payload.commercial?.subtotal || 0,
    vat: row.vat || payload.commercial?.vat || 0,
    validUntil: row.valid_until,
    checksum: row.checksum,
    note: row.note,
    createdByUserId: row.created_by_user_id,
