    next_ongoing_renewal_closeout_packet_id: handoff.nextOngoingRenewalCloseoutPacketId,
    next_ongoing_renewal_payment_collection_packet_id: handoff.nextOngoingRenewalPaymentCollectionPacketId,
    next_ongoing_renewal_posting_packet_id: handoff.nextOngoingRenewalPostingPacketId,
