    ongoing_renewal_payment_collection_packet_id: handoff.ongoingRenewalPaymentCollectionPacketId,
    ongoing_renewal_posting_packet_id: handoff.ongoingRenewalPostingPacketId,
    continuation_renewal_closeout_packet_id: handoff.continuationRenewalCloseoutPacketId,
    subsequent_renewal_closeout_packet_id: handoff.subsequentRenewalCloseoutPacketId,
    following_renewal_closeout_packet_id: handoff.followingRenewalCloseoutPacketId,
    next_renewal_closeout_packet_id: handoff.nextRenewalCloseoutPacketId,
    renewal_closeout_packet_id: handoff.renewalCloseoutPacketId,
