    next_renewal_task_id: handoff.nextRenewalTaskId,
    following_renewal_task_id: handoff.followingRenewalTaskId,
    subsequent_renewal_task_id: handoff.subsequentRenewalTaskId,
    continuation_renewal_task_id: handoff.continuationRenewalTaskId,
    ongoing_renewal_task_id: handoff.ongoingRenewalTaskId,
    next_ongoing_renewal_task_id: handoff.nextOngoingRenewalTaskId,
    following_ongoing_renewal_task_id: handoff.followingOngoingRenewalTaskId,
    subsequent_ongoing_renewal_task_id: handoff.subsequentOngoingRenewalTaskId,
