    nextOngoingRenewalPaymentCollectionPacketId: row.next_ongoing_renewal_payment_collection_packet_id,
    nextOngoingRenewalPostingPacketId: row.next_ongoing_renewal_posting_packet_id,
    nextOngoingRenewalDraftPacketId: row.next_ongoing_renewal_draft_packet_id,
    nextOngoingRenewalAcceptanceHandoffId: row.next_ongoing_renewal_acceptance_handoff_id,
    nextOngoingRenewalQuoteReleasePacketId: row.next_ongoing_renewal_quote_release_packet_id,
    nextOngoingRenewalQuoteHandoffId: row.next_ongoing_renewal_quote_handoff_id,
    ongoingRenewalCloseoutPacketId: row.ongoing_renewal_closeout_packet_id,
    ongoingRenewalPaymentCollectionPacketId: row.ongoing_renewal_payment_collection_packet_id,
    ongoingRenewalPostingPacketId: row.ongoing_renewal_posting_packet_id,
    continuationRenewalCloseoutPacketId: row.continuation_renewal_closeout_packet_id,
    subsequentRenewalCloseoutPacketId: row.subsequent_renewal_closeout_packet_id,
    followingRenewalCloseoutPacketId: row.following_renewal_closeout_packet_id,
    nextRenewalCloseoutPacketId: row.next_renewal_closeout_packet_id,
    renewalCloseoutPacketId: row.renewal_closeout_packet_id,
