      subsequentOngoingRenewalQuoteReleasePacketId: release.id,
      subsequentOngoingRenewalQuoteHandoffId: release.subsequentOngoingRenewalQuoteHandoffId,
      followingOngoingRenewalCloseoutPacketId: release.followingOngoingRenewalCloseoutPacketId,
