    vatMode: row.vat_mode || payload.hayhashvapah?.vatMode || payload.financeApproval?.vatMode || "",
    total: row.total || payload.quote?.total || 0,
    subtotal: row.subtotal || payload.quote?.subtotal || 0,
    vat: row.vat || payload.quote?.vat || 0,
    checksum: row.checksum,
    note: row.note,
    createdByUserId: row.created_by_user_id,
    createdByName: row.created_by_name,
