function getPilotSubsequentOngoingRenewalHayhashvapahDraftInvoicePackets(db, orgId, templateKey, subsequentOngoingRenewalAcceptanceHandoffId = "") {
  const filters = ["pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.org_id = ?", "pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedHandoffId = String(subsequentOngoingRenewalAcceptanceHandoffId || "").trim();
  if (requestedHandoffId) {
    filters.push("pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.subsequent_ongoing_renewal_acceptance_handoff_id = ?");
    params.push(requestedHandoffId);
  }
  return db.prepare(`
    SELECT pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets
    JOIN customers ON customers.id = pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.customer_id
    LEFT JOIN users ON users.id = pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.created_at DESC
  `).all(...params).map(row => formatPilotSubsequentOngoingRenewalHayhashvapahDraftInvoicePacket(row, false));
}

function getPilotSubsequentOngoingRenewalHayhashvapahDraftInvoicePacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets
    JOIN customers ON customers.id = pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.customer_id
    LEFT JOIN users ON users.id = pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.created_by_user_id
    WHERE pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.org_id = ? AND pilot_subsequent_ongoing_renewal_hayhashvapah_draft_invoice_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotSubsequentOngoingRenewalHayhashvapahDraftInvoicePacket(row, includePayload) : null;
}

