    nextOngoingRenewalTaskId: row.next_ongoing_renewal_task_id,
    followingOngoingRenewalTaskId: row.following_ongoing_renewal_task_id,
    subsequentOngoingRenewalTaskId: row.subsequent_ongoing_renewal_task_id,
    customerId: row.customer_id,
    customerName: row.customer_name || payload.customer?.name,
    dealId: row.deal_id,
    quoteId: row.quote_id,
    acceptanceId: row.acceptance_id,
    financeApprovalId: row.finance_approval_id,
    workflowRunId: row.workflow_run_id,
    draftInvoiceId: row.draft_invoice_id,
    draftNumber: row.draft_number,
    status: row.status,
    periodKey: row.period_key || payload.hayhashvapah?.periodKey || payload.draftInvoice?.periodKey || "",
    vatMode: row.vat_mode || payload.hayhashvapah?.vatMode || "",
    subtotal: row.subtotal || payload.draftInvoice?.subtotal || 0,
    vat: row.vat || payload.draftInvoice?.vat || 0,
    total: row.total || payload.draftInvoice?.total || 0,
    checksum: row.checksum,
    note: row.note,
