function getPilotSubsequentOngoingRenewalCloseoutPackets(db, orgId, templateKey, paymentCollectionPacketId = "") {
  const filters = ["pilot_subsequent_ongoing_renewal_closeout_packets.org_id = ?", "pilot_subsequent_ongoing_renewal_closeout_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedPaymentCollectionPacketId = String(paymentCollectionPacketId || "").trim();
  if (requestedPaymentCollectionPacketId) {
    filters.push("pilot_subsequent_ongoing_renewal_closeout_packets.subsequent_ongoing_renewal_payment_collection_packet_id = ?");
    params.push(requestedPaymentCollectionPacketId);
  }
  return db.prepare(`
    SELECT pilot_subsequent_ongoing_renewal_closeout_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_subsequent_ongoing_renewal_closeout_packets
    JOIN customers ON customers.id = pilot_subsequent_ongoing_renewal_closeout_packets.customer_id
    LEFT JOIN users ON users.id = pilot_subsequent_ongoing_renewal_closeout_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_subsequent_ongoing_renewal_closeout_packets.created_at DESC
  `).all(...params).map(row => formatPilotSubsequentOngoingRenewalCloseoutPacket(row, false));
}

function getPilotSubsequentOngoingRenewalCloseoutPacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_subsequent_ongoing_renewal_closeout_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_subsequent_ongoing_renewal_closeout_packets
    JOIN customers ON customers.id = pilot_subsequent_ongoing_renewal_closeout_packets.customer_id
    LEFT JOIN users ON users.id = pilot_subsequent_ongoing_renewal_closeout_packets.created_by_user_id
    WHERE pilot_subsequent_ongoing_renewal_closeout_packets.org_id = ? AND pilot_subsequent_ongoing_renewal_closeout_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotSubsequentOngoingRenewalCloseoutPacket(row, includePayload) : null;
}

