    nextRecurringOngoingRenewalDueDate: row.next_recurring_ongoing_renewal_due_date || payload.nextRecurringOngoingRenewalTask?.dueDate,
    status: row.status,
    periodKey: row.period_key || payload.payment?.periodKey || "",
    vatMode: row.vat_mode || payload.hayhashvapah?.vatMode || "",
    subtotal: row.subtotal || payload.hayhashvapah?.subtotal || 0,
    vat: row.vat || payload.invoice?.vat || 0,
    amount: row.amount || payload.payment?.amount || 0,
    checksum: row.checksum,
    note: row.note,
    createdByUserId: row.created_by_user_id,
    createdByName: row.created_by_name,
    createdAt: row.created_at,
