function getPilotNextRecurringOngoingRenewalQuoteReleasePackets(db, orgId, templateKey, nextRecurringOngoingRenewalHandoffId = "") {
  const filters = ["pilot_next_recurring_ongoing_renewal_quote_release_packets.org_id = ?", "pilot_next_recurring_ongoing_renewal_quote_release_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedHandoffId = String(nextRecurringOngoingRenewalHandoffId || "").trim();
  if (requestedHandoffId) {
    filters.push("pilot_next_recurring_ongoing_renewal_quote_release_packets.next_recurring_ongoing_renewal_quote_handoff_id = ?");
    params.push(requestedHandoffId);
  }
  return db.prepare(`
    SELECT pilot_next_recurring_ongoing_renewal_quote_release_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_recurring_ongoing_renewal_quote_release_packets
    JOIN customers ON customers.id = pilot_next_recurring_ongoing_renewal_quote_release_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_recurring_ongoing_renewal_quote_release_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_next_recurring_ongoing_renewal_quote_release_packets.created_at DESC
  `).all(...params).map(row => formatPilotNextRecurringOngoingRenewalQuoteReleasePacket(row, false));
}

function getPilotNextRecurringOngoingRenewalQuoteReleasePacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_next_recurring_ongoing_renewal_quote_release_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_recurring_ongoing_renewal_quote_release_packets
    JOIN customers ON customers.id = pilot_next_recurring_ongoing_renewal_quote_release_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_recurring_ongoing_renewal_quote_release_packets.created_by_user_id
    WHERE pilot_next_recurring_ongoing_renewal_quote_release_packets.org_id = ? AND pilot_next_recurring_ongoing_renewal_quote_release_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotNextRecurringOngoingRenewalQuoteReleasePacket(row, includePayload) : null;
}

