function getPilotNextRecurringOngoingRenewalQuoteAcceptanceHandoffPackets(db, orgId, templateKey, releasePacketId = "") {
  const filters = ["pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.org_id = ?", "pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedReleasePacketId = String(releasePacketId || "").trim();
  if (requestedReleasePacketId) {
    filters.push("pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.next_recurring_ongoing_renewal_quote_release_packet_id = ?");
    params.push(requestedReleasePacketId);
  }
  return db.prepare(`
    SELECT pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets
    JOIN customers ON customers.id = pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.created_at DESC
  `).all(...params).map(row => formatPilotNextRecurringOngoingRenewalQuoteAcceptanceHandoffPacket(row, false));
}

function getPilotNextRecurringOngoingRenewalQuoteAcceptanceHandoffPacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets
    JOIN customers ON customers.id = pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.created_by_user_id
    WHERE pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.org_id = ? AND pilot_next_recurring_ongoing_renewal_quote_acceptance_handoff_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotNextRecurringOngoingRenewalQuoteAcceptanceHandoffPacket(row, includePayload) : null;
}

