function getPilotNextRecurringOngoingRenewalHayhashvapahDraftInvoicePackets(db, orgId, templateKey, nextRecurringOngoingRenewalAcceptanceHandoffId = "") {
  const filters = ["pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.org_id = ?", "pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.template_key = ?"];
  const params = [orgId, templateKey];
  const requestedHandoffId = String(nextRecurringOngoingRenewalAcceptanceHandoffId || "").trim();
  if (requestedHandoffId) {
    filters.push("pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.next_recurring_ongoing_renewal_acceptance_handoff_id = ?");
    params.push(requestedHandoffId);
  }
  return db.prepare(`
    SELECT pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets
    JOIN customers ON customers.id = pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.created_by_user_id
    WHERE ${filters.join(" AND ")}
    ORDER BY pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.created_at DESC
  `).all(...params).map(row => formatPilotNextRecurringOngoingRenewalHayhashvapahDraftInvoicePacket(row, false));
}

function getPilotNextRecurringOngoingRenewalHayhashvapahDraftInvoicePacket(db, orgId, packetId, includePayload = false) {
  const row = db.prepare(`
    SELECT pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.*, customers.name AS customer_name, users.name AS created_by_name
    FROM pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets
    JOIN customers ON customers.id = pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.customer_id
    LEFT JOIN users ON users.id = pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.created_by_user_id
    WHERE pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.org_id = ? AND pilot_next_recurring_ongoing_renewal_hayhashvapah_draft_invoice_packets.id = ?
  `).get(orgId, packetId);
  return row ? formatPilotNextRecurringOngoingRenewalHayhashvapahDraftInvoicePacket(row, includePayload) : null;
}

