    followingOngoingRenewalPostingPacketId: row.following_ongoing_renewal_posting_packet_id,
    followingOngoingRenewalDraftPacketId: row.following_ongoing_renewal_draft_packet_id,
    followingOngoingRenewalAcceptanceHandoffId: row.following_ongoing_renewal_acceptance_handoff_id,
    followingOngoingRenewalQuoteReleasePacketId: row.following_ongoing_renewal_quote_release_packet_id,
