function getRoleDashboard(db, user) {
  const config = ROLE_DASHBOARD_CONFIGS[user.role] || ROLE_DASHBOARD_CONFIGS.Operator;
  const apps = getAssignedApps(db, user.org_id, user.role).map(app => ({
    id: app.id,
    name: app.name,
    category: app.category
  }));
  const semantic = getSemanticMetrics(db, user.org_id, user);
  const metricsById = new Map(semantic.metrics.map(metric => [metric.id, metric]));
  const primaryMetrics = config.metricIds.map(metricId => metricsById.get(metricId)).filter(Boolean);
  const permissions = roleDashboardPermissions(db, user, apps.map(app => app.id));
  const reports = permissions.canReadReports ? getAnalyticsReportPackets(db, user).slice(0, 4) : [];
  const snapshots = permissions.canUseAnalyticsApp
    ? getSemanticMetricSnapshots(db, user.org_id, {}).series
      .filter(series => config.metricIds.includes(series.metricId))
      .slice(0, 4)
    : [];

  return {
    role: user.role,
    dashboardId: config.dashboardId,
    title: config.title,
    generatedAt: new Date().toISOString(),
    apps,
    semanticLayerVersion: semantic.semanticLayerVersion,
    primaryMetricIds: primaryMetrics.map(metric => metric.id),
    summaryCards: primaryMetrics.map(metric => roleDashboardMetricCard(metric)),
    snapshots,
    reports,
    permissions,
    nextActions: config.nextActions.map(([actionKey, label, description]) => ({ actionKey, label, description }))
  };
}

function roleDashboardPermissions(db, user, appIds) {
  return {
    canUseAnalyticsApp: appIds.includes("analytics"),
    canUseFinanceApp: appIds.includes("finance"),
    canUseDeskApp: appIds.includes("desk"),
    canCaptureSnapshots: ["Owner", "Admin", "Accountant"].includes(user.role),
    canCreateOwnerReport: ["Owner", "Admin"].includes(user.role),
    canCreateAccountantReport: ["Owner", "Admin", "Accountant"].includes(user.role),
    canReadReports: visibleAnalyticsReportTypes(user).length > 0,
    canViewSensitiveFinance: hasAppAccess(db, user, "finance")
  };
}

function roleDashboardMetricCard(metric) {
  return {
    metricId: metric.id,
    label: metric.label,
    value: metric.value,
    unit: metric.unit,
    recordCount: metric.recordCount,
    sourceApps: metric.sourceApps,
    formula: metric.formula,
    definition: metric.definition,
    drilldownUrl: metric.drilldownUrl,
    ownerRole: metric.ownerRole
  };
}

function captureSemanticMetricSnapshots(db, user, body) {
  const input = normalizeAnalyticsSnapshotCaptureBody(body);
  const { reportDate, note } = input;
  const capturedAt = new Date().toISOString();
  const semanticMetrics = getSemanticMetrics(db, user.org_id, user, reportDate);
  const insertSnapshot = db.prepare(`
    INSERT INTO analytics_metric_snapshots (
      id, org_id, metric_id, metric_label, metric_unit, metric_value,
      record_count, report_date, semantic_layer_version, source_apps,
      formula, definition, checksum, note, captured_by_user_id, captured_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(org_id, metric_id, report_date) DO UPDATE SET
      metric_label = excluded.metric_label,
      metric_unit = excluded.metric_unit,
      metric_value = excluded.metric_value,
      record_count = excluded.record_count,
      semantic_layer_version = excluded.semantic_layer_version,
      source_apps = excluded.source_apps,
      formula = excluded.formula,
      definition = excluded.definition,
      checksum = excluded.checksum,
      note = excluded.note,
      captured_by_user_id = excluded.captured_by_user_id,
      captured_at = excluded.captured_at
  `);
  let createdCount = 0;
  let updatedCount = 0;

  for (const metric of semanticMetrics.metrics) {
    const existing = db.prepare(`
      SELECT id
      FROM analytics_metric_snapshots
      WHERE org_id = ? AND metric_id = ? AND report_date = ?
    `).get(user.org_id, metric.id, reportDate);
    const snapshotId = existing?.id || randomId("metric-snapshot");
    const checksumPayload = {
      orgId: user.org_id,
      metricId: metric.id,
      value: metric.value,
      unit: metric.unit,
      recordCount: metric.recordCount,
      reportDate,
      semanticLayerVersion: semanticMetrics.semanticLayerVersion,
      sourceApps: metric.sourceApps,
      formula: metric.formula,
      definition: metric.definition
    };
    const checksum = crypto.createHash("sha256").update(JSON.stringify(checksumPayload)).digest("hex");
    insertSnapshot.run(
      snapshotId,
      user.org_id,
      metric.id,
      metric.label,
      metric.unit,
      metric.value,
      metric.recordCount,
      reportDate,
      semanticMetrics.semanticLayerVersion,
      JSON.stringify(metric.sourceApps),
      metric.formula,
      metric.definition,
      checksum,
      note,
      user.id,
      capturedAt
    );
    if (existing) updatedCount += 1;
    else createdCount += 1;
  }

  const snapshots = getSemanticMetricSnapshotRows(db, user.org_id, { reportDate });
  const runPayload = {
    reportDate,
    metricCount: snapshots.length,
    createdCount,
    updatedCount,
    semanticLayerVersion: semanticMetrics.semanticLayerVersion,
    snapshotChecksums: snapshots.map(snapshot => snapshot.checksum)
  };
  const checksum = crypto.createHash("sha256").update(JSON.stringify(runPayload)).digest("hex");
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "analytics.semantic_snapshot.captured",
    subjectType: "analytics_metric_snapshot",
    subjectId: reportDate,
    status: "captured",
    payload: { ...runPayload, checksum }
  });
  audit(db, user.org_id, user.id, "analytics.semantic_snapshot.captured", {
    reportDate,
    metricCount: snapshots.length,
    createdCount,
    updatedCount,
    checksum
  });

  return {
    ok: true,
    snapshotRun: {
      ...runPayload,
      checksum,
      capturedAt,
      capturedByUserId: user.id,
      note
    },
    snapshots
  };
}

function getSemanticMetricSnapshots(db, orgId, query = {}) {
  const filters = normalizeAnalyticsSnapshotQuery(query);
  const snapshots = getSemanticMetricSnapshotRows(db, orgId, filters);
  return {
    semanticLayerVersion: snapshots[0]?.semanticLayerVersion || SEMANTIC_LAYER_VERSION,
    snapshots,
    series: buildSemanticSnapshotSeries(snapshots)
  };
}

function normalizeAnalyticsSnapshotQuery(query) {
  if (!isPlainObject(query)) {
    throwInvalidAnalyticsMetadata();
  }
  return {
    metricId: normalizeAnalyticsQueryText(query, "metricId", { maxLength: 120 }),
    reportDate: normalizeAnalyticsQueryDate(query, "reportDate"),
    from: normalizeAnalyticsQueryDate(query, "from"),
    to: normalizeAnalyticsQueryDate(query, "to")
  };
}

function normalizeAnalyticsQueryText(query, field, options = {}) {
  const { maxLength = 120 } = options;
  const value = Object.prototype.hasOwnProperty.call(query, field) ? query[field] : undefined;
  if (value === undefined || value === "") return "";
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidAnalyticsMetadata();
  }
  const text = value.trim();
  if (text.length > maxLength) {
    throwInvalidAnalyticsMetadata();
  }
  return text;
}

function normalizeAnalyticsPathId(value) {
  if (typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidAnalyticsPathId();
  }
  const id = value.trim();
  if (!id || id.length > 160 || !/^[a-z0-9-]+$/.test(id)) {
    throwInvalidAnalyticsPathId();
  }
  return id;
}

function throwInvalidAnalyticsPathId() {
  const err = new Error("Invalid analytics path id");
  err.statusCode = 400;
  throw err;
}

function normalizeAnalyticsQueryDate(query, field) {
  const value = Object.prototype.hasOwnProperty.call(query, field) ? query[field] : undefined;
  if (value === undefined || value === "") return "";
  return normalizeSnapshotReportDate(value);
}

function normalizeAnalyticsAsOfQuery(query, fallback) {
  if (!isPlainObject(query)) {
    throwInvalidAnalyticsMetadata();
  }
  const value = Object.prototype.hasOwnProperty.call(query, "asOf") ? query.asOf : undefined;
  if (value === undefined || value === "") return fallback;
  return normalizeSnapshotReportDate(value);
}

function getSemanticMetricSnapshotRows(db, orgId, filters = {}) {
  const params = [orgId];
  const where = ["analytics_metric_snapshots.org_id = ?"];
  if (filters.metricId) {
    where.push("analytics_metric_snapshots.metric_id = ?");
    params.push(filters.metricId);
  }
  if (filters.reportDate) {
    where.push("analytics_metric_snapshots.report_date = ?");
    params.push(filters.reportDate);
  }
  if (filters.from) {
    where.push("analytics_metric_snapshots.report_date >= ?");
    params.push(filters.from);
  }
  if (filters.to) {
    where.push("analytics_metric_snapshots.report_date <= ?");
    params.push(filters.to);
  }
  return db.prepare(`
    SELECT analytics_metric_snapshots.*, users.name AS captured_by_name
    FROM analytics_metric_snapshots
    LEFT JOIN users ON users.id = analytics_metric_snapshots.captured_by_user_id
    WHERE ${where.join(" AND ")}
    ORDER BY analytics_metric_snapshots.report_date ASC, analytics_metric_snapshots.metric_id ASC
  `).all(...params).map(formatSemanticMetricSnapshot);
}

function formatSemanticMetricSnapshot(row) {
  return {
    id: row.id,
    metricId: row.metric_id,
    label: row.metric_label,
    unit: row.metric_unit,
    value: Number(row.metric_value),
    recordCount: row.record_count,
    reportDate: row.report_date,
    semanticLayerVersion: row.semantic_layer_version,
    sourceApps: safeJson(row.source_apps),
    formula: row.formula,
    definition: row.definition,
    checksum: row.checksum,
    note: row.note,
    capturedByUserId: row.captured_by_user_id,
    capturedByName: row.captured_by_name,
    capturedAt: row.captured_at
  };
}

function buildSemanticSnapshotSeries(snapshots) {
  const byMetric = new Map();
  for (const snapshot of snapshots) {
    if (!byMetric.has(snapshot.metricId)) {
      byMetric.set(snapshot.metricId, {
        metricId: snapshot.metricId,
        label: snapshot.label,
        unit: snapshot.unit,
        sourceApps: snapshot.sourceApps,
        points: []
      });
    }
    byMetric.get(snapshot.metricId).points.push({
      reportDate: snapshot.reportDate,
      value: snapshot.value,
      recordCount: snapshot.recordCount,
      checksum: snapshot.checksum,
      capturedAt: snapshot.capturedAt
    });
  }
  return [...byMetric.values()];
}

function normalizeAnalyticsSnapshotCaptureBody(body) {
  if (!isPlainObject(body)) {
    throwInvalidAnalyticsMetadata();
  }
  return {
    reportDate: normalizeSnapshotReportDate(Object.prototype.hasOwnProperty.call(body, "reportDate") ? body.reportDate : armeniaDateString()),
    note: normalizeAnalyticsNote(body, "note")
  };
}

function normalizeSnapshotReportDate(value) {
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    const err = new Error("Report date must be YYYY-MM-DD");
    err.statusCode = 400;
    throw err;
  }
  const text = value.trim();
  if (isExactIsoDate(text)) return text;
  const err = new Error("Report date must be YYYY-MM-DD");
  err.statusCode = 400;
  throw err;
}

function createAnalyticsReportPacket(db, user, body) {
  const input = normalizeAnalyticsReportPacketBody(body);
  const { reportType, format, periodKey, note } = input;
  if (!reportType) {
    const err = new Error("Report type must be owner or accountant");
    err.statusCode = 400;
    throw err;
  }
  requireAnalyticsReportWriter(user, reportType);
  const createdAt = new Date().toISOString();
  const metricIds = ANALYTICS_REPORT_METRICS[reportType];
  const { from, to } = analyticsPeriodBounds(periodKey);
  const snapshots = getSemanticMetricSnapshotRows(db, user.org_id, { from, to })
    .filter(snapshot => metricIds.includes(snapshot.metricId));
  if (snapshots.length === 0) {
    const err = new Error("No semantic metric snapshots exist for this period");
    err.statusCode = 409;
    throw err;
  }
  const payload = buildAnalyticsReportPayload(db, user.org_id, {
    reportType,
    periodKey,
    format,
    metricIds,
    snapshots,
    createdAt
  });
  const exportContent = format === "csv" ? analyticsReportCsv(payload) : JSON.stringify(payload, null, 2);
  const checksum = crypto.createHash("sha256").update(exportContent).digest("hex");
  const reportId = randomId("analytics-report");
  const contentType = format === "csv" ? "text/csv; charset=utf-8" : "application/json; charset=utf-8";
  const fileName = `armosphera-one-${reportType}-${periodKey}.${format}`;
  db.prepare(`
    INSERT INTO analytics_report_packets (
      id, org_id, report_type, period_key, format, status, metric_count,
      snapshot_count, checksum, payload, export_content, content_type,
      file_name, note, created_by_user_id, created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    reportId,
    user.org_id,
    reportType,
    periodKey,
    format,
    "ready",
    payload.metrics.length,
    snapshots.length,
    checksum,
    JSON.stringify(payload),
    exportContent,
    contentType,
    fileName,
    note,
    user.id,
    createdAt
  );
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "analytics.report_packet.created",
    subjectType: "analytics_report_packet",
    subjectId: reportId,
    status: "ready",
    payload: { reportType, periodKey, format, metricCount: payload.metrics.length, snapshotCount: snapshots.length, checksum }
  });
  audit(db, user.org_id, user.id, "analytics.report_packet.created", {
    reportId,
    reportType,
    periodKey,
    format,
    metricCount: payload.metrics.length,
    snapshotCount: snapshots.length,
    checksum
  });
  return getAnalyticsReportPacket(db, user, reportId, true);
}

function normalizeAnalyticsReportPacketBody(body) {
  if (!isPlainObject(body)) {
    throwInvalidAnalyticsMetadata();
  }
  return {
    reportType: normalizeAnalyticsChoice(body, "reportType", ["owner", "accountant"], ""),
    format: normalizeAnalyticsChoice(body, "format", ["json", "csv"], "json"),
    periodKey: normalizeAnalyticsPeriodKey(Object.prototype.hasOwnProperty.call(body, "periodKey") ? body.periodKey : armeniaDateString().slice(0, 7)),
    note: normalizeAnalyticsNote(body, "note")
  };
}

function buildAnalyticsReportPayload(db, orgId, { reportType, periodKey, format, metricIds, snapshots, createdAt }) {
  const organization = getOrganization(db, orgId);
  const metrics = buildAnalyticsReportMetrics(snapshots, metricIds);
  const latest = Object.fromEntries(metrics.map(metric => [metric.metricId, metric.latestValue]));
  const summary = {
    periodKey,
    reportType,
    format,
    metricCount: metrics.length,
    snapshotCount: snapshots.length,
    reportingDates: unique(snapshots.map(snapshot => snapshot.reportDate)),
    highlights: reportType === "accountant"
      ? {
        receivablesAging: latest["receivables-aging"] || 0,
        overdueExposure: latest["overdue-exposure"] || 0,
        vatReadinessControls: latest["vat-readiness"] || 0
      }
      : {
        pipelineValue: latest["pipeline-value"] || 0,
        weightedForecast: latest["forecast-weighted"] || 0,
        campaignRoi: latest["campaign-roi"] || 0,
        overdueExposure: latest["overdue-exposure"] || 0,
        slaRisk: latest["sla-risk"] || 0
      }
  };
  return {
    kind: "armosphera-one-analytics-report",
    product: "Armosphera One",
    reportType,
    periodKey,
    generatedAt: createdAt,
    semanticLayerVersion: snapshots[0]?.semanticLayerVersion || SEMANTIC_LAYER_VERSION,
    organization: {
      id: organization.id,
      name: organization.name,
      legalName: organization.legal_name,
      taxId: organization.tax_id,
      locale: organization.locale,
      currency: organization.currency,
      market: organization.market
    },
    summary,
    metrics,
    controls: [
      "metric definitions preserved with formulas",
      "source applications preserved for drilldown",
      "checksum generated from exported content",
      "report packet included in tenant backup scope"
    ]
  };
}

function buildAnalyticsReportMetrics(snapshots, metricIds) {
  return metricIds.map(metricId => {
    const rows = snapshots.filter(snapshot => snapshot.metricId === metricId)
      .sort((a, b) => a.reportDate.localeCompare(b.reportDate));
    if (rows.length === 0) return null;
    const latest = rows[rows.length - 1];
    return {
      metricId,
      label: latest.label,
      unit: latest.unit,
      latestValue: latest.value,
      latestRecordCount: latest.recordCount,
      sourceApps: latest.sourceApps,
      formula: latest.formula,
      definition: latest.definition,
      pointCount: rows.length,
      points: rows.map(row => ({
        reportDate: row.reportDate,
        value: row.value,
        recordCount: row.recordCount,
        checksum: row.checksum
      }))
    };
  }).filter(Boolean);
}

function analyticsReportCsv(payload) {
  const rows = [[
    "reportType",
    "periodKey",
    "reportDate",
    "metricId",
    "label",
    "value",
    "unit",
    "recordCount",
    "sourceApps",
    "formula",
    "checksum"
  ]];
  for (const metric of payload.metrics) {
    for (const point of metric.points) {
      rows.push([
        payload.reportType,
        payload.periodKey,
        point.reportDate,
        metric.metricId,
        metric.label,
        point.value,
        metric.unit,
        point.recordCount,
        metric.sourceApps.join(" + "),
        metric.formula,
        point.checksum
      ]);
    }
  }
  return rows.map(row => row.map(csvCell).join(",")).join("\n");
}

function csvCell(value) {
  const text = String(value ?? "");
  return `"${text.replace(/"/g, "\"\"")}"`;
}

function getAnalyticsReportPackets(db, user) {
  const reportTypes = visibleAnalyticsReportTypes(user);
  if (reportTypes.length === 0) return [];
  const placeholders = reportTypes.map(() => "?").join(",");
  return db.prepare(`
    SELECT analytics_report_packets.*, users.name AS created_by_name
    FROM analytics_report_packets
    LEFT JOIN users ON users.id = analytics_report_packets.created_by_user_id
    WHERE analytics_report_packets.org_id = ?
      AND analytics_report_packets.report_type IN (${placeholders})
    ORDER BY analytics_report_packets.created_at DESC
  `).all(user.org_id, ...reportTypes).map(row => formatAnalyticsReportPacket(row, false));
}

function getAnalyticsReportPacket(db, user, reportId, includePayload = false) {
  const reportTypes = visibleAnalyticsReportTypes(user);
  if (reportTypes.length === 0) return null;
  const placeholders = reportTypes.map(() => "?").join(",");
  const row = db.prepare(`
    SELECT analytics_report_packets.*, users.name AS created_by_name
    FROM analytics_report_packets
    LEFT JOIN users ON users.id = analytics_report_packets.created_by_user_id
    WHERE analytics_report_packets.org_id = ?
      AND analytics_report_packets.id = ?
      AND analytics_report_packets.report_type IN (${placeholders})
  `).get(user.org_id, reportId, ...reportTypes);
  return row ? formatAnalyticsReportPacket(row, includePayload) : null;
}

function formatAnalyticsReportPacket(row, includePayload = false) {
  const report = {
    id: row.id,
    reportType: row.report_type,
    periodKey: row.period_key,
    format: row.format,
    status: row.status,
    metricCount: row.metric_count,
    snapshotCount: row.snapshot_count,
    checksum: row.checksum,
    contentType: row.content_type,
    fileName: row.file_name,
    note: row.note,
    createdByUserId: row.created_by_user_id,
    createdByName: row.created_by_name,
    createdAt: row.created_at
  };
  if (includePayload) {
    report.payload = safeJson(row.payload);
    report.exportContent = row.export_content;
  }
  return report;
}

function normalizeAnalyticsChoice(body, field, allowed, fallback) {
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "") return fallback;
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidAnalyticsMetadata();
  }
  const text = value.trim();
  if (!allowed.includes(text)) throwInvalidAnalyticsMetadata();
  return text;
}

function normalizeAnalyticsNote(body, field) {
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "") return "";
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidAnalyticsMetadata();
  }
  const note = value.trim();
  if (note.length > 500) {
    throwInvalidAnalyticsMetadata();
  }
  return note;
}

function normalizeAnalyticsPeriodKey(value) {
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    const err = new Error("Period key must be YYYY-MM");
    err.statusCode = 400;
    throw err;
  }
  const text = value.trim();
  const match = /^(\d{4})-(\d{2})$/.exec(text);
  if (match) {
    const month = Number(match[2]);
    if (month >= 1 && month <= 12) return text;
  }
  const err = new Error("Period key must be YYYY-MM");
  err.statusCode = 400;
  throw err;
}

function throwInvalidAnalyticsMetadata() {
  const err = new Error("Analytics request requires safe metadata");
  err.statusCode = 400;
  throw err;
}

function analyticsPeriodBounds(periodKey) {
  const [year, month] = periodKey.split("-").map(Number);
  const lastDay = new Date(Date.UTC(year, month, 0)).getUTCDate();
  return {
    from: `${periodKey}-01`,
    to: `${periodKey}-${String(lastDay).padStart(2, "0")}`
  };
}

function armeniaDateString(date = new Date()) {
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: ARMENIA_TIME_ZONE,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(date).reduce((memo, part) => {
    memo[part.type] = part.value;
    return memo;
  }, {});
  return `${parts.year}-${parts.month}-${parts.day}`;
}

function getSemanticMetricDrilldown(db, orgId, user, metricId, reportDate = DEFAULT_REPORT_DATE) {
  const metric = getSemanticMetrics(db, orgId, user, reportDate).metrics.find(item => item.id === metricId);
  if (!metric) {
    const err = new Error("Semantic metric not found");
    err.statusCode = 404;
    throw err;
  }

  const records = getSemanticMetricRecords(db, orgId, metricId, reportDate);
  return {
    semanticLayerVersion: SEMANTIC_LAYER_VERSION,
    reportDate,
    metric,
    totals: {
      recordCount: records.length,
      amdTotal: records.reduce((sum, record) => sum + Number(record.total || record.value || record.weightedValue || 0), 0)
    },
    records
  };
}

function getSemanticMetricRecords(db, orgId, metricId, reportDate = DEFAULT_REPORT_DATE) {
  if (metricId === "pipeline-value") {
    return getCrmForecastSummary(db, orgId).deals.map(deal => ({
      sourceApp: "Armosphera CRM",
      dealId: deal.id,
      customerId: deal.customerId,
      customerName: deal.customerName,
      title: deal.title,
      stage: deal.stage,
      value: deal.value,
      probability: deal.probability,
      forecastCategory: deal.forecastCategory,
      nextStep: deal.nextStep
    }));
  }

  if (metricId === "forecast-weighted") {
    return getCrmForecastSummary(db, orgId).deals.map(deal => ({
      sourceApp: "Armosphera CRM",
      dealId: deal.id,
      customerId: deal.customerId,
      customerName: deal.customerName,
      title: deal.title,
      value: deal.value,
      weightedValue: deal.weightedValue,
      probability: deal.probability,
      healthStatus: deal.healthStatus,
      forecastCategory: deal.forecastCategory
    }));
  }

  if (metricId === "campaign-roi") {
    return getCampaignPerformance(db, orgId).campaigns.map(campaign => ({
      sourceApp: "Campaigns",
      campaignId: campaign.id,
      name: campaign.name,
      channel: campaign.channel,
      status: campaign.status,
      spend: campaign.spend,
      paidRevenue: campaign.paidRevenue,
      roiPercent: campaign.roiPercent,
      leadCount: campaign.leadCount,
      customerCount: campaign.customerCount
    }));
  }

  if (metricId === "receivables-aging") {
    return getReceivablesAging(db, orgId, "", reportDate).invoices.map(formatSemanticInvoiceRecord);
  }

  if (metricId === "overdue-exposure") {
    return getReceivablesAging(db, orgId, "", reportDate).invoices
      .filter(invoice => invoice.daysPastDue > 0)
      .map(formatSemanticInvoiceRecord);
  }

  if (metricId === "ticket-backlog") {
    return getServiceCases(db, orgId)
      .filter(serviceCase => serviceCase.status !== "closed")
      .map(formatSemanticServiceCaseRecord);
  }

  if (metricId === "sla-risk") {
    return semanticSlaRiskCases(getServiceCases(db, orgId)).map(formatSemanticServiceCaseRecord);
  }

  if (metricId === "vat-readiness") {
    return semanticVatReadinessItems(db, orgId).map(item => ({
      sourceApp: item.sourceApp,
      key: item.key,
      label: item.label,
      status: item.status,
      effectiveDate: item.effectiveDate || null
    }));
  }

  return [];
}

function formatSemanticInvoiceRecord(invoice) {
  return {
    sourceApp: "HayHashvapah Finance",
    invoiceId: invoice.id,
    invoiceNumber: invoice.number,
    customerId: invoice.customerId,
    customerName: invoice.customerName,
    total: invoice.total,
    vat: invoice.vat,
    dueDate: invoice.dueDate,
    daysPastDue: invoice.daysPastDue,
    bucket: invoice.bucket,
    bucketLabel: invoice.bucketLabel,
    nextAction: invoice.nextAction
  };
}

function formatSemanticServiceCaseRecord(serviceCase) {
  return {
    sourceApp: "Armosphera Desk",
    caseId: serviceCase.id,
    caseNumber: serviceCase.caseNumber,
    customerId: serviceCase.customerId,
    customerName: serviceCase.customerName,
    subject: serviceCase.subject,
    status: serviceCase.status,
    priority: serviceCase.priority,
    channel: serviceCase.channel,
    slaStatus: serviceCase.slaStatus,
    knowledgeArticle: serviceCase.knowledgeArticle,
    nextAction: serviceCase.aiSuggestion || "Review queue owner and customer response before SLA breach"
  };
}

function semanticSlaRiskCases(serviceCases) {
  return serviceCases.filter(serviceCase => serviceCase.status !== "closed" && serviceCase.slaStatus === "at-risk");
}

function semanticVatReadinessItems(db, orgId, localizationItems = localizationChecklist()) {
  const taxKeys = new Set(["tax-id", "vat-20", "src"]);
  const localizationControls = localizationItems
    .filter(item => taxKeys.has(item.key))
    .map(item => ({ ...item, sourceApp: "Armenian localization" }));
  const legalControls = getLegalSources(db, orgId)
    .filter(source => /vat|tax|src|հվհհ|invoice/i.test(`${source.title} ${source.jurisdiction}`))
    .filter(source => ["active", "needs-accountant-review", "needs-lawyer-review"].includes(source.status))
    .map(source => ({
      key: source.id,
      label: source.title,
      status: source.status,
      effectiveDate: source.effectiveDate,
      sourceApp: "Legal database"
    }));
  return [...localizationControls, ...legalControls];
}

function emptyReceivableBuckets() {
  return [
    { key: "current", label: "Current", total: 0, invoiceCount: 0, customers: [], invoices: [] },
    { key: "1-30", label: "1-30 days", total: 0, invoiceCount: 0, customers: [], invoices: [] },
    { key: "31-60", label: "31-60 days", total: 0, invoiceCount: 0, customers: [], invoices: [] },
    { key: "61-90", label: "61-90 days", total: 0, invoiceCount: 0, customers: [], invoices: [] },
    { key: "90+", label: "90+ days", total: 0, invoiceCount: 0, customers: [], invoices: [] }
  ];
}

function formatReceivableInvoice(row, reportDate) {
  const daysPastDue = Math.max(0, daysBetween(row.due_date, reportDate));
  const bucket = receivableBucket(daysPastDue);
  return {
    id: row.id,
    number: row.number,
    status: row.status,
    customerId: row.customer_id,
    customerName: row.customer_name,
    taxId: row.customer_tax_id,
    total: row.total,
    vat: row.vat,
    dueDate: row.due_date,
    daysPastDue,
    bucket,
    bucketLabel: receivableBucketLabel(bucket),
    sourceSystem: "HayHashvapah",
    nextAction: bucket === "current"
      ? "Monitor due date and confirm payment channel"
      : "Create CRM collection task and attach HayHashvapah receivable context"
  };
}

function receivableBucket(daysPastDue) {
  if (daysPastDue <= 0) return "current";
  if (daysPastDue <= 30) return "1-30";
  if (daysPastDue <= 60) return "31-60";
  if (daysPastDue <= 90) return "61-90";
  return "90+";
}

function receivableBucketLabel(bucket) {
  const labels = {
    current: "Current",
    "1-30": "1-30 days",
    "31-60": "31-60 days",
    "61-90": "61-90 days",
    "90+": "90+ days"
  };
  return labels[bucket] || bucket;
}

function daysBetween(startDate, endDate) {
  const start = Date.parse(`${startDate}T00:00:00.000Z`);
  const end = Date.parse(`${endDate}T00:00:00.000Z`);
  return Math.floor((end - start) / (24 * 60 * 60 * 1000));
}

function updateCrmDealForecast(db, user, dealId, body) {
  const deal = getDeal(db, user.org_id, dealId);
  if (!deal) {
    const err = new Error("Deal not found");
    err.statusCode = 404;
    throw err;
  }
  const { forecastCategory, closeDate, managerNote } = normalizeCrmDealForecastInput(body);
  const weightedValue = Math.round(Number(deal.value || 0) * Number(deal.probability || 0) / 100);
  const health = calculateDealHealth(db, user.org_id, deal, { forecastCategory, closeDate, managerNote });
  const now = new Date().toISOString();
  const existing = getCrmDealForecast(db, user.org_id, deal.id);
  const forecastId = existing?.id || randomId("deal-forecast");

  db.prepare(`
    INSERT INTO crm_deal_forecasts (
      id, org_id, deal_id, forecast_category, close_date, weighted_value,
      health_score, health_status, health_reasons, manager_note,
      updated_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(org_id, deal_id) DO UPDATE SET
      forecast_category = excluded.forecast_category,
      close_date = excluded.close_date,
      weighted_value = excluded.weighted_value,
      health_score = excluded.health_score,
      health_status = excluded.health_status,
      health_reasons = excluded.health_reasons,
      manager_note = excluded.manager_note,
      updated_by_user_id = excluded.updated_by_user_id,
      updated_at = excluded.updated_at
  `).run(
    forecastId,
    user.org_id,
    deal.id,
    forecastCategory,
    closeDate,
    weightedValue,
    health.score,
    health.status,
    JSON.stringify(health.reasons),
    managerNote,
    user.id,
    existing?.createdAt || now,
    now
  );

  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "crm.deal.forecast_updated",
    subjectType: "deal",
    subjectId: deal.id,
    customerId: deal.customerId,
    status: health.status,
    payload: { forecastCategory, weightedValue, healthScore: health.score, closeDate }
  });
  audit(db, user.org_id, user.id, "crm.deal.forecast.updated", {
    dealId: deal.id,
    forecastCategory,
    weightedValue,
    healthStatus: health.status
  });
  return getCrmDealForecast(db, user.org_id, deal.id);
}

function normalizeCrmDealForecastInput(body) {
  if (!isPlainObject(body)) {
    throwInvalidCrmDealForecastMetadata();
  }
  return {
    forecastCategory: normalizeCrmDealForecastChoice(body, "forecastCategory", ["pipeline", "best_case", "commit", "omitted"]),
    closeDate: normalizeCrmDealForecastDate(body, "closeDate"),
    managerNote: normalizeCrmDealForecastText(body, "managerNote", { minLength: 10, maxLength: 1000 })
  };
}

function normalizeCrmDealForecastChoice(body, field, choices) {
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "" || value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCrmDealForecastMetadata("Forecast category, close date, and manager note are required");
  }
  const text = value.trim();
  if (!choices.includes(text)) {
    throwInvalidCrmDealForecastMetadata("Forecast category, close date, and manager note are required");
  }
  return text;
}

function normalizeCrmDealForecastDate(body, field) {
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "" || value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCrmDealForecastMetadata("Forecast category, close date, and manager note are required");
  }
  const text = value.trim();
  if (!isExactIsoDate(text)) {
    throwInvalidCrmDealForecastMetadata("Forecast category, close date, and manager note are required");
  }
  return text;
}

function normalizeCrmDealForecastText(body, field, options = {}) {
  const { minLength = 0, maxLength = 1000 } = options;
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "" || value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCrmDealForecastMetadata("Forecast category, close date, and manager note are required");
  }
  const text = value.trim();
  if (text.length < minLength || text.length > maxLength) {
    throwInvalidCrmDealForecastMetadata("Forecast category, close date, and manager note are required");
  }
  return text;
}

function throwInvalidCrmDealForecastMetadata(message = "Deal forecast requires safe metadata") {
  const err = new Error(message);
  err.statusCode = 400;
  throw err;
}

function calculateDealHealth(db, orgId, deal, forecast) {
  let score = 35;
  const reasons = [];
  if (forecast.forecastCategory === "commit") {
    score += 25;
    reasons.push("commit-category");
  } else if (forecast.forecastCategory === "best_case") {
    score += 15;
    reasons.push("best-case-category");
  }
  const quote = db.prepare(`
    SELECT id, status
    FROM quotes
    WHERE org_id = ? AND deal_id = ? AND status IN ('sent', 'accepted')
    ORDER BY created_at DESC
    LIMIT 1
  `).get(orgId, deal.id);
  if (quote) {
    score += 15;
    reasons.push(quote.status === "accepted" ? "quote-accepted" : "quote-sent");
  }
  const note = `${forecast.managerNote} ${deal.nextStep}`;
  if (/(hayhashvapah|invoice|vat|հաշվ|հարկ|էլեկտրոնային)/i.test(note)) {
    score += 15;
    reasons.push("hayhashvapah-handoff-ready");
  }
  const closeTime = new Date(`${forecast.closeDate}T00:00:00.000Z`).getTime();
  const now = Date.now();
  if (Number.isFinite(closeTime) && closeTime >= now && closeTime <= now + 1000 * 60 * 60 * 24 * 120) {
    score += 10;
    reasons.push("close-date-current");
  } else {
    reasons.push("close-date-risk");
  }
  if (deal.probability >= 70) {
    score += 5;
    reasons.push("probability-aligned");
  }
  const normalizedScore = Math.min(100, score);
  return {
    score: normalizedScore,
    status: normalizedScore >= 80 ? "healthy" : normalizedScore >= 60 ? "watch" : "at-risk",
    reasons
  };
}

function getCrmDeals(db, orgId, customerId = "") {
  const params = [orgId];
  let where = "WHERE deals.org_id = ?";
  if (customerId) {
    where += " AND deals.customer_id = ?";
    params.push(customerId);
  }
  return db.prepare(`
    SELECT deals.*, customers.name AS customer_name,
      crm_deal_forecasts.id AS forecast_id,
      crm_deal_forecasts.forecast_category,
      crm_deal_forecasts.close_date,
      crm_deal_forecasts.weighted_value,
      crm_deal_forecasts.health_score,
      crm_deal_forecasts.health_status,
      crm_deal_forecasts.health_reasons,
      crm_deal_forecasts.manager_note,
      crm_deal_forecasts.updated_at AS forecast_updated_at
    FROM deals
    JOIN customers ON customers.id = deals.customer_id
    LEFT JOIN crm_deal_forecasts
      ON crm_deal_forecasts.org_id = deals.org_id
      AND crm_deal_forecasts.deal_id = deals.id
    ${where}
    ORDER BY deals.value DESC
  `).all(...params).map(formatCrmDeal);
}

function formatCrmDeal(row) {
  const fallbackCategory = row.stage === "Won" ? "closed_won" : "pipeline";
  const weightedValue = row.weighted_value ?? Math.round(Number(row.value || 0) * Number(row.probability || 0) / 100);
  return {
    id: row.id,
    customerId: row.customer_id,
    customerName: row.customer_name,
    title: row.title,
    stage: row.stage,
    value: row.value,
    currency: row.currency,
    probability: row.probability,
    nextStep: row.next_step,
    forecastId: row.forecast_id || null,
    forecastCategory: row.forecast_category || fallbackCategory,
    closeDate: row.close_date || null,
    weightedValue,
    healthScore: row.health_score ?? null,
    healthStatus: row.health_status || "unreviewed",
    healthReasons: row.health_reasons ? safeJson(row.health_reasons) : [],
    managerNote: row.manager_note || "",
    forecastUpdatedAt: row.forecast_updated_at || null
  };
}

function getCrmDealForecast(db, orgId, dealId) {
  const row = db.prepare(`
    SELECT crm_deal_forecasts.*, deals.customer_id, deals.title, deals.value, deals.currency,
      deals.probability, users.name AS updated_by_name
    FROM crm_deal_forecasts
    JOIN deals ON deals.id = crm_deal_forecasts.deal_id
    LEFT JOIN users ON users.id = crm_deal_forecasts.updated_by_user_id
    WHERE crm_deal_forecasts.org_id = ? AND crm_deal_forecasts.deal_id = ?
  `).get(orgId, dealId);
  return row ? formatCrmDealForecast(row) : null;
}

function formatCrmDealForecast(row) {
  return {
    id: row.id,
    dealId: row.deal_id,
    customerId: row.customer_id,
    dealTitle: row.title,
    value: row.value,
    currency: row.currency,
    probability: row.probability,
    forecastCategory: row.forecast_category,
    closeDate: row.close_date,
    weightedValue: row.weighted_value,
    healthScore: row.health_score,
    healthStatus: row.health_status,
    healthReasons: safeJson(row.health_reasons),
    managerNote: row.manager_note,
    updatedByName: row.updated_by_name,
    createdAt: row.created_at,
    updatedAt: row.updated_at
  };
}

function getCrmForecastSummary(db, orgId, user = null) {
  const deals = getCrmDeals(db, orgId).filter(deal => deal.stage !== "Won");
  const categoryMap = new Map();
  for (const deal of deals) {
    const key = deal.forecastCategory || "pipeline";
    const current = categoryMap.get(key) || { forecastCategory: key, count: 0, value: 0, weightedValue: 0 };
    current.count += 1;
    current.value += Number(deal.value || 0);
    current.weightedValue += Number(deal.weightedValue || 0);
    categoryMap.set(key, current);
  }
  return {
    categories: [...categoryMap.values()].sort((a, b) => b.weightedValue - a.weightedValue),
    deals,
    dealRiskBriefs: user && ["Owner", "Admin", "Salesperson"].includes(user.role) ? getAiDealRiskBriefs(db, orgId) : [],
    totals: {
      value: deals.reduce((sum, deal) => sum + Number(deal.value || 0), 0),
      weightedValue: deals.reduce((sum, deal) => sum + Number(deal.weightedValue || 0), 0),
      atRisk: deals.filter(deal => deal.healthStatus === "at-risk").length,
      unreviewed: deals.filter(deal => deal.healthStatus === "unreviewed").length
    }
  };
}

function convertCrmLead(db, user, leadId, body) {
  const lead = getCrmLead(db, user.org_id, leadId);
  if (!lead) {
    const err = new Error("Lead not found");
    err.statusCode = 404;
    throw err;
  }
  if (lead.status === "converted" && lead.convertedCustomerId && lead.convertedDealId) {
    return {
      lead,
      customer: db.prepare("SELECT * FROM customers WHERE org_id = ? AND id = ?").get(user.org_id, lead.convertedCustomerId),
      deal: db.prepare("SELECT * FROM deals WHERE org_id = ? AND id = ?").get(user.org_id, lead.convertedDealId),
      activity: getCrmLeadConversionActivity(db, user.org_id, lead.id)
    };
  }

  const now = new Date().toISOString();
  const today = now.slice(0, 10);
  const customerId = randomId("cust");
  const dealId = randomId("deal");
  const activityId = randomId("crm-activity");
  const conversionInput = normalizeCrmLeadConversionInput(body, lead);
  const { forecastCategory, dealTitle, nextStep } = conversionInput;
  const probability = forecastCategory === "commit" ? 75 : forecastCategory === "best_case" ? 55 : 35;

  db.prepare(`
    INSERT INTO customers (
      id, org_id, name, tax_id, email, phone, segment, health_score,
      lifetime_value, open_receivables, last_touch
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    customerId,
    user.org_id,
    lead.companyName,
    lead.taxId,
    lead.email,
    lead.phone,
    lead.segment,
    Math.min(95, Math.max(55, 55 + Math.round(lead.score / 3))),
    0,
    0,
    today
  );

  const profileId = randomId("profile");
  db.prepare(`
    INSERT INTO customer_profiles (
      id, org_id, customer_id, display_name, tax_id, data_quality_score,
      consent_status, processing_purpose, merge_status, owner_user_id, last_event_at, created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    profileId,
    user.org_id,
    customerId,
    lead.companyName,
    lead.taxId,
    Math.min(96, Math.max(70, lead.score)),
    lead.consentStatus,
    "sales-service-finance",
    "canonical",
    user.id,
    today,
    now
  );

  const sourceRows = [
    ["crm", "lead", lead.id, lead.taxId ? `tin:${lead.taxId}` : `email:${lead.email}`, 94, 1],
    ["campaigns", "consent", `lead-consent-${lead.id}`, `email:${lead.email}`, /recorded/i.test(lead.consentStatus) ? 88 : 55, 0]
  ];
  const insertSource = db.prepare(`
    INSERT INTO customer_profile_sources (
      id, org_id, profile_id, source_app, source_entity_type, source_entity_id,
      match_key, confidence, authoritative, last_synced_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `);
  for (const [sourceApp, entityType, entityId, matchKey, confidence, authoritative] of sourceRows) {
    insertSource.run(
      randomId("profile-source"),
      user.org_id,
      profileId,
      sourceApp,
      entityType,
      entityId,
      matchKey,
      confidence,
      authoritative,
      now
    );
  }

  db.prepare(`
    INSERT INTO deals (id, org_id, customer_id, title, stage, value, currency, probability, next_step)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(dealId, user.org_id, customerId, dealTitle, "Qualified", lead.estimatedValue, currencyOrActive(lead.currency), probability, nextStep);

  db.prepare(`
    INSERT INTO crm_activities (
      id, org_id, customer_id, lead_id, deal_id, kind, title, body,
      forecast_category, actor_user_id, occurred_at, created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    activityId,
    user.org_id,
    customerId,
    lead.id,
    dealId,
    "conversion",
    "Lead converted to customer and qualified deal",
    `${lead.companyName} converted from ${lead.source}/${lead.channel}. ${nextStep}`,
    forecastCategory,
    user.id,
    now,
    now
  );

  db.prepare(`
    UPDATE crm_leads
    SET status = 'converted', converted_customer_id = ?, converted_deal_id = ?,
      converted_by_user_id = ?, converted_at = ?, updated_at = ?
    WHERE org_id = ? AND id = ?
  `).run(customerId, dealId, user.id, now, now, user.org_id, lead.id);

  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "crm.lead.converted",
    subjectType: "crm_lead",
    subjectId: lead.id,
    customerId,
    status: "converted",
    payload: { dealId, score: lead.score, forecastCategory, estimatedValue: lead.estimatedValue }
  });
  audit(db, user.org_id, user.id, "crm.lead.converted", { leadId: lead.id, customerId, dealId, forecastCategory });

  return {
    lead: getCrmLead(db, user.org_id, lead.id),
    customer: db.prepare("SELECT * FROM customers WHERE org_id = ? AND id = ?").get(user.org_id, customerId),
    deal: db.prepare("SELECT * FROM deals WHERE org_id = ? AND id = ?").get(user.org_id, dealId),
    activity: getCrmActivity(db, user.org_id, activityId)
  };
}

function normalizeCrmLeadConversionInput(body, lead) {
  const input = body === undefined ? {} : body;
  if (!isPlainObject(input)) {
    throwInvalidCrmLeadConversionMetadata();
  }
  const defaultForecastCategory = lead.rating === "hot" ? "commit" : "pipeline";
  return {
    forecastCategory: normalizeCrmLeadConversionChoice(input, "forecastCategory", ["pipeline", "best_case", "commit"], defaultForecastCategory),
    dealTitle: normalizeCrmLeadConversionText(input, "dealTitle", {
      fallback: buildCrmLeadConversionDefaultDealTitle(lead),
      minLength: 2,
      maxLength: 200
    }),
    nextStep: normalizeCrmLeadConversionText(input, "nextStep", {
      fallback: lead.nextAction,
      minLength: 2,
      maxLength: 500
    })
  };
}

function buildCrmLeadConversionDefaultDealTitle(lead) {
  const suffix = " onboarding package";
  const maxLength = 200;
  const companyName = String(lead.companyName || "").trim();
  const title = `${companyName}${suffix}`;
  if (title.length <= maxLength) return title;
  const companyNameBudget = Math.max(0, maxLength - suffix.length);
  return `${companyName.slice(0, companyNameBudget).trimEnd()}${suffix}`;
}

function normalizeCrmLeadConversionChoice(body, field, choices, fallback) {
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "") return fallback;
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCrmLeadConversionMetadata();
  }
  const text = value.trim();
  if (!choices.includes(text)) {
    throwInvalidCrmLeadConversionMetadata();
  }
  return text;
}

function normalizeCrmLeadConversionText(body, field, options = {}) {
  const { fallback = "", minLength = 0, maxLength = 500 } = options;
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "") {
    const text = String(fallback || "").trim();
    if (text.length < minLength || text.length > maxLength || /[\x00-\x1f\x7f]/.test(text)) {
      throwInvalidCrmLeadConversionMetadata();
    }
    return text;
  }
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCrmLeadConversionMetadata();
  }
  const text = value.trim();
  if (text.length < minLength || text.length > maxLength) {
    throwInvalidCrmLeadConversionMetadata();
  }
  return text;
}

function throwInvalidCrmLeadConversionMetadata() {
  const err = new Error("Lead conversion requires safe metadata");
  err.statusCode = 400;
  throw err;
}

function getCrmLeadConversionActivity(db, orgId, leadId) {
  const row = db.prepare(`
    SELECT crm_activities.*, users.name AS actor_name, customers.name AS customer_name, deals.title AS deal_title
    FROM crm_activities
    LEFT JOIN users ON users.id = crm_activities.actor_user_id
    LEFT JOIN customers ON customers.id = crm_activities.customer_id
    LEFT JOIN deals ON deals.id = crm_activities.deal_id
    WHERE crm_activities.org_id = ? AND crm_activities.lead_id = ? AND crm_activities.kind = 'conversion'
    ORDER BY crm_activities.occurred_at DESC
    LIMIT 1
  `).get(orgId, leadId);
  return row ? formatCrmActivity(row) : null;
}

function createTenantBackup(db, user, body) {
  if (!isPlainObject(body)) {
    throwInvalidAdminEvidenceRequest();
  }
  const now = new Date().toISOString();
  const payload = buildTenantBackupPayload(db, user.org_id, now);
  const tableCounts = countBackupTables(payload);
  const checksum = crypto.createHash("sha256").update(JSON.stringify(payload)).digest("hex");
  const backupId = randomId("tenant-backup");
  const note = normalizeAdminEvidenceText(body, "note", { fallback: "", maxLength: 500 });
  db.prepare(`
    INSERT INTO tenant_backup_packets (
      id, org_id, status, checksum, payload, table_counts, exclusions,
      note, created_by_user_id, created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    backupId,
    user.org_id,
    "verified",
    checksum,
    JSON.stringify(payload),
    JSON.stringify(tableCounts),
    JSON.stringify(BACKUP_EXCLUSIONS),
    note,
    user.id,
    now
  );
  audit(db, user.org_id, user.id, "admin.backup.created", {
    backupId,
    checksum,
    tableCounts,
    exclusions: BACKUP_EXCLUSIONS
  });
  return getTenantBackup(db, user.org_id, backupId, true);
}

function normalizeAdminEvidenceText(body, field, options = {}) {
  const { fallback = "", required = false, minLength = 0, maxLength = 500 } = options;
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "") {
    if (required) throwInvalidAdminEvidenceRequest();
    const text = String(fallback || "").trim();
    if (text.length < minLength || text.length > maxLength || /[\x00-\x1f\x7f]/.test(text)) {
      throwInvalidAdminEvidenceRequest();
    }
    return text;
  }
  if (value === null || typeof value !== "string") {
    throwInvalidAdminEvidenceRequest();
  }
  if (/[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidAdminEvidenceRequest();
  }
  const text = value.trim();
  if (text.length < minLength || text.length > maxLength) {
    throwInvalidAdminEvidenceRequest();
  }
  return text;
}

function throwInvalidAdminEvidenceRequest() {
  const err = new Error("Admin evidence request requires safe metadata");
  err.statusCode = 400;
  throw err;
}

function buildTenantBackupPayload(db, orgId, createdAt) {
  const organization = getOrganization(db, orgId);
  const tables = {
    apps: db.prepare("SELECT id, name, category, description, route, maturity, priority FROM apps ORDER BY priority").all(),
    users: db.prepare("SELECT id, org_id, email, name, role, created_at FROM users WHERE org_id = ? ORDER BY id").all(orgId)
  };
  for (const table of ORG_BACKUP_TABLES) {
    tables[table] = loadBackupRows(db, table, orgId).map(row => sanitizeBackupRow(table, row));
  }
  return {
    kind: "armosphera-one-tenant-backup",
    product: "Armosphera One",
    schemaVersion: 1,
    createdAt,
    organization,
    exclusions: BACKUP_EXCLUSIONS,
    restorePlan: ["restore-only-into-empty-tenant", "recreate-users-with-new-passwords", "reenter-webhook-secrets"],
    tables
  };
}

function loadBackupRows(db, table, orgId) {
  const rows = db.prepare(`SELECT * FROM ${table} WHERE org_id = ? ORDER BY ${backupOrderColumn(table)}`).all(orgId);
  return table === "stock_locations" ? sortStockLocationsForRestore(rows) : rows;
}

function backupOrderColumn(table) {
  if (table === "app_assignments") return "role, app_id";
  return table === "audit_events" ? "id" : "id";
}

function sortStockLocationsForRestore(rows) {
  const byId = new Map(rows.map(row => [row.id, row]));
  const visited = new Set();
  const sorted = [];
  const visit = row => {
    if (!row || visited.has(row.id)) return;
    if (row.parent_location_id && byId.has(row.parent_location_id)) visit(byId.get(row.parent_location_id));
    visited.add(row.id);
    sorted.push(row);
  };
  for (const row of rows) visit(row);
  return sorted;
}

function sanitizeBackupRow(table, row) {
  const sanitized = {};
  for (const [key, value] of Object.entries(row)) {
    if (/(password_hash|secret|token)/i.test(key)) continue;
    sanitized[key] = value;
  }
  if (table === "webhook_endpoints") {
    sanitized.secretExcluded = true;
  }
  if (table === "user_mfa_factors") {
    sanitized.secretExcluded = true;
  }
  if (table === "integration_connectors") {
    sanitized.secretExcluded = Boolean(row.secret_hash);
    sanitized.secretFingerprint = row.secret_fingerprint || "";
  }
  return sanitized;
}

function countBackupTables(payload) {
  const counts = { organizations: payload.organization ? 1 : 0 };
  for (const [table, rows] of Object.entries(payload.tables || {})) {
    counts[table] = Array.isArray(rows) ? rows.length : 0;
  }
  return counts;
}

function getTenantBackups(db, orgId) {
  return db.prepare(`
    SELECT tenant_backup_packets.*, users.name AS created_by_name
    FROM tenant_backup_packets
    LEFT JOIN users ON users.id = tenant_backup_packets.created_by_user_id
    WHERE tenant_backup_packets.org_id = ?
    ORDER BY tenant_backup_packets.created_at DESC
  `).all(orgId).map(row => formatTenantBackup(row, false));
}

function getTenantBackup(db, orgId, backupId, includePayload = false) {
  const safeBackupId = normalizeAdminEvidencePathId(backupId, "tenant-backup", "Invalid tenant backup id");
  const row = db.prepare(`
    SELECT tenant_backup_packets.*, users.name AS created_by_name
    FROM tenant_backup_packets
    LEFT JOIN users ON users.id = tenant_backup_packets.created_by_user_id
    WHERE tenant_backup_packets.org_id = ? AND tenant_backup_packets.id = ?
  `).get(orgId, safeBackupId);
  return row ? formatTenantBackup(row, includePayload) : null;
}

function formatTenantBackup(row, includePayload) {
  const backup = {
    id: row.id,
    status: row.status,
    checksum: row.checksum,
    tableCounts: safeJson(row.table_counts),
    exclusions: safeJson(row.exclusions),
    note: row.note,
    createdByUserId: row.created_by_user_id,
    createdByName: row.created_by_name,
    createdAt: row.created_at
  };
  if (includePayload) backup.payload = safeJson(row.payload);
  return backup;
}

function verifyTenantBackupRestoreProof(db, user, backupId) {
  const backup = getTenantBackup(db, user.org_id, backupId, true);
  if (!backup) {
    const err = new Error("Backup not found");
    err.statusCode = 404;
    throw err;
  }
  const serialized = JSON.stringify(backup.payload);
  const checksum = crypto.createHash("sha256").update(serialized).digest("hex");
  const secretScan = backupSecretScan(serialized);
  const restoreProof = {
    id: randomId("restore-proof"),
    backupId: backup.id,
    status: checksum === backup.checksum && secretScan.clean ? "verified" : "blocked",
    checksumVerified: checksum === backup.checksum,
    secretScan,
    tableCounts: backup.tableCounts,
    exclusions: backup.exclusions,
    restorePlan: ["restore-only-into-empty-tenant", "rotate-user-passwords", "reenter-webhook-secrets", "verify-legal-source-effective-dates"],
    verifiedAt: new Date().toISOString()
  };
  audit(db, user.org_id, user.id, `admin.backup.restore_proof.${restoreProof.status}`, {
    backupId: backup.id,
    checksumVerified: restoreProof.checksumVerified,
    secretScan: secretScan.clean
  });
  return restoreProof;
}

function backupSecretScan(serialized) {
  const findings = [];
  for (const pattern of ["password_hash", "whsec-", "\"token\"", "public_token"]) {
    if (serialized.includes(pattern)) findings.push(pattern);
  }
  return { clean: findings.length === 0, findings };
}

function assertCustomer(db, orgId, customerId) {
  const exists = db.prepare("SELECT id FROM customers WHERE org_id = ? AND id = ?").get(orgId, customerId);
  if (!exists) {
    const err = new Error("Unknown customer");
    err.statusCode = 404;
    throw err;
  }
}

function normalizeCustomer360PathId(value, rawUrl = "") {
  const rawSegment = typeof rawUrl === "string"
    ? rawUrl.match(/^\/api\/customer-360\/([^/?#]+)(?:[?#]|$)/)?.[1]
    : "";
  if (rawSegment && (rawSegment.length > 160 || !/^[a-z0-9-]+$/.test(rawSegment))) {
    throwInvalidCustomer360PathId();
  }
  if (typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCustomer360PathId();
  }
  const customerId = value.trim();
  if (!customerId || customerId.length > 160 || !/^[a-z0-9-]+$/.test(customerId)) {
    throwInvalidCustomer360PathId();
  }
  return customerId;
}

function throwInvalidCustomer360PathId() {
  const err = new Error("Invalid customer id");
  err.statusCode = 400;
  throw err;
}

function normalizeServiceCaseCreateInput(body) {
  if (!isPlainObject(body)) {
    throwInvalidServiceMetadata();
  }
  return {
    customerId: normalizeServiceText(body, "customerId", { required: true, minLength: 1, maxLength: 120 }),
    subject: normalizeServiceText(body, "subject", { required: true, minLength: 4, maxLength: 240 }),
    priority: normalizeServiceChoice(body, "priority", ["low", "medium", "high"], "medium"),
    channel: normalizeServiceChoice(body, "channel", ["WhatsApp", "Telegram", "Email", "Phone", "Manual"], "Manual")
  };
}

function normalizeServiceReplyInput(body) {
  if (!isPlainObject(body)) {
    throwInvalidServiceMetadata();
  }
  return {
    body: normalizeServiceText(body, "body", { required: true, minLength: 3, maxLength: 4000, allowMultiline: true })
  };
}

function normalizeServiceCaseUpdateInput(body) {
  if (!isPlainObject(body)) {
    throwInvalidServiceMetadata();
  }
  const input = {};
  if (Object.prototype.hasOwnProperty.call(body, "status")) {
    input.status = normalizeServiceChoice(body, "status", ["open", "in-progress", "waiting-customer", "resolved", "closed"], "");
  }
  if (Object.prototype.hasOwnProperty.call(body, "priority")) {
    input.priority = normalizeServiceChoice(body, "priority", ["low", "medium", "high"], "");
  }
  if (Object.prototype.hasOwnProperty.call(body, "ownerUserId")) {
    input.ownerUserId = normalizeServiceText(body, "ownerUserId", { required: true, minLength: 1, maxLength: 120 });
  }
  return input;
}

function normalizeServiceEscalationInput(body) {
  if (!isPlainObject(body)) {
    throwInvalidServiceMetadata();
  }
  return {
    severity: normalizeServiceChoice(body, "severity", ["sla-risk", "customer-risk", "finance-risk"], "sla-risk"),
    reason: normalizeServiceText(body, "reason", { required: true, minLength: 12, maxLength: 1000, allowMultiline: true })
  };
}

function normalizeServiceResolutionInput(body) {
  if (!isPlainObject(body)) {
    throwInvalidServiceMetadata();
  }
  return {
    resolutionCode: normalizeServiceChoice(body, "resolutionCode", [
      "answered-with-tax-review",
      "customer-confirmed",
      "no-action-needed",
      "converted-to-change-request"
    ], "customer-confirmed"),
    summary: normalizeServiceText(body, "summary", { required: true, minLength: 20, maxLength: 2000, allowMultiline: true }),
    satisfactionScore: normalizeServiceSatisfactionScore(body),
    customerConfirmedAt: normalizeServiceTimestamp(body, "customerConfirmedAt", new Date().toISOString())
  };
}

function normalizeServiceText(body, field, options = {}) {
  const { fallback = "", required = false, minLength = 0, maxLength = 2000, allowMultiline = false } = options;
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "") {
    if (required) throwInvalidServiceMetadata();
    return fallback;
  }
  const unsafePattern = allowMultiline ? /[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]/ : /[\x00-\x1f\x7f]/;
  if (value === null || typeof value !== "string" || unsafePattern.test(value)) {
    throwInvalidServiceMetadata();
  }
  const text = value.trim();
  if (text.length < minLength || text.length > maxLength) {
    throwInvalidServiceMetadata();
  }
  return text;
}

function normalizeServiceChoice(body, field, choices, fallback) {
  const hasValue = Object.prototype.hasOwnProperty.call(body, field);
  if (!hasValue || body[field] === "") return fallback;
  const text = normalizeServiceText(body, field, { required: true, minLength: 1, maxLength: 80 });
  if (!choices.includes(text)) {
    throwInvalidServiceMetadata();
  }
  return text;
}

function normalizeServiceSatisfactionScore(body) {
  if (!Object.prototype.hasOwnProperty.call(body, "satisfactionScore") || body.satisfactionScore === null || body.satisfactionScore === "") {
    return null;
  }
  const value = body.satisfactionScore;
  if (typeof value === "string" && /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidServiceMetadata();
  }
  if (typeof value !== "number" && typeof value !== "string") {
    throwInvalidServiceMetadata();
  }
  if (typeof value === "string" && !/^[1-5]$/.test(value.trim())) {
    throwInvalidServiceMetadata();
  }
  const score = Number(value);
  if (!Number.isInteger(score) || score < 1 || score > 5) {
    throwInvalidServiceMetadata();
  }
  return score;
}

function normalizeServiceTimestamp(body, field, fallback) {
  if (!Object.prototype.hasOwnProperty.call(body, field) || body[field] === "") {
    return fallback;
  }
  const text = normalizeServiceText(body, field, { required: true, minLength: 10, maxLength: 40 });
  const parsed = new Date(text);
  if (Number.isNaN(parsed.getTime())) {
    throwInvalidServiceMetadata();
  }
  return text;
}

function throwInvalidServiceMetadata(message = "Service request requires safe metadata") {
  const err = new Error(message);
  err.statusCode = 400;
  throw err;
}

function normalizeServiceCasePathId(value) {
  if (typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidServiceCasePathId();
  }
  const text = value.trim();
  if (!text || text.length > 160 || !/^[a-z0-9-]+$/.test(text)) {
    throwInvalidServiceCasePathId();
  }
  return text;
}

function throwInvalidServiceCasePathId() {
  const err = new Error("Invalid service case id");
  err.statusCode = 400;
  throw err;
}

function normalizeAiAdvisoryInput(body, idField, promptFallback, options = {}) {
  const { promptRequired = false, promptMinLength = 0, promptMaxLength = 2000 } = options;
  if (!isPlainObject(body)) {
    throwInvalidAiAdvisoryMetadata();
  }
  return {
    id: normalizeAiAdvisoryText(body, idField, { required: true, minLength: 1, maxLength: 120 }),
    prompt: normalizeAiAdvisoryText(body, "prompt", {
      fallback: promptFallback,
      required: promptRequired,
      minLength: promptMinLength,
      maxLength: promptMaxLength
    })
  };
}

function normalizeAiAdvisoryText(body, field, options = {}) {
  const { fallback = "", required = false, minLength = 0, maxLength = 2000 } = options;
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "") {
    if (required) throwInvalidAiAdvisoryMetadata();
    return fallback;
  }
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidAiAdvisoryMetadata();
  }
  const text = value.trim();
  if (text.length < minLength || text.length > maxLength) {
    throwInvalidAiAdvisoryMetadata();
  }
  return text;
}

function throwInvalidAiAdvisoryMetadata(message = "AI advisory request requires safe metadata") {
  const err = new Error(message);
  err.statusCode = 400;
  throw err;
}

function createAiCustomerBrief(db, user, body) {
  const input = normalizeAiAdvisoryInput(body, "customerId", "Generate Customer 360 brief");
  const customerId = input.id;
  const customer = db.prepare("SELECT * FROM customers WHERE org_id = ? AND id = ?").get(user.org_id, customerId);
  if (!customer) {
    const err = new Error("Customer not found");
    err.statusCode = 404;
    throw err;
  }

  const prompt = input.prompt;
  const context = buildAiCustomerBriefContext(db, user.org_id, customer);
  const recommendedNextActions = buildAiCustomerBriefActions(customer, context);
  const groundingSources = buildAiCustomerBriefGrounding(customer, context);
  const confidence = Math.min(96, 72 + groundingSources.length * 4);
  const summary = [
    `${customer.name} is a ${customer.segment} customer with ${customer.health_score}% health and ${formatStoredMoney(customer.open_receivables || 0)} open receivables.`,
    context.primaryDeal ? `Primary CRM motion: ${context.primaryDeal.title} at ${context.primaryDeal.stage} for ${formatStoredMoney(context.primaryDeal.value)}.` : "No active CRM deal is currently prioritized.",
    context.openInvoices.length > 0 ? `HayHashvapah context: ${context.openInvoices.length} open invoice(s), including ${context.openInvoices[0].number} due ${context.openInvoices[0].due_date}.` : "HayHashvapah context: no open invoice is currently blocking the account.",
    context.atRiskCase ? `Service risk: ${context.atRiskCase.caseNumber} is ${context.atRiskCase.slaStatus} on ${context.atRiskCase.channel}.` : "Service risk: no active SLA risk detected.",
    "This brief is advisory only and does not send messages, create tasks, or change financial/legal records."
  ].join(" ");
  const now = new Date().toISOString();
  const briefId = randomId("ai-brief");
  const payloadForChecksum = {
    customerId,
    prompt,
    summary,
    recommendedNextActions,
    groundingSources,
    confidence,
    advisoryOnly: true,
    reviewRequired: false,
    modelPolicy: "deterministic-grounded-summary"
  };
  const checksum = crypto.createHash("sha256").update(JSON.stringify(payloadForChecksum)).digest("hex");

  db.prepare(`
    INSERT INTO ai_customer_briefs (
      id, org_id, customer_id, generated_by_user_id, status, prompt, summary,
      recommended_next_actions, grounding_sources, confidence, advisory_only,
      review_required, model_policy, checksum, created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    briefId,
    user.org_id,
    customerId,
    user.id,
    "generated",
    prompt,
    summary,
    JSON.stringify(recommendedNextActions),
    JSON.stringify(groundingSources),
    confidence,
    1,
    0,
    "deterministic-grounded-summary",
    checksum,
    now
  );

  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "ai.customer_brief.generated",
    subjectType: "ai_customer_brief",
    subjectId: briefId,
    customerId,
    status: "advisory",
    payload: {
      customerId,
      confidence,
      advisoryOnly: true,
      groundingSourceCount: groundingSources.length,
      checksum
    }
  });
  audit(db, user.org_id, user.id, "ai.customer_brief.generated", {
    briefId,
    customerId,
    confidence,
    advisoryOnly: true,
    groundingSourceCount: groundingSources.length,
    checksum
  });

  return { brief: getAiCustomerBrief(db, user.org_id, briefId) };
}

function buildAiCustomerBriefContext(db, orgId, customer) {
  const deals = getCrmDeals(db, orgId, customer.id);
  const openInvoices = db.prepare(`
    SELECT * FROM invoices
    WHERE org_id = ? AND customer_id = ? AND status != 'paid'
    ORDER BY due_date ASC
  `).all(orgId, customer.id);
  const serviceCases = getServiceCases(db, orgId, customer.id);
  const legalQuestions = getLegalQuestions(db, orgId, customer.id);
  return {
    deals,
    primaryDeal: deals.find(deal => deal.stage !== "Won") || deals[0] || null,
    openInvoices,
    serviceCases,
    atRiskCase: serviceCases.find(serviceCase => serviceCase.slaStatus === "at-risk" || serviceCase.priority === "high") || null,
    legalQuestions
  };
}

function buildAiCustomerBriefActions(customer, context) {
  const actions = [];
  if (context.openInvoices.length > 0) {
    actions.push(`Review HayHashvapah receivable ${context.openInvoices[0].number} before customer follow-up.`);
    actions.push("Use governed Workflow Studio approval before creating or sending collection actions.");
  }
  if (context.atRiskCase) {
    actions.push(`Resolve service blocker ${context.atRiskCase.caseNumber} before escalating commercial pressure.`);
  }
  if (context.primaryDeal) {
    actions.push(`Align next CRM step with ${context.primaryDeal.title} and keep the quote-to-invoice handoff ready.`);
  }
  if (actions.length === 0) {
    actions.push(`Prepare a localized retention check-in for ${customer.name}.`);
  }
  return actions;
}

function buildAiCustomerBriefGrounding(customer, context) {
  const sources = [
    { type: "customer_profile", id: customer.id, label: customer.name, confidence: 96 }
  ];
  if (context.primaryDeal) {
    sources.push({ type: "crm_deal", id: context.primaryDeal.id, label: context.primaryDeal.title, confidence: 90 });
  }
  for (const invoice of context.openInvoices.slice(0, 2)) {
    sources.push({ type: "finance_invoice", id: invoice.id, label: invoice.number, confidence: 92 });
  }
  if (context.atRiskCase) {
    sources.push({ type: "service_case", id: context.atRiskCase.id, label: context.atRiskCase.caseNumber, confidence: 88 });
  }
  if (context.legalQuestions[0]) {
    sources.push({ type: "legal_question", id: context.legalQuestions[0].id, label: context.legalQuestions[0].topic, confidence: 84 });
  }
  return sources;
}

function getAiCustomerBriefs(db, orgId, customerId = "") {
  const params = [orgId];
  let where = "WHERE ai_customer_briefs.org_id = ?";
  if (customerId) {
    where += " AND ai_customer_briefs.customer_id = ?";
    params.push(customerId);
  }
  return db.prepare(`
    SELECT ai_customer_briefs.*, customers.name AS customer_name, users.name AS generated_by_name
    FROM ai_customer_briefs
    JOIN customers ON customers.id = ai_customer_briefs.customer_id
    LEFT JOIN users ON users.id = ai_customer_briefs.generated_by_user_id
    ${where}
    ORDER BY ai_customer_briefs.created_at DESC
  `).all(...params).map(formatAiCustomerBrief);
}

function getAiCustomerBrief(db, orgId, briefId) {
  const row = db.prepare(`
    SELECT ai_customer_briefs.*, customers.name AS customer_name, users.name AS generated_by_name
    FROM ai_customer_briefs
    JOIN customers ON customers.id = ai_customer_briefs.customer_id
    LEFT JOIN users ON users.id = ai_customer_briefs.generated_by_user_id
    WHERE ai_customer_briefs.org_id = ? AND ai_customer_briefs.id = ?
  `).get(orgId, briefId);
  return row ? formatAiCustomerBrief(row) : null;
}

function formatAiCustomerBrief(row) {
  return {
    id: row.id,
    customerId: row.customer_id,
    customerName: row.customer_name,
    generatedByUserId: row.generated_by_user_id,
    generatedByName: row.generated_by_name,
    status: row.status,
    prompt: row.prompt,
    summary: row.summary,
    recommendedNextActions: safeJson(row.recommended_next_actions),
    groundingSources: safeJson(row.grounding_sources),
    confidence: row.confidence,
    advisoryOnly: Boolean(row.advisory_only),
    reviewRequired: Boolean(row.review_required),
    modelPolicy: row.model_policy,
    checksum: row.checksum,
    createdAt: row.created_at
  };
}

function createAiDealRiskBrief(db, user, body) {
  const input = normalizeAiAdvisoryInput(body, "dealId", "Generate deal risk brief");
  const dealId = input.id;
  const deal = getCrmDeals(db, user.org_id).find(item => item.id === dealId);
  if (!deal) {
    const err = new Error("Deal not found");
    err.statusCode = 404;
    throw err;
  }
  const customer = db.prepare("SELECT * FROM customers WHERE org_id = ? AND id = ?").get(user.org_id, deal.customerId);
  if (!customer) {
    const err = new Error("Customer not found");
    err.statusCode = 404;
    throw err;
  }

  const prompt = input.prompt;
  const context = buildAiDealRiskContext(db, user.org_id, deal, customer);
  const riskFactors = buildAiDealRiskFactors(deal, customer, context);
  const riskScore = calculateAiDealRiskScore(deal, customer, context);
  const riskLevel = riskScore >= 70 ? "high" : riskScore >= 45 ? "medium" : "low";
  const recommendedNextActions = buildAiDealRiskActions(deal, context, riskLevel);
  const groundingSources = buildAiDealRiskGrounding(deal, context);
  const confidence = Math.min(96, 70 + groundingSources.length * 5);
  const forecastLabel = context.forecast?.forecastCategory || deal.forecastCategory || "pipeline";
  const summary = [
    `${deal.title} for ${customer.name} is ${riskLevel} risk (${riskScore}/100) before the ${forecastLabel} forecast review.`,
    context.openInvoices.length > 0 ? `HayHashvapah exposure is ${formatStoredMoney(context.receivables.summary.totalOpen)} across ${context.openInvoices.length} open invoice(s).` : "HayHashvapah shows no open invoice blocker for this deal.",
    context.overdueInvoices[0] ? `Primary overdue item: ${context.overdueInvoices[0].number} is ${context.overdueInvoices[0].daysPastDue} day(s) past due.` : "No overdue invoice is currently attached to the account.",
    context.atRiskCase ? `Service blocker: ${context.atRiskCase.caseNumber} is ${context.atRiskCase.slaStatus} on ${context.atRiskCase.channel}.` : "No at-risk service case is attached to the account.",
    "This risk brief is advisory only and does not update forecasts, create tasks, send messages, or change HayHashvapah records."
  ].join(" ");
  const now = new Date().toISOString();
  const briefId = randomId("ai-deal-risk");
  const payloadForChecksum = {
    dealId,
    customerId: customer.id,
    prompt,
    summary,
    riskLevel,
    riskScore,
    riskFactors,
    recommendedNextActions,
    groundingSources,
    confidence,
    advisoryOnly: true,
    reviewRequired: false,
    modelPolicy: "deterministic-grounded-deal-risk"
  };
  const checksum = crypto.createHash("sha256").update(JSON.stringify(payloadForChecksum)).digest("hex");

  db.prepare(`
    INSERT INTO ai_deal_risk_briefs (
      id, org_id, deal_id, customer_id, generated_by_user_id, status, prompt,
      summary, risk_level, risk_score, risk_factors, recommended_next_actions,
      grounding_sources, confidence, advisory_only, review_required,
      model_policy, checksum, created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    briefId,
    user.org_id,
    dealId,
    customer.id,
    user.id,
    "generated",
    prompt,
    summary,
    riskLevel,
    riskScore,
    JSON.stringify(riskFactors),
    JSON.stringify(recommendedNextActions),
    JSON.stringify(groundingSources),
    confidence,
    1,
    0,
    "deterministic-grounded-deal-risk",
    checksum,
    now
  );

  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "ai.deal_risk.generated",
    subjectType: "ai_deal_risk_brief",
    subjectId: briefId,
    customerId: customer.id,
    status: "advisory",
    payload: {
      dealId,
      riskLevel,
      riskScore,
      confidence,
      advisoryOnly: true,
      groundingSourceCount: groundingSources.length,
      checksum
    }
  });
  audit(db, user.org_id, user.id, "ai.deal_risk.generated", {
    briefId,
    dealId,
    customerId: customer.id,
    riskLevel,
    riskScore,
    confidence,
    advisoryOnly: true,
    groundingSourceCount: groundingSources.length,
    checksum
  });

  return { brief: getAiDealRiskBrief(db, user.org_id, briefId) };
}

function buildAiDealRiskContext(db, orgId, deal, customer) {
  const forecast = getCrmDealForecast(db, orgId, deal.id);
  const receivables = getReceivablesAging(db, orgId, customer.id);
  const openInvoices = receivables.invoices;
  const overdueInvoices = openInvoices.filter(invoice => invoice.daysPastDue > 0 || invoice.status === "overdue");
  const serviceCases = getServiceCases(db, orgId, customer.id);
  const atRiskCase = serviceCases.find(serviceCase => serviceCase.slaStatus === "at-risk" || serviceCase.priority === "high") || null;
  const quote = getQuotes(db, orgId, customer.id).find(item => item.dealId === deal.id) || null;
  return {
    forecast,
    receivables,
    openInvoices,
    overdueInvoices,
    serviceCases,
    atRiskCase,
    quote
  };
}

function buildAiDealRiskFactors(deal, customer, context) {
  const factors = [];
  if (context.receivables.summary.totalOpen > 0) {
    factors.push(`Open HayHashvapah receivables: ${formatStoredMoney(context.receivables.summary.totalOpen)}.`);
  }
  if (context.overdueInvoices[0]) {
    factors.push(`Overdue invoice ${context.overdueInvoices[0].number} is ${context.overdueInvoices[0].daysPastDue} day(s) past due.`);
  }
  if (context.atRiskCase) {
    factors.push(`Service blocker ${context.atRiskCase.caseNumber} is ${context.atRiskCase.slaStatus} with ${context.atRiskCase.priority} priority.`);
  }
  if ((context.forecast?.forecastCategory || deal.forecastCategory) === "commit" && (context.openInvoices.length > 0 || context.atRiskCase)) {
    factors.push("Commit forecast has unresolved finance or service blockers.");
  }
  if (context.quote && context.quote.status !== "accepted") {
    factors.push(`Quote ${context.quote.number} is ${context.quote.status}, not accepted.`);
  }
  if (customer.health_score < 85) {
    factors.push(`Customer health is ${customer.health_score}%, below the stable account threshold.`);
  }
  if (factors.length === 0) {
    factors.push("No material finance, service, or quote blocker is visible in grounded records.");
  }
  return factors;
}

function calculateAiDealRiskScore(deal, customer, context) {
  let score = 20;
  if (deal.stage !== "Won") score += 8;
  if ((context.forecast?.forecastCategory || deal.forecastCategory) === "commit") score += 8;
  if (context.receivables.summary.totalOpen > 0) score += 20;
  if (context.overdueInvoices.length > 0) score += 18;
  if (context.atRiskCase) score += 18;
  if (context.quote && context.quote.status !== "accepted") score += 8;
  if (deal.healthStatus === "at-risk") score += 15;
  else if (deal.healthStatus === "watch") score += 8;
  if (customer.health_score < 70) score += 10;
  else if (customer.health_score < 85) score += 5;
  return Math.min(95, Math.max(5, score));
}

function buildAiDealRiskActions(deal, context, riskLevel) {
  const actions = [];
  if (context.overdueInvoices[0]) {
    actions.push(`Ask HayHashvapah owner to verify ${context.overdueInvoices[0].number} payment status before pushing the deal to close.`);
  } else if (context.openInvoices[0]) {
    actions.push(`Review HayHashvapah receivable ${context.openInvoices[0].number} before the next buyer follow-up.`);
  }
  if (context.atRiskCase) {
    actions.push(`Clear service blocker ${context.atRiskCase.caseNumber} before commercial escalation.`);
  }
  if ((context.forecast?.forecastCategory || deal.forecastCategory) === "commit" && riskLevel !== "low") {
    actions.push("Keep the forecast review note explicit about finance and service blockers before confirming commit confidence.");
  }
  if (context.quote && context.quote.status !== "accepted") {
    actions.push(`Confirm acceptance path for quote ${context.quote.number} and align the quote-to-invoice handoff.`);
  }
  if (actions.length === 0) {
    actions.push("Proceed with the next CRM step and keep standard HayHashvapah invoice readiness checks in place.");
  }
  return actions;
}

function buildAiDealRiskGrounding(deal, context) {
  const sources = [
    { type: "crm_deal", id: deal.id, label: deal.title, confidence: 94 }
  ];
  if (context.forecast) {
    sources.push({ type: "crm_forecast", id: context.forecast.id, label: context.forecast.forecastCategory, confidence: 90 });
  }
  if (context.quote) {
    sources.push({ type: "crm_quote", id: context.quote.id, label: context.quote.number, confidence: 88 });
  }
  for (const invoice of context.openInvoices.slice(0, 2)) {
    sources.push({ type: "finance_invoice", id: invoice.id, label: invoice.number, confidence: 92 });
  }
  if (context.atRiskCase) {
    sources.push({ type: "service_case", id: context.atRiskCase.id, label: context.atRiskCase.caseNumber, confidence: 88 });
  }
  return sources;
}

