function getLegalQuestions(db, orgId, customerId = "") {
  const params = [orgId];
  let where = "WHERE legal_questions.org_id = ?";
  if (customerId) {
    where += " AND legal_questions.customer_id = ?";
    params.push(customerId);
  }
  return db.prepare(`
    SELECT legal_questions.*, customers.name AS customer_name, users.name AS asked_by_name
    FROM legal_questions
    JOIN customers ON customers.id = legal_questions.customer_id
    LEFT JOIN users ON users.id = legal_questions.asked_by_user_id
    ${where}
    ORDER BY legal_questions.created_at DESC
    LIMIT 50
  `).all(...params).map(row => attachLegalAnswer(db, orgId, formatLegalQuestion(row)));
}

function getLegalQuestion(db, orgId, questionId) {
  const row = db.prepare(`
    SELECT legal_questions.*, customers.name AS customer_name, users.name AS asked_by_name
    FROM legal_questions
    JOIN customers ON customers.id = legal_questions.customer_id
    LEFT JOIN users ON users.id = legal_questions.asked_by_user_id
    WHERE legal_questions.org_id = ? AND legal_questions.id = ?
  `).get(orgId, questionId);
  return row ? formatLegalQuestion(row) : null;
}

function attachLegalAnswer(db, orgId, question) {
  const answer = question ? getLegalAnswerByQuestion(db, orgId, question.id) : null;
  return answer ? { ...question, answer, sources: answer.sources } : question;
}

function formatLegalQuestion(row) {
  return {
    id: row.id,
    customerId: row.customer_id,
    customerName: row.customer_name,
    askedByUserId: row.asked_by_user_id,
    askedByName: row.asked_by_name,
    question: row.question,
    topic: row.topic,
    riskLevel: row.risk_level,
    status: row.status,
    createdAt: row.created_at
  };
}

function normalizeLegalPrivacyListQuery(query) {
  if (!isPlainObject(query)) {
    throwInvalidLegalPrivacyListQuery();
  }
  return {
    customerId: normalizeLegalPrivacyListQueryText(query, "customerId", { maxLength: 160 })
  };
}

function normalizeLegalPrivacyListQueryText(query, field, options = {}) {
  const { maxLength = 160 } = options;
  const value = Object.prototype.hasOwnProperty.call(query, field) ? query[field] : undefined;
  if (value === undefined || value === "") {
    return "";
  }
  if (value === null || typeof value !== "string") {
    throwInvalidLegalPrivacyListQuery();
  }
  if (/[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidLegalPrivacyListQuery();
  }
  const text = value.trim();
  if (!text || text.length > maxLength) {
    throwInvalidLegalPrivacyListQuery();
  }
  return text;
}

function throwInvalidLegalPrivacyListQuery() {
  const err = new Error("Invalid legal/privacy list query");
  err.statusCode = 400;
  throw err;
}

