function createSignaturePacket(db, user, body) {
  if (!isPlainObject(body)) {
    throwInvalidSignaturePacket();
  }
  const quoteId = normalizeSignaturePacketText(body, "quoteId", { required: true, maxLength: 120 });
  const quote = quoteId ? getQuote(db, user.org_id, quoteId) : null;
  if (!quote) {
    const err = new Error("Quote not found");
    err.statusCode = 404;
    throw err;
  }
  if (quote.status !== "accepted") {
    const err = new Error("QUOTE_NOT_ACCEPTED");
    err.statusCode = 409;
    throw err;
  }

  const legalSource = requireProfessionalLegalSource(db, user.org_id, "law-esign", "ESIGN_SOURCE_REVIEW_REQUIRED");

  const acceptance = getQuoteAcceptanceByQuote(db, user.org_id, quote.id);
  if (!acceptance) {
    const err = new Error("Quote acceptance not found");
    err.statusCode = 422;
    throw err;
  }

  const sourceKey = `signature-packet:${quote.id}`;
  const note = normalizeSignaturePacketText(body, "note", { fallback: "", maxLength: 500 });
  const existing = getSignaturePacketBySourceKey(db, user.org_id, sourceKey);
  if (existing) return { idempotent: true, packet: existing };

  const organization = getOrganization(db, user.org_id);
  const packetId = randomId("signature-packet");
  const now = new Date().toISOString();
  const payload = {
    kind: "accepted-quote-signature-evidence",
    product: "Armosphera One",
    organization: {
      id: organization.id,
      name: organization.name,
      legalName: organization.legal_name,
      taxId: organization.tax_id,
      locale: organization.locale
    },
    customer: {
      id: quote.customerId,
      name: quote.customerName,
      taxId: quote.taxId
    },
    quote: {
      id: quote.id,
      number: quote.number,
      title: quote.title,
      status: quote.status,
      total: quote.total,
      vat: quote.vat,
      currency: quote.currency,
      acceptedAt: quote.acceptedAt,
      lines: quote.lines
    },
    acceptance: {
      id: acceptance.id,
      signerName: acceptance.signerName,
      signerEmail: acceptance.signerEmail,
      acceptedAt: acceptance.acceptedAt,
      ipAddress: acceptance.ipAddress,
      userAgent: acceptance.userAgent
    },
    legalSource: legalSourcePayload(legalSource),
    note,
    disclaimer: "Prepared as an Armenian e-signature evidence handoff; not a qualified signature service."
  };
  const checksum = crypto.createHash("sha256").update(JSON.stringify(payload)).digest("hex");
  db.prepare(`
    INSERT INTO docs_signature_packets (
      id, org_id, customer_id, quote_id, acceptance_id, legal_source_id,
      status, checksum, payload, note, source_key, created_by_user_id, created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    packetId,
    user.org_id,
    quote.customerId,
    quote.id,
    acceptance.id,
    legalSource.id,
    "archived",
    checksum,
    JSON.stringify(payload),
    payload.note,
    sourceKey,
    user.id,
    now
  );

  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "docs.signature_packet.created",
    subjectType: "docs_signature_packet",
    subjectId: packetId,
    customerId: quote.customerId,
    status: "archived",
    payload: { quoteId: quote.id, acceptanceId: acceptance.id, checksum }
  });
  audit(db, user.org_id, user.id, "docs.signature_packet.created", { packetId, quoteId: quote.id, acceptanceId: acceptance.id });

  return { idempotent: false, packet: getSignaturePacket(db, user.org_id, packetId) };
}

function normalizeSignaturePacketText(body, field, options = {}) {
  const { required = false, fallback = "", maxLength = 160 } = options;
  const hasField = Object.prototype.hasOwnProperty.call(body, field);
  const value = hasField ? body[field] : undefined;
  if (value === undefined) {
    if (required) throwInvalidSignaturePacket();
    return fallback;
  }
  if (value === null) {
    throwInvalidSignaturePacket();
  }
  if (value === "") {
    if (required) throwInvalidSignaturePacket();
    return fallback;
  }
  if (typeof value !== "string") {
    throwInvalidSignaturePacket();
  }
  if (/[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidSignaturePacket();
  }
  const text = value.trim();
  if (!text) {
    if (required) throwInvalidSignaturePacket();
    return fallback;
  }
  if (text.length > maxLength) {
    throwInvalidSignaturePacket();
  }
  return text;
}

function normalizeSignaturePacketListQuery(query) {
  if (!isPlainObject(query)) {
    throwInvalidSignaturePacket();
  }
  return {
    customerId: normalizeSignaturePacketText(query, "customerId", { fallback: "", maxLength: 160 })
  };
}

function throwInvalidSignaturePacket() {
  const err = new Error("Invalid signature packet");
  err.statusCode = 400;
  throw err;
}

