function averageSatisfaction(resolutions) {
  const scores = resolutions.map(item => item.satisfactionScore).filter(score => Number.isFinite(score));
  if (scores.length === 0) return 0;
  return Math.round(scores.reduce((sum, score) => sum + score, 0) / scores.length);
}

