function executeApprovedAction(db, user, approval) {
  if (approval.actionKey === "crm.task.create") return executeCrmTaskApproval(db, user, approval);
  if (approval.actionKey === "service.reply.send") return executeServiceReplyApproval(db, user, approval);
  if (approval.actionKey === "crm.quote.release") return executeQuoteReleaseApproval(db, user, approval);
  if (approval.actionKey === "finance.invoice.propose") return executeDraftInvoiceApproval(db, user, approval);
  if (approval.actionKey === "legal.answer.approve") return executeLegalAnswerApproval(db, user, approval);
  if (approval.actionKey === "privacy.request.approve") return executePrivacyRequestApproval(db, user, approval);

  const err = new Error("Unsupported approval action");
  err.statusCode = 422;
  throw err;
}

function recordWorkflowRunFailure(db, user, approval, error) {
  const now = new Date().toISOString();
  const runId = randomId("run");
  const errorCode = String(error.message || "WORKFLOW_FAILED");
  const payload = {
    source: "workflow_approval",
    approvalId: approval.id,
    errorCode,
    errorMessage: errorCode,
    retryable: isRetryableWorkflowError(errorCode),
    nextRetryAction: workflowRetryAction(errorCode, approval),
    attempts: [{
      status: "failed",
      errorCode,
      attemptedByUserId: user.id,
      attemptedAt: now
    }]
  };
  db.prepare(`
    INSERT INTO workflow_runs (
      id, org_id, approval_id, rule_id, customer_id, action_key, status,
      result_type, result_id, payload, started_at, completed_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    runId,
    user.org_id,
    approval.id,
    approval.ruleId,
    approval.customerId,
    approval.actionKey,
    "failed",
    "workflow_guardrail",
    null,
    JSON.stringify(payload),
    now,
    now
  );

  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "workflow.action.failed",
    subjectType: "workflow_run",
    subjectId: runId,
    customerId: approval.customerId,
    status: "failed",
    payload: {
      approvalId: approval.id,
      actionKey: approval.actionKey,
      errorCode,
      retryable: payload.retryable,
      nextRetryAction: payload.nextRetryAction
    }
  });
  audit(db, user.org_id, user.id, "workflow.action.failed", {
    approvalId: approval.id,
    runId,
    errorCode,
    retryable: payload.retryable
  });

  return { run: getWorkflowRun(db, user.org_id, runId) };
}

function replyWorkflowFailure(reply, db, user, approval, run, statusCode = 409) {
  reply.code(statusCode);
  const payload = run.payload || {};
  return {
    ok: false,
    error: payload.errorCode || "WORKFLOW_RUN_FAILED",
    run,
    retry: {
      available: Boolean(payload.retryable),
      endpoint: `/api/workflow/runs/${run.id}/retry`,
      nextAction: payload.nextRetryAction || "Review workflow guardrail before retrying."
    },
    events: getRecentSuiteEvents(db, user.org_id, 8, approval.customerId)
  };
}

function retryWorkflowRun(db, user, run) {
  if (run.status !== "failed") {
    const err = new Error("Only failed workflow runs can be retried");
    err.statusCode = 409;
    throw err;
  }
  if (!run.payload?.retryable) {
    const err = new Error("Workflow run is not retryable");
    err.statusCode = 409;
    throw err;
  }
  const approval = getWorkflowApproval(db, user.org_id, run.approvalId);
  if (!approval) {
    const err = new Error("Workflow approval not found for retry");
    err.statusCode = 404;
    throw err;
  }
  if (approval.actionKey === "finance.invoice.propose") {
    return retryDraftInvoiceWorkflowRun(db, user, run, approval);
  }
  const err = new Error("Workflow retry is not supported for this action");
  err.statusCode = 422;
  throw err;
}

function retryDraftInvoiceWorkflowRun(db, user, run, approval) {
  const now = new Date().toISOString();
  const previousPayload = run.payload || {};
  const previousFailure = {
    errorCode: previousPayload.errorCode || "WORKFLOW_RUN_FAILED",
    failedAt: previousPayload.attempts?.[0]?.attemptedAt || run.completedAt,
    nextRetryAction: previousPayload.nextRetryAction || ""
  };
  const draftInvoice = createDraftInvoiceFromApproval(db, user, approval, now);
  const attempts = [
    ...(Array.isArray(previousPayload.attempts) ? previousPayload.attempts : []),
    {
      status: "completed",
      resultType: "finance_draft_invoice",
      resultId: draftInvoice.id,
      attemptedByUserId: user.id,
      attemptedAt: now
    }
  ];
  const payload = {
    draftInvoiceId: draftInvoice.id,
    dealId: draftInvoice.dealId,
    periodKey: draftInvoice.periodKey,
    source: "workflow_retry",
    approvalId: approval.id,
    retryOf: run.id,
    previousFailure,
    attempts
  };
  db.prepare(`
    UPDATE workflow_runs
    SET status = ?, result_type = ?, result_id = ?, payload = ?, completed_at = ?
    WHERE org_id = ? AND id = ?
  `).run("completed", "finance_draft_invoice", draftInvoice.id, JSON.stringify(payload), now, user.org_id, run.id);
  db.prepare("UPDATE workflow_approvals SET status = ?, decided_by_user_id = COALESCE(decided_by_user_id, ?), decided_at = COALESCE(decided_at, ?) WHERE org_id = ? AND id = ?")
    .run("executed", user.id, now, user.org_id, approval.id);

  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "finance.draft_invoice.created",
    subjectType: "finance_draft_invoice",
    subjectId: draftInvoice.id,
    customerId: approval.customerId,
    status: "draft",
    payload: {
      approvalId: approval.id,
      dealId: draftInvoice.dealId,
      number: draftInvoice.number,
      total: draftInvoice.total,
      periodKey: draftInvoice.periodKey,
      retryOf: run.id
    }
  });
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "workflow.action.retried",
    subjectType: "workflow_run",
    subjectId: run.id,
    customerId: approval.customerId,
    status: "completed",
    payload: { approvalId: approval.id, resultType: "finance_draft_invoice", resultId: draftInvoice.id, previousError: previousFailure.errorCode }
  });
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "workflow.action.executed",
    subjectType: "workflow_run",
    subjectId: run.id,
    customerId: approval.customerId,
    status: "completed",
    payload: { approvalId: approval.id, resultType: "finance_draft_invoice", resultId: draftInvoice.id, retry: true }
  });
  audit(db, user.org_id, user.id, "workflow.action.retried", { approvalId: approval.id, runId: run.id, previousError: previousFailure.errorCode, draftInvoiceId: draftInvoice.id });
  audit(db, user.org_id, user.id, "workflow.action.executed", { approvalId: approval.id, runId: run.id, draftInvoiceId: draftInvoice.id, retry: true });

  return {
    run: getWorkflowRun(db, user.org_id, run.id),
    draftInvoice: getFinanceDraftInvoice(db, user.org_id, draftInvoice.id),
    approval: getWorkflowApproval(db, user.org_id, approval.id)
  };
}

function isRetryableWorkflowError(errorCode) {
  return ["PERIOD_LOCKED"].includes(errorCode);
}

function workflowRetryAction(errorCode, approval) {
  if (errorCode === "PERIOD_LOCKED") {
    const periodKey = String((approval.payload || {}).periodKey || "current period");
    return `Reopen finance period ${periodKey} before retrying HayHashvapah draft invoice workflow.`;
  }
  return "Review workflow guardrail before retrying.";
}

