function getPostedInvoicesForSrcExport(db, orgId, periodKey) {
  return db.prepare(`
    SELECT
      invoices.id AS invoice_id,
      invoices.number AS invoice_number,
      invoices.status AS invoice_status,
      invoices.due_date,
      customers.id AS customer_id,
      customers.name AS customer_name,
      customers.tax_id AS customer_tax_id,
      finance_invoice_links.id AS link_id,
      finance_draft_invoices.id AS draft_invoice_id,
      finance_draft_invoices.period_key,
      finance_draft_invoices.currency,
      finance_draft_invoices.subtotal,
      finance_draft_invoices.vat,
      finance_draft_invoices.total
    FROM finance_invoice_links
    JOIN invoices ON invoices.id = finance_invoice_links.invoice_id
    JOIN customers ON customers.id = invoices.customer_id
    JOIN finance_draft_invoices ON finance_draft_invoices.id = finance_invoice_links.draft_invoice_id
    WHERE finance_invoice_links.org_id = ?
      AND finance_draft_invoices.period_key = ?
    ORDER BY invoices.number
  `).all(orgId, periodKey);
}

function getFinanceSrcExports(db, orgId, periodKey = "", options = {}) {
  const params = [orgId];
  let where = "WHERE finance_src_exports.org_id = ?";
  if (periodKey) {
    where += " AND finance_src_exports.period_key = ?";
    params.push(periodKey);
  }
  return db.prepare(`
    SELECT finance_src_exports.*, users.name AS created_by_name
    FROM finance_src_exports
    LEFT JOIN users ON users.id = finance_src_exports.created_by_user_id
    ${where}
    ORDER BY finance_src_exports.created_at DESC
  `).all(...params).map(row => formatFinanceSrcExport(row, options));
}

function getFinanceSrcExport(db, orgId, exportId, options = {}) {
  const row = db.prepare(`
    SELECT finance_src_exports.*, users.name AS created_by_name
    FROM finance_src_exports
    LEFT JOIN users ON users.id = finance_src_exports.created_by_user_id
    WHERE finance_src_exports.org_id = ? AND finance_src_exports.id = ?
  `).get(orgId, exportId);
  return row ? formatFinanceSrcExport(row, options) : null;
}

function getFinanceSrcExportBySourceKey(db, orgId, sourceKey, options = {}) {
  const row = db.prepare(`
    SELECT finance_src_exports.*, users.name AS created_by_name
    FROM finance_src_exports
    LEFT JOIN users ON users.id = finance_src_exports.created_by_user_id
    WHERE finance_src_exports.org_id = ? AND finance_src_exports.source_key = ?
  `).get(orgId, sourceKey);
  return row ? formatFinanceSrcExport(row, options) : null;
}

function formatFinanceSrcExport(row, options = {}) {
  const includePayload = options.includePayload !== false;
  return {
    id: row.id,
    periodKey: row.period_key,
    status: row.status,
    legalSourceId: row.legal_source_id,
    invoiceCount: row.invoice_count,
    subtotal: row.subtotal,
    vat: row.vat,
    total: row.total,
    checksum: includePayload ? row.checksum : null,
    payload: includePayload ? safeJson(row.payload) : null,
    note: row.note,
    sourceKey: includePayload ? row.source_key : null,
    createdByUserId: row.created_by_user_id,
    createdByName: row.created_by_name,
    createdAt: row.created_at
  };
}

function createFinanceVatReturn(db, user, body) {
  if (locale.activeLocale() === "ru") {
    const err = new Error("RU VAT-return persistence is not yet available; use POST /api/finance/vat-return/compute for the RF НДС settlement.");
    err.statusCode = 501;
    err.code = "RU_VAT_RETURN_PERSIST_UNSUPPORTED";
    throw err;
  }
  const { periodKey, note } = normalizeFinanceVatReturnBody(body);

  const period = getFinancePeriod(db, user.org_id, periodKey);
  if (!period || period.status !== "open") {
    const err = new Error("PERIOD_LOCKED");
    err.statusCode = 409;
    throw err;
  }

  const legalSource = requireProfessionalLegalSource(db, user.org_id, "law-tax-code", "VAT_SOURCE_REVIEW_REQUIRED");
  const sourceKey = `vat-return:${periodKey}`;
  const existing = getFinanceVatReturnBySourceKey(db, user.org_id, sourceKey);
  if (existing) return { idempotent: true, vatReturn: existing };

  const inputs = getVatReturnLedgerInputs(db, user.org_id, periodKey);
  const totals = vatReturn.computeVatReturn(inputs);
  const organization = getOrganization(db, user.org_id);
  const payload = {
    kind: "armenian-vat-return-packet",
    preparedFor: "Armenian VAT return accountant review",
    product: "Armosphera One",
    organization: {
      id: organization.id,
      name: organization.name,
      legalName: organization.legal_name,
      taxId: organization.tax_id,
      locale: organization.locale,
      currency: organization.currency
    },
    period: {
      periodKey,
      startsOn: period.startsOn,
      endsOn: period.endsOn,
      status: period.status
    },
    legalSource: legalSourcePayload(legalSource),
    vatRate: vatReturn.STANDARD_VAT_RATE,
    inputs,
    totals,
    note,
    disclaimer: "Prepared as an offline VAT return calculation for accountant review; not submitted to SRC and not mapped to official form line numbers."
  };
  const checksum = crypto.createHash("sha256").update(JSON.stringify(payload)).digest("hex");
  const returnId = randomId("vat-return");
  const now = new Date().toISOString();
  db.prepare(`
    INSERT INTO finance_vat_returns (
      id, org_id, period_key, status, legal_source_id, output_vat,
      input_vat, taxable_sales, taxable_purchases, net, payable, credit_carried,
      checksum, payload, note, source_key, created_by_user_id, created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    returnId,
    user.org_id,
    periodKey,
    "prepared",
    legalSource.id,
    totals.outputVat,
    totals.inputVat,
    totals.taxableSales,
    totals.taxablePurchases,
    totals.net,
    totals.payable,
    totals.creditCarried,
    checksum,
    JSON.stringify(payload),
    payload.note,
    sourceKey,
    user.id,
    now
  );

  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "finance.vat_return.created",
    subjectType: "finance_vat_return",
    subjectId: returnId,
    status: "prepared",
    payload: { periodKey, payable: totals.payable, creditCarried: totals.creditCarried, checksum }
  });
  audit(db, user.org_id, user.id, "finance.vat_return.created", {
    returnId,
    periodKey,
    payable: totals.payable,
    creditCarried: totals.creditCarried
  });

  return { idempotent: false, vatReturn: getFinanceVatReturn(db, user.org_id, returnId) };
}

