function createWorkflowDryRun(db, user, ruleId, body) {
  if (!isPlainObject(body)) {
    throwInvalidWorkflowDryRun();
  }
  const rule = getAutomationRule(db, user.org_id, ruleId);
  if (!rule) {
    const err = new Error("Workflow rule not found");
    err.statusCode = 404;
    throw err;
  }
  if (!rule.enabled) {
    const err = new Error("Workflow rule is disabled");
    err.statusCode = 409;
    throw err;
  }

  const now = new Date().toISOString();
  const preview = buildWorkflowDryRunPreview(db, user, rule, body || {});
  const guardrails = workflowDryRunGuardrails(rule.action, preview);
  const checksumPayload = {
    ruleId: rule.id,
    trigger: rule.trigger,
    action: rule.action,
    customerId: preview.customerId,
    matchedSubjectType: preview.matchedSubjectType,
    matchedSubjectId: preview.matchedSubjectId,
    resultPreview: preview.resultPreview,
    guardrails
  };
  const checksum = crypto.createHash("sha256").update(JSON.stringify(checksumPayload)).digest("hex");
  const dryRunId = randomId("workflow-dry-run");
  const sourceKey = `dry-run:${rule.id}:${preview.matchedSubjectType}:${preview.matchedSubjectId}:${Date.parse(now)}`;
  const note = normalizeWorkflowDryRunText(body, "note", { fallback: "", maxLength: 500 });

  db.prepare(`
    INSERT INTO workflow_dry_runs (
      id, org_id, rule_id, customer_id, triggered_by_user_id, trigger_key,
      action_key, status, risk_level, approval_required, matched_subject_type,
      matched_subject_id, result_preview, guardrails, checksum, note, source_key,
      created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    dryRunId,
    user.org_id,
    rule.id,
    preview.customerId,
    user.id,
    rule.trigger,
    rule.action,
    preview.status,
    workflowRiskLevel(rule.action),
    workflowApprovalRequired(rule.action) ? 1 : 0,
    preview.matchedSubjectType,
    preview.matchedSubjectId,
    JSON.stringify(preview.resultPreview),
    JSON.stringify(guardrails),
    checksum,
    note,
    sourceKey,
    now
  );

  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "workflow.dry_run.created",
    subjectType: "workflow_dry_run",
    subjectId: dryRunId,
    customerId: preview.customerId,
    status: preview.status,
    payload: {
      ruleId: rule.id,
      trigger: rule.trigger,
      action: rule.action,
      matchedSubjectType: preview.matchedSubjectType,
      matchedSubjectId: preview.matchedSubjectId,
      checksum
    }
  });
  audit(db, user.org_id, user.id, "workflow.dry_run.created", {
    dryRunId,
    ruleId: rule.id,
    customerId: preview.customerId,
    matchedSubjectId: preview.matchedSubjectId,
    checksum
  });

  return { dryRun: getWorkflowDryRun(db, user.org_id, dryRunId) };
}

function normalizeWorkflowDryRunText(body, field, options = {}) {
  const { required = false, fallback = "", maxLength = 160 } = options;
  const hasField = Object.prototype.hasOwnProperty.call(body, field);
  const value = hasField ? body[field] : undefined;
  if (value === undefined) {
    if (required) throwInvalidWorkflowDryRun();
    return fallback;
  }
  if (value === null) {
    throwInvalidWorkflowDryRun();
  }
  if (value === "") {
    if (required) throwInvalidWorkflowDryRun();
    return fallback;
  }
  if (typeof value !== "string") {
    throwInvalidWorkflowDryRun();
  }
  if (/[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidWorkflowDryRun();
  }
  const text = value.trim();
  if (!text) {
    if (required) throwInvalidWorkflowDryRun();
    return fallback;
  }
  if (text.length > maxLength) {
    throwInvalidWorkflowDryRun();
  }
  return text;
}

function throwInvalidWorkflowDryRun() {
  const err = new Error("Invalid workflow dry-run");
  err.statusCode = 400;
  throw err;
}

function createWorkflowTestEvent(db, user, ruleId, body) {
  if (!isPlainObject(body)) {
    throwInvalidWorkflowTestEvent();
  }
  const rule = getAutomationRule(db, user.org_id, ruleId);
  if (!rule) {
    const err = new Error("Workflow rule not found");
    err.statusCode = 404;
    throw err;
  }
  if (!rule.enabled) {
    const err = new Error("Workflow rule is disabled");
    err.statusCode = 409;
    throw err;
  }

  const eventType = normalizeWorkflowTestEventText(body, "eventType", { required: true, maxLength: 80 });
  const expectedEventType = workflowTestEventTypeForTrigger(rule.trigger);
  if (eventType !== expectedEventType) {
    const err = new Error(`eventType must be ${expectedEventType} for this workflow rule`);
    err.statusCode = 422;
    throw err;
  }

  const evaluation = buildWorkflowTestEventEvaluation(db, user, rule, body);
  const guardrails = workflowTestEventGuardrails(rule.action, evaluation);
  const note = normalizeWorkflowTestEventText(body, "note", { fallback: "", maxLength: 500 });
  const inputPayload = normalizeWorkflowTestEventPayload(body);
  const now = new Date().toISOString();
  const testEventId = randomId("workflow-test-event");
  const checksumPayload = {
    ruleId: rule.id,
    trigger: rule.trigger,
    action: rule.action,
    eventType,
    customerId: evaluation.customerId,
    subjectType: evaluation.subjectType,
    subjectId: evaluation.subjectId,
    inputPayload,
    evaluation: evaluation.result,
    guardrails
  };
  const checksum = crypto.createHash("sha256").update(JSON.stringify(checksumPayload)).digest("hex");

  db.prepare(`
    INSERT INTO workflow_test_events (
      id, org_id, rule_id, customer_id, triggered_by_user_id, event_type,
      trigger_key, action_key, subject_type, subject_id, status, evaluation,
      input_payload, guardrails, checksum, note, created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    testEventId,
    user.org_id,
    rule.id,
    evaluation.customerId,
    user.id,
    eventType,
    rule.trigger,
    rule.action,
    evaluation.subjectType,
    evaluation.subjectId,
    evaluation.status,
    JSON.stringify(evaluation.result),
    JSON.stringify(inputPayload),
    JSON.stringify(guardrails),
    checksum,
    note,
    now
  );

  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "workflow.test_event.created",
    subjectType: "workflow_test_event",
    subjectId: testEventId,
    customerId: evaluation.customerId,
    status: evaluation.status,
    payload: {
      ruleId: rule.id,
      eventType,
      subjectType: evaluation.subjectType,
      subjectId: evaluation.subjectId,
      action: rule.action,
      checksum
    }
  });
  audit(db, user.org_id, user.id, "workflow.test_event.created", {
    testEventId,
    ruleId: rule.id,
    eventType,
    customerId: evaluation.customerId,
    subjectType: evaluation.subjectType,
    subjectId: evaluation.subjectId,
    checksum
  });

  return { testEvent: getWorkflowTestEvent(db, user.org_id, testEventId) };
}

function normalizeWorkflowTestEventText(body, field, options = {}) {
  const { required = false, fallback = "", maxLength = 160 } = options;
  const hasField = Object.prototype.hasOwnProperty.call(body, field);
  const value = hasField ? body[field] : undefined;
  if (value === undefined) {
    if (required) throwInvalidWorkflowTestEvent();
    return fallback;
  }
  if (value === null) {
    throwInvalidWorkflowTestEvent();
  }
  if (value === "") {
    if (required) throwInvalidWorkflowTestEvent();
    return fallback;
  }
  if (typeof value !== "string") {
    throwInvalidWorkflowTestEvent();
  }
  if (/[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidWorkflowTestEvent();
  }
  const text = value.trim();
  if (!text) {
    if (required) throwInvalidWorkflowTestEvent();
    return fallback;
  }
  if (text.length > maxLength) {
    throwInvalidWorkflowTestEvent();
  }
  return text;
}

function normalizeWorkflowTestEventPayload(body) {
  if (!Object.prototype.hasOwnProperty.call(body, "payload")) return {};
  if (!isPlainObject(body.payload)) {
    throwInvalidWorkflowTestEvent();
  }
  return body.payload;
}

function throwInvalidWorkflowTestEvent() {
  const err = new Error("Invalid workflow test event");
  err.statusCode = 400;
  throw err;
}

function buildWorkflowDryRunPreview(db, user, rule, body) {
  if (rule.trigger === "invoice.overdue" && rule.action === "crm.task.create") {
    return buildOverdueInvoiceTaskDryRun(db, user, rule, body);
  }
  const customerId = normalizeWorkflowDryRunText(body, "customerId", { fallback: null, maxLength: 120 });
  if (customerId) assertCustomer(db, user.org_id, customerId);
  return {
    status: "ready",
    customerId,
    matchedSubjectType: "automation_rule",
    matchedSubjectId: rule.id,
    resultPreview: {
      ruleName: rule.name,
      trigger: rule.trigger,
      action: rule.action,
      version: 1,
      noRecordsCreated: true
    }
  };
}

function buildWorkflowTestEventEvaluation(db, user, rule, body) {
  if (rule.trigger === "invoice.overdue" && rule.action === "crm.task.create") {
    const subjectType = normalizeWorkflowTestEventText(body, "subjectType", { fallback: "invoice", maxLength: 80 });
    const invoiceId = Object.prototype.hasOwnProperty.call(body, "invoiceId")
      ? normalizeWorkflowTestEventText(body, "invoiceId", { fallback: "", maxLength: 160 })
      : "";
    const subjectId = Object.prototype.hasOwnProperty.call(body, "subjectId")
      ? normalizeWorkflowTestEventText(body, "subjectId", { fallback: "", maxLength: 160 })
      : invoiceId;
    const customerId = normalizeWorkflowTestEventText(body, "customerId", { fallback: "", maxLength: 120 });
    if (subjectType !== "invoice" || !subjectId) {
      const err = new Error("invoice_overdue test events require invoice subjectType and subjectId");
      err.statusCode = 422;
      throw err;
    }
    const preview = buildOverdueInvoiceTaskDryRun(db, user, rule, {
      customerId,
      invoiceId: subjectId
    });
    return {
      status: "matched",
      customerId: preview.customerId,
      subjectType: "invoice",
      subjectId: preview.matchedSubjectId,
      result: {
        eventType: "invoice_overdue",
        triggerMatched: true,
        trigger: rule.trigger,
        action: rule.action,
        proposedTask: preview.resultPreview.proposedTask,
        approval: preview.resultPreview.approval,
        noRecordsCreated: true
      }
    };
  }

  const customerId = normalizeWorkflowTestEventText(body, "customerId", { fallback: null, maxLength: 120 });
  if (customerId) assertCustomer(db, user.org_id, customerId);
  return {
    status: "matched",
    customerId,
    subjectType: normalizeWorkflowTestEventText(body, "subjectType", { fallback: "test_event", maxLength: 80 }),
    subjectId: normalizeWorkflowTestEventText(body, "subjectId", { fallback: rule.id, maxLength: 160 }),
    result: {
      eventType: workflowTestEventTypeForTrigger(rule.trigger),
      triggerMatched: true,
      trigger: rule.trigger,
      action: rule.action,
      noRecordsCreated: true
    }
  };
}

function buildOverdueInvoiceTaskDryRun(db, user, rule, body) {
  const requestedCustomerId = normalizeWorkflowDryRunText(body, "customerId", { fallback: "", maxLength: 120 });
  const invoiceId = normalizeWorkflowDryRunText(body, "invoiceId", { fallback: "", maxLength: 160 });
  const invoice = invoiceId
    ? getInvoice(db, user.org_id, invoiceId)
    : getFirstOverdueInvoice(db, user.org_id, requestedCustomerId);
  if (!invoice) {
    const err = new Error("No overdue invoice matched dry-run input");
    err.statusCode = 422;
    throw err;
  }
  if (requestedCustomerId && invoice.customerId !== requestedCustomerId) {
    const err = new Error("Invoice does not belong to requested customer");
    err.statusCode = 422;
    throw err;
  }
  if (invoice.status === "paid" || invoice.dueDate >= DEFAULT_REPORT_DATE) {
    const err = new Error("Invoice is not overdue for dry-run");
    err.statusCode = 422;
    throw err;
  }

  const customer = db.prepare("SELECT * FROM customers WHERE org_id = ? AND id = ?").get(user.org_id, invoice.customerId);
  const daysOverdue = daysBetween(invoice.dueDate, DEFAULT_REPORT_DATE);
  return {
    status: "ready",
    customerId: invoice.customerId,
    matchedSubjectType: "invoice",
    matchedSubjectId: invoice.id,
    resultPreview: {
      ruleName: rule.name,
      trigger: rule.trigger,
      action: rule.action,
      version: 1,
      approval: {
        required: true,
        riskLevel: "financial",
        reason: "Creates a CRM collection task from HayHashvapah receivable context."
      },
      proposedTask: {
        title: `Collect overdue invoice ${invoice.number}`,
        customerName: customer?.name || invoice.customerName,
        invoiceId: invoice.id,
        invoiceNumber: invoice.number,
        amount: invoice.total,
        currency: currencyOrActive(invoice.currency),
        daysOverdue,
        priority: daysOverdue > 5 ? "high" : "medium",
        dueDate: addDays(DEFAULT_REPORT_DATE, 1),
        ownerRole: "Operator"
      },
      noRecordsCreated: true
    }
  };
}

function workflowDryRunGuardrails(actionKey, preview) {
  const guardrails = [
    "dry-run-only-no-records-created",
    "human-approval-required-before-execution",
    "append-only-audit-evidence",
    "idempotent-execution-check-required"
  ];
  if (/finance|invoice|payment/.test(actionKey) || preview.matchedSubjectType === "invoice") {
    guardrails.push("hayhashvapah-period-lock-and-vat-context-visible");
  }
  if (/reply|message|whatsapp|telegram/.test(actionKey)) {
    guardrails.push("external-message-human-review-required");
  }
  return guardrails;
}

function workflowTestEventGuardrails(actionKey, evaluation) {
  const guardrails = [
    "test-event-only-no-records-created",
    "human-approval-required-before-execution",
    "append-only-audit-evidence",
    "trigger-payload-checksum-recorded"
  ];
  if (/finance|invoice|payment/.test(actionKey) || evaluation.subjectType === "invoice") {
    guardrails.push("hayhashvapah-period-lock-and-vat-context-visible");
  }
  if (/reply|message|whatsapp|telegram/.test(actionKey)) {
    guardrails.push("external-message-human-review-required");
  }
  return guardrails;
}

function workflowTestEventTypeForTrigger(triggerKey) {
  if (triggerKey === "invoice.overdue") return "invoice_overdue";
  if (triggerKey.startsWith("deal.stage_changed")) return "deal_stage_changed";
  if (triggerKey.startsWith("ticket.")) return "ticket_created";
  return triggerKey.replace(/[.:]+/g, "_");
}

function workflowRiskLevel(actionKey) {
  if (/legal|privacy/.test(actionKey)) return "legal";
  if (/finance|invoice|payment|task/.test(actionKey)) return "financial";
  if (/reply|message/.test(actionKey)) return "service";
  return "operational";
}

function workflowApprovalRequired(actionKey) {
  return [
    "crm.task.create",
    "service.reply.send",
    "crm.quote.release",
    "finance.invoice.propose",
    "legal.answer.approve",
    "privacy.request.approve"
  ].includes(actionKey);
}

function getFirstOverdueInvoice(db, orgId, customerId = "") {
  const params = [orgId, DEFAULT_REPORT_DATE];
  let where = "WHERE invoices.org_id = ? AND invoices.status != 'paid' AND invoices.due_date < ?";
  if (customerId) {
    where += " AND invoices.customer_id = ?";
    params.push(customerId);
  }
  const row = db.prepare(`
    SELECT invoices.*, customers.name AS customer_name
    FROM invoices
    JOIN customers ON customers.id = invoices.customer_id
    ${where}
    ORDER BY invoices.due_date ASC
    LIMIT 1
  `).get(...params);
  return row ? formatInvoice(row) : null;
}

function daysBetween(startDate, endDate) {
  const start = new Date(`${startDate}T00:00:00.000Z`);
  const end = new Date(`${endDate}T00:00:00.000Z`);
  return Math.max(0, Math.round((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)));
}

function getWorkflowDryRuns(db, orgId, customerId = "") {
  const params = [orgId];
  let where = "WHERE workflow_dry_runs.org_id = ?";
  if (customerId) {
    where += " AND workflow_dry_runs.customer_id = ?";
    params.push(customerId);
  }
  return db.prepare(`
    SELECT workflow_dry_runs.*, automation_rules.name AS rule_name,
      users.name AS triggered_by_name, customers.name AS customer_name
    FROM workflow_dry_runs
    JOIN automation_rules ON automation_rules.id = workflow_dry_runs.rule_id
    LEFT JOIN users ON users.id = workflow_dry_runs.triggered_by_user_id
    LEFT JOIN customers ON customers.id = workflow_dry_runs.customer_id
    ${where}
    ORDER BY workflow_dry_runs.created_at DESC
  `).all(...params).map(formatWorkflowDryRun);
}

