const COLLECTION_REMINDER_CHANNELS = ["WhatsApp", "Telegram", "Email", "Phone", "Manual"];

function normalizeCollectionPromiseBody(body, invoice) {
  if (!isPlainObject(body)) {
    throwInvalidCollectionMetadata();
  }
  return {
    promisedAmount: normalizeCollectionAmount(body, "promisedAmount", invoice),
    promisedOn: normalizeCollectionDate(body, "promisedOn", { required: true }),
    reminderChannel: normalizeCollectionChannel(body, "reminderChannel", { required: true }),
    note: normalizeCollectionText(body, "note", { fallback: "", maxLength: 500 })
  };
}

function normalizeCollectionReminderBody(body, promise) {
  if (!isPlainObject(body)) {
    throwInvalidCollectionMetadata();
  }
  const channel = normalizeCollectionChannel(body, "channel", { fallback: promise.reminderChannel });
  return {
    channel,
    provider: normalizeCollectionText(body, "provider", { fallback: `${channel} manual evidence`, maxLength: 80 })
  };
}

function normalizeCollectionListQuery(query) {
  if (!isPlainObject(query)) {
    throwInvalidCollectionMetadata();
  }
  return {
    customerId: normalizeCollectionQueryText(query, "customerId", { maxLength: 160 })
  };
}

function normalizeCollectionTaskPathId(value, rawUrl = "") {
  const rawSegment = typeof rawUrl === "string"
    ? rawUrl.match(/^\/api\/crm\/tasks\/([^/?#]+)\/payment-promise(?:[?#]|$)/)?.[1]
    : "";
  if (rawSegment && (rawSegment.length > 160 || !/^[a-z0-9-]+$/.test(rawSegment))) {
    throwInvalidCollectionPathId("Invalid collection task id");
  }
  return normalizeCollectionPathId(value, "Invalid collection task id");
}

function normalizeCollectionPromisePathId(value, rawUrl = "") {
  const rawSegment = typeof rawUrl === "string"
    ? rawUrl.match(/^\/api\/crm\/collection-promises\/([^/?#]+)\/send-reminder(?:[?#]|$)/)?.[1]
    : "";
  if (rawSegment && (rawSegment.length > 160 || !/^[a-z0-9-]+$/.test(rawSegment))) {
    throwInvalidCollectionPathId("Invalid collection promise id");
  }
  return normalizeCollectionPathId(value, "Invalid collection promise id");
}

function normalizeCollectionPathId(value, message) {
  if (typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCollectionPathId(message);
  }
  const text = value.trim();
  if (!text || text.length > 160 || !/^[a-z0-9-]+$/.test(text)) {
    throwInvalidCollectionPathId(message);
  }
  return text;
}

function throwInvalidCollectionPathId(message) {
  const err = new Error(message);
  err.statusCode = 400;
  throw err;
}

function normalizeCollectionQueryText(query, field, options = {}) {
  const { maxLength = 160 } = options;
  const value = Object.prototype.hasOwnProperty.call(query, field) ? query[field] : undefined;
  if (value === undefined || value === "") return "";
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCollectionMetadata();
  }
  const text = value.trim();
  if (!text || text.length > maxLength) {
    throwInvalidCollectionMetadata();
  }
  return text;
}

function normalizeCollectionAmount(body, field, invoice) {
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "" || value === null || Array.isArray(value) || typeof value === "object") {
    throwInvalidCollectionMetadata("Promised amount must be positive and not exceed the invoice total");
  }
  const amount = toStoredMoneyInput(value, () => throwInvalidCollectionMetadata("Promised amount must be positive and not exceed the invoice total"), {
    positive: true,
    zeroSubunitFraction: "zeroes"
  });
  if (amount > invoice.total) {
    throwInvalidCollectionMetadata("Promised amount must be positive and not exceed the invoice total");
  }
  return amount;
}

function normalizeCollectionDate(body, field, options = {}) {
  const { required = false, fallback = "" } = options;
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "") {
    if (required) throwInvalidCollectionMetadata();
    return fallback;
  }
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCollectionMetadata();
  }
  const date = value.trim();
  if (!isExactIsoDate(date)) {
    throwInvalidCollectionMetadata();
  }
  return date;
}

function normalizeCollectionChannel(body, field, options = {}) {
  const { required = false, fallback = "" } = options;
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "") {
    if (required && !fallback) throwInvalidCollectionMetadata();
    return fallback;
  }
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCollectionMetadata();
  }
  const channel = value.trim();
  if (!channel) {
    if (required && !fallback) throwInvalidCollectionMetadata();
    return fallback;
  }
  if (!COLLECTION_REMINDER_CHANNELS.includes(channel)) {
    throwInvalidCollectionMetadata();
  }
  return channel;
}

function normalizeCollectionText(body, field, options = {}) {
  const { fallback = "", maxLength = 500 } = options;
  const value = Object.prototype.hasOwnProperty.call(body, field) ? body[field] : undefined;
  if (value === undefined || value === "") {
    return fallback;
  }
  if (value === null || typeof value !== "string" || /[\x00-\x1f\x7f]/.test(value)) {
    throwInvalidCollectionMetadata();
  }
  const text = value.trim();
  if (!text) {
    return fallback;
  }
  if (text.length > maxLength) {
    throwInvalidCollectionMetadata();
  }
  return text;
}

function throwInvalidCollectionMetadata(message = "Collection request requires safe metadata") {
  const err = new Error(message);
  err.statusCode = 400;
  throw err;
}

function createCollectionPromiseForTask(db, user, taskId, body) {
  const task = getCrmTask(db, user.org_id, taskId);
  if (!task) {
    const err = new Error("CRM task not found");
    err.statusCode = 404;
    throw err;
  }
  if (!task.invoiceId) {
    const err = new Error("Collection task must be linked to a HayHashvapah invoice");
    err.statusCode = 422;
    throw err;
  }
  const invoice = getInvoice(db, user.org_id, task.invoiceId);
  if (!invoice || invoice.status === "paid") {
    const err = new Error("Open invoice required for payment promise");
    err.statusCode = 422;
    throw err;
  }
  const input = normalizeCollectionPromiseBody(body, invoice);
  const { promisedAmount, promisedOn, reminderChannel, note } = input;
  const sourceKey = `task:${task.id}:promise:${promisedOn}:${promisedAmount}`;
  const existing = getCollectionPromiseBySource(db, user.org_id, sourceKey);
  if (existing) {
    return { ok: true, idempotent: true, promise: existing, task: getCrmTask(db, user.org_id, task.id), events: getRecentSuiteEvents(db, user.org_id, 8, task.customerId) };
  }

  const now = new Date().toISOString();
  const promiseId = randomId("promise");
  const reminderAt = `${promisedOn}T09:00:00+04:00`;
  const messageHy = buildCollectionMessageHy(invoice, promisedAmount, promisedOn);
  db.prepare(`
    INSERT INTO crm_collection_promises (
      id, org_id, customer_id, invoice_id, task_id, status, promised_amount,
      currency, promised_on, reminder_channel, reminder_at, message_hy, note,
      source_key, created_by_user_id, created_at, updated_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    promiseId,
    user.org_id,
    task.customerId,
    invoice.id,
    task.id,
    "scheduled",
    promisedAmount,
    currencyOrActive(invoice.currency),
    promisedOn,
    reminderChannel,
    reminderAt,
    messageHy,
    note,
    sourceKey,
    user.id,
    now,
    now
  );
  db.prepare("UPDATE crm_tasks SET status = ?, due_date = ?, updated_at = ? WHERE org_id = ? AND id = ?")
    .run("waiting-payment", reminderAt, now, user.org_id, task.id);
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "crm.collection_promise.recorded",
    subjectType: "crm_collection_promise",
    subjectId: promiseId,
    customerId: task.customerId,
    status: "scheduled",
    payload: { invoiceId: invoice.id, invoiceNumber: invoice.number, promisedAmount, currency: currencyOrActive(invoice.currency), promisedOn, reminderChannel }
  });
  audit(db, user.org_id, user.id, "crm.collection_promise.recorded", { promiseId, taskId: task.id, invoiceId: invoice.id, promisedAmount, promisedOn, reminderChannel });
  return {
    ok: true,
    idempotent: false,
    promise: getCollectionPromise(db, user.org_id, promiseId),
    task: getCrmTask(db, user.org_id, task.id),
    events: getRecentSuiteEvents(db, user.org_id, 8, task.customerId)
  };
}

function sendCollectionReminder(db, user, promiseId, body) {
  const promise = getCollectionPromise(db, user.org_id, promiseId);
  if (!promise) {
    const err = new Error("Collection promise not found");
    err.statusCode = 404;
    throw err;
  }
  const customer = db.prepare("SELECT * FROM customers WHERE org_id = ? AND id = ?").get(user.org_id, promise.customerId);
  const task = getCrmTask(db, user.org_id, promise.taskId);
  const invoice = getInvoice(db, user.org_id, promise.invoiceId);
  if (!customer || !task || !invoice) {
    const err = new Error("Collection reminder context is incomplete");
    err.statusCode = 422;
    throw err;
  }
  const { channel, provider } = normalizeCollectionReminderBody(body, promise);
  const sourceKey = `promise:${promise.id}:reminder:${channel}`;
  const existing = getCollectionReminderDeliveryBySource(db, user.org_id, sourceKey);
  if (existing) {
    return {
      ok: true,
      idempotent: true,
      delivery: existing,
      promise: getCollectionPromise(db, user.org_id, promise.id),
      task,
      events: getRecentSuiteEvents(db, user.org_id, 8, promise.customerId)
    };
  }

  const now = new Date().toISOString();
  const deliveryId = randomId("delivery");
  const recipient = chooseReminderRecipient(customer, channel);
  db.prepare(`
    INSERT INTO crm_collection_reminder_deliveries (
      id, org_id, customer_id, promise_id, invoice_id, task_id, status,
      channel, provider, recipient, message_hy, source_key, sent_by_user_id,
      sent_at, created_at
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    deliveryId,
    user.org_id,
    promise.customerId,
    promise.id,
    promise.invoiceId,
    promise.taskId,
    "sent",
    channel,
    provider,
    recipient,
    promise.messageHy,
    sourceKey,
    user.id,
    now,
    now
  );
  db.prepare("UPDATE crm_collection_promises SET status = ?, updated_at = ? WHERE org_id = ? AND id = ?")
    .run("reminder-sent", now, user.org_id, promise.id);
  db.prepare("UPDATE crm_tasks SET status = ?, updated_at = ? WHERE org_id = ? AND id = ?")
    .run("reminder-sent", now, user.org_id, promise.taskId);
  emitSuiteEvent(db, {
    orgId: user.org_id,
    actorUserId: user.id,
    eventType: "crm.collection_reminder.sent",
    subjectType: "crm_collection_reminder_delivery",
    subjectId: deliveryId,
    customerId: promise.customerId,
    status: "sent",
    payload: { promiseId: promise.id, invoiceId: invoice.id, invoiceNumber: invoice.number, channel, provider }
  });
  audit(db, user.org_id, user.id, "crm.collection_reminder.sent", { deliveryId, promiseId: promise.id, invoiceId: invoice.id, channel, provider });
  return {
    ok: true,
    idempotent: false,
    delivery: getCollectionReminderDelivery(db, user.org_id, deliveryId),
    promise: getCollectionPromise(db, user.org_id, promise.id),
    task: getCrmTask(db, user.org_id, promise.taskId),
    events: getRecentSuiteEvents(db, user.org_id, 8, promise.customerId)
  };
}

function chooseReminderRecipient(customer, channel) {
  if (["WhatsApp", "Telegram", "Phone"].includes(channel)) return customer.phone || "manual-recipient";
  if (channel === "Email") return customer.email || "manual-recipient";
  return `${customer.name} manual follow-up`;
}

function getCollectionPromises(db, orgId, customerId = "") {
  const params = [orgId];
  let where = "WHERE crm_collection_promises.org_id = ?";
  if (customerId) {
    where += " AND crm_collection_promises.customer_id = ?";
    params.push(customerId);
  }
  return db.prepare(`
    SELECT crm_collection_promises.*, customers.name AS customer_name,
      invoices.number AS invoice_number, crm_tasks.title AS task_title,
      users.name AS created_by_name
    FROM crm_collection_promises
    JOIN customers ON customers.id = crm_collection_promises.customer_id
    JOIN invoices ON invoices.id = crm_collection_promises.invoice_id
    JOIN crm_tasks ON crm_tasks.id = crm_collection_promises.task_id
    LEFT JOIN users ON users.id = crm_collection_promises.created_by_user_id
    ${where}
    ORDER BY crm_collection_promises.promised_on ASC, crm_collection_promises.created_at DESC
  `).all(...params).map(formatCollectionPromise);
}

