function getWorkflowRunResult(db, orgId, run) {
  if (run.resultType === "crm_task") {
    return { task: getCrmTask(db, orgId, run.resultId), draftInvoice: null };
  }
  if (run.resultType === "finance_draft_invoice") {
    return { task: null, draftInvoice: getFinanceDraftInvoice(db, orgId, run.resultId) };
  }
  if (run.resultType === "service_reply") {
    const reply = getCaseMessage(db, orgId, run.resultId);
    return {
      task: null,
      draftInvoice: null,
      case: reply ? getServiceCase(db, orgId, reply.caseId) : null,
      reply
    };
  }
  if (run.resultType === "crm_quote_release") {
    return { task: null, draftInvoice: null, quote: getQuote(db, orgId, run.resultId) };
  }
  if (run.resultType === "legal_publication") {
    return { task: null, draftInvoice: null, publication: getLegalPublication(db, orgId, run.resultId) };
  }
  if (run.resultType === "privacy_export_packet") {
    return { task: null, draftInvoice: null, publication: null, packet: getPrivacyExportPacket(db, orgId, run.resultId) };
  }
  if (run.resultType === "privacy_retention_assessment") {
    return {
      task: null,
      draftInvoice: null,
      publication: null,
      packet: null,
      assessment: getPrivacyRetentionAssessment(db, orgId, run.resultId)
    };
  }
  return { task: null, draftInvoice: null, publication: null, packet: null, assessment: null };
}

